# Remove Protection From All Active Process
<#
Clear-Host
Write-Host
$Query = Query-EprocessStruct
$Eprocess = $Query | % { ConvertFrom-EprocessStruct -EprocessBase $_  -IgnoreDirectoryTable -IgnoreToken -IgnoreExitStatus }
$Eprocess | % {
    if ($_.ProtectionType -and $_.ProtectionType -ne 'None') {
        $EprocessBase = [IntPtr][Convert]::ToInt64($_.EprocessAddress, 16)
        Update-ProcessProtection -Eprocess $EprocessBase -SignerValue None -TypeValue None
    }
}
#>

# Query Protection From All Active Process
<#
Clear-Host
Write-Host ""

$Query = Query-EprocessStruct
# Filter out only invalid/ghost records so we catch all active processes
$Eprocess = $Query | % { ConvertFrom-EprocessStruct -EprocessBase $_ -IgnoreExitStatus } | ? { $null -ne $_.ProcessID }

if ($null -ne $Eprocess) {

    # Updated Layout Spacing to cleanly blend ExitStatus and Zombie markers
    $FormatStr = "{0,-6} {1,-18} {2,-19} {3,-19} {4,-19} {5,-19} {6,-15} {7}"
    
    # 1. Header Layout
    Write-Host ($FormatStr -f `
        "PID", "Protection", "Eprocess Addr", "Token Addr", "Kernel CR3 Base", "User CR3 Base", "Exit Status", "Image Name"
    ) -ForegroundColor Cyan

    Write-Host ($FormatStr -f `
        "---", "----------", "-------------", "----------", "---------------", "-------------", "-----------", "----------"
    ) -ForegroundColor Cyan

    # 2. Data Rows
    foreach ($Process in $Eprocess) {

        # Format Protection string nicely
        $ProtectionDisplay = if ($Process.ProtectionType -ne "None") {
            "{0}({1})" -f $Process.ProtectionType, $Process.ProtectionSigner
        }
        else {
            "None"
        }

        # Handle UI highlighting rules for zombie indicators
        if ($Process.IsZombie) {
            $RowColor = "Red"
            $NameDisplay = "[Z] $($Process.ProcessName)"
        } else {
            $RowColor = "Yellow"
            $NameDisplay = $Process.ProcessName
        }

        # Render rows dynamically matching the expanded format columns
        Write-Host ($FormatStr -f `
            $Process.ProcessID,
            $ProtectionDisplay,
            $Process.EprocessAddress,
            $Process.TokenAddress,
            $Process.KernelPhysicalAddress,
            $Process.UserPhysicalAddress,
            $Process.ExitStatus,
            $NameDisplay
        ) -ForegroundColor $RowColor
    }
    Write-Host ""
}
