#region Map
# Source, PPLShade
# Link, https://github.com/redteamfortress/PPLShade
Function Convert-VirtualToPhysical {
    param (
        [IntPtr]$VirtualAddress = (Get-KernelBaseAddress)
    )

    try {
        $Module = [AppDomain]::CurrentDomain.GetAssemblies() | Where-Object { $_.ManifestModule.ScopeName -eq "Fetch" } | Select-Object -Last 1
        $Fetch = $Module.GetTypes()[0]
    }
    catch {
        $Module = [AppDomain]::CurrentDomain.DefineDynamicAssembly("null", 1).DefineDynamicModule("Fetch", $False).DefineType("null")
        @(
            @('null', 'null', [int], @()), # Alignment Placeholder
        
            # Superfetch Core Translation Exports
            @('MT_Initialize',        'C:\windows\system32\superfetch.dll', [Int32], @()),
            @('MT_VirtualToPhysical', 'C:\windows\system32\superfetch.dll', [Int64], @([Int64])),
            @('MT_Cleanup',           'C:\windows\system32\superfetch.dll', [Void],  @())
        ) | ForEach-Object {
            $Module.DefinePInvokeMethod(($_[0]), ($_[1]), 22, 1, [Type]($_[2]), [Type[]]($_[3]), 1, 3).SetImplementationFlags(128)
        }
        $Fetch = $Module.CreateType()
    }

    if (-not [File]::Exists('C:\windows\system32\superfetch.dll')) {
        Import-EmbeddedBlock -BlockName superfetch -OutPath 'C:\windows\system32\superfetch.dll' | Out-Null
    }

    if ($Fetch::MT_Initialize() -eq 0) {
        Write-Warning "Access Denied! You forgot to run as Administrator."
        return
    }

    try {
        Return (
            $Fetch::MT_VirtualToPhysical(
                $VirtualAddress.ToInt64())
        )
    }
    finally {
        $Fetch::MT_Cleanup() | Out-Null
    }
}

