        $Owner = "Unknown"
        foreach ($Mod in $ModuleList) { 
            if ($FuncInt -ge $Mod.B -and $FuncInt -lt $Mod.E) { $Owner = $Mod.N; break } 
        }

        $HexFunc = "0x{0:X16}" -f $FuncInt
