    UmciAuditModeEnabled            = 0x0010
    UmciExclusionPathsEnabled       = 0x0020
    TestBuild                       = 0x0040
    PreproductionBuild              = 0x0080
    DebugModeEnabled                = 0x0100
    FlightBuild                     = 0x0200
    FlightingEnabled                = 0x0400
    HvciKmciEnabled                 = 0x0800
    HvciKmciAuditModeEnabled        = 0x1000
    HvciKmciStrictModeEnabled       = 0x2000
    HvciIumEnabled                  = 0x4000
    WhqlEnforcementEnabled          = 0x8000
}
